import { useState, useMemo, useEffect, useLayoutEffect, useRef, Fragment } from "react";
import { createPortal } from "react-dom";

// Auto-generated guide content. Built from build_cd_expandables.py +
// build_rpd_expandables.py + build_indirect_guide.py via
// /tmp/extract_guides_json.py. Each entry has the chapter id, num, title,
// and an array of blocks (section/paragraph/bullets/numbered/callout).
// Refresh by re-running the extract script and overwriting this file.
import GUIDES_DATA from "./guides-data.json";

// RPD engine — extracted to its own module (src/rpd-engine.js) for separation
// from the UI. Engine is pure JS with no React dependencies; UI consumes its
// public API via this import. Tests import directly from the engine module.
import {
 // Constants
 RPD_TEETH_MAX, RPD_TEETH_MAND,
 RPD_MAX_ANTERIOR, RPD_ESTHETIC_ZONE,
 RPD_CANINES, RPD_FIRST_PREMOLARS, RPD_SECOND_PREMOLARS,
 RPD_FIRST_MOLARS, RPD_SECOND_MOLARS, RPD_THIRD_MOLARS,
 RPD_ABUTMENT_DEFAULTS,
 RPD_AXIUM_STEPS,
 // Utilities
 rpdArchOf, rpdToothName, rpdToothList,
 // Classification + design API
 rpdClassifyKennedy, rpdGetEdentulousSpans,
 rpdCheckRPIContraindications,
 rpdSelectMajorConnector, rpdSelectBaseDesign,
 rpdDesignAbutment, rpdPlaceIndirectRetainers,
 rpdPlanRetention, rpdHydrateAbutment, rpdRunEngine,
 // Case helpers
 rpdMakeBlankCase, rpdNormalizeTeeth,
} from "./rpd-engine.js";

