// Flatten the hierarchy into a list of procedures with breadcrumb metadata —
// useful for everything that operates on a procedure (Note Builder, Prep List,
// jump handlers).
function getAllProcedures() {
 const out = [];
 for (const cat of CATEGORIES) {
 for (const grp of cat.groups) {
 for (const proc of grp.procedures) {
 out.push({
 id: proc.id,
 label: proc.label,
 categoryId: cat.id,
 categoryLabel: cat.label,
 groupId: grp.id,
 groupLabel: grp.label,
 breadcrumb: `${cat.label} → ${grp.label} → ${proc.label}`,
...(proc.pinnedCodes && { pinnedCodes: proc.pinnedCodes }),
 });
 }
 }
 }
 return out;
}

const ALL_PROCEDURES = getAllProcedures();
const findProcedure = (id) => ALL_PROCEDURES.find(p => p.id === id);

// Flatten a category's groups into a single procedures list with each
// procedure tagged with its group label as a prefix where helpful. This
// preserves the simpler 2-dropdown picker used by Note Builder and Prep
// List while still giving users the group context they'd see in Browse.
function flattenCategory(cat) {
 const procs = [];
 for (const grp of cat.groups) {
 for (const p of grp.procedures) {
 // Procedure labels render bare — no "Group — " prefix — per Jake.
 // The group is still tracked in groupLabel (used by search ranking),
 // it just isn't shown in the Procedure dropdown.
 procs.push({ id: p.id, label: p.label, groupId: grp.id, groupLabel: grp.label });
 }
 }
 return {...cat, procedures: procs };
}

// All categories with.procedures available (for NoteBuilder).
// Lab Scripts are surfaced here too — the same Rx body can be drafted via the
// note generator (with the existing tooth + shade + crown-type fields auto-
// substituting #N and A2 placeholders) and pasted into Axium's Labs > Details
// field. Inserted right after Restorative in the dropdown order.
// Excludes misc (Axium workflows / lookup references — no notes there).
//
// Within each category, procedures that have no TEMPLATES body are dropped —
// the note builder has nothing to render for them. The lab category, in
// particular, includes a "Workflow" group (How to Submit a Lab Script, Tooth
// Requisition, Lab Turn-Around Time) that lives in the Steps tab nav but
// has no Rx text, so those entries get filtered out here.
const FLAT_CATEGORIES = (() => {
 const ordered = [];
 for (const cat of CATEGORIES) {
 if (cat.id === "misc" || cat.id === "lab" || cat.id === "icc") continue;
 ordered.push(cat);
 if (cat.id === "restorative") {
 const lab = CATEGORIES.find(c => c.id === "lab");
 if (lab) ordered.push(lab);
 // ICC sits right after Lab Scripts in the dropdown (per Jake), not at its
 // canonical CATEGORIES position (after Oral Surgery). It's a note-only
 // clinic so it never appears in the Steps browse.
 const icc = CATEGORIES.find(c => c.id === "icc");
 if (icc) ordered.push(icc);
 }
 }
 return ordered
.map(cat => ({
...cat,
 groups: cat.groups
.map(grp => ({
...grp,
 procedures: grp.procedures.filter(p => TEMPLATES[p.id]),
 }))
.filter(grp => grp.procedures.length > 0),
 }))
.filter(cat => cat.groups.length > 0)
.map(flattenCategory);
})();

// Browse tab: every category. Lab Scripts used to be filtered out because the
// per-procedure pages had no CHUNKS content; each lab Rx now has a REF_DATA
// entry with the Rx body + supplements + Swade turnaround, so they belong
// here too.
// Steps tab nav. Excludes the note-only categories (ICC + Oral Surgery) —
// those are templates in the Note tab with no step-by-step CHUNKS content,
// so they'd show as empty Steps pages.
const BROWSE_CATEGORIES = CATEGORIES.filter(c => c.id !== "icc" && c.id !== "os");

/* ============================================================================
 * REF_DATA — structured rendering for Misc. > Lookup procedures.
 *
 * Lookup chunks are reference material (BP categories, drug catalog, materials,
 * prescription formulations, caries staging). The raw bodies are space-aligned
 * ASCII tables that render badly in any proportional font. Rather than force
 * monospace, we hand-author structured data here and render it with proper
 * typography. Procedures NOT keyed in this map fall back to ProseBlock — fine
 * for the prose-heavy ones (anesthesia narrative, MRONJ, pregnant pts, etc.).
 *
 * Block shapes:
 * { type: "table", caption?, headers, rows, footnote? }
 * { type: "cards", caption?, cards: [{ title, subtitle?, body?, rows? }] }
 * { type: "prose", heading?, lines: [...] }
 * ==========================================================================*/
