// Fee lookup: try exact code first, then strip a trailing step-letter (A–D)
// so that DD2610A → DD2610, D2740B → D2740, D3310A → D3310, etc.
const lookupFee = code => CLINIC_FEES[code]?? CLINIC_FEES[code.replace(/[A-D]$/, '')];

