// Concatenate all PE arrays into a single PES_ALL constant.
const PES_ALL = [...PES,...PES_PART2,...PES_PART3,...PES_PART4,...PES_PART5,...PES_PART6,...PES_PART7];

// PE-to-Procedure mapping for "Show Steps" links.
// Only includes PEs with clear, exact matches to procedure IDs in the Steps tab.
// PEs without a clean 1:1 procedure match are intentionally omitted (their
// "Show Steps" link won't render).
//
// Value format: either a string (single procedure) or an array of
// { id, label } objects when one PE maps to multiple distinct procedures.
const PE_PROCEDURE_MAP = {
 // Perio
 "PER01": "573", // Periodontal Clinical Evaluation → Perio COE
 "PER02": "ohi", // Prevention & Risk Factor (OHI) Exam → OHI
 "SRP04": "1272", // Calculus Detection & SRP → SRP
 "MAINT04": "1425", // Periodontal Maintenance → Perio Maintenance
 "REVA04": "1346", // Periodontal Re-Evaluation → Perio Re-Evaluation
 // Restorative Foundation
 "CARDX": "ref-caries-dx", // Caries Dx & ADA Classification → Caries Diagnosis ref
 // Operative
 "CR2": "1745", // Class II Composite → Class II
 "CR3": "1850", // Class III Composite → Class III
 // Fixed Prosthodontics
 "CRN1": "2821", // Crown Prep & Provisionalization → Crown Prep
 "CRN2": "3076", // Crown Final Impression → Final Impression
 "CRN3": "3204", // Crown Cementation → Crown Delivery
 // Removable Prosthodontics — PE has 5 steps, Steps tab has 6 (anterior + posterior
 // try-ins are split). PE CD4 "Trial Denture Try-in" = full setup with all teeth =
 // posterior try-in (#5). Anterior try-in (#4) doesn't have a dedicated PE.
 "CD1": "3704", // Preliminary Impression → #1 COE & Diagnostic Impressions
 "CD2": "3831", // Border Molding & Final Impression → #2 Border Molding
 "CD3": "3954", // Wax-Rim Try-In → #3 Wax Rims
 "CD4": "4169", // Trial Denture Try-in → #5 Posterior Try-In
 "CD5": "4257", // Denture Delivery → #6 Delivery
 // Specialty
 "EROOT1": "5472", // Endo Single-Rooted → RCT 1 Visit
 "EROOT2": "5472", // Endo Multi-Rooted → RCT 1 Visit
 // Rotation
 "PEDO_EXAM": "5985", // Pediatric Exam & Tx Planning → Peds Initial/Recall
 "PEDO_REST": [ // Peds Primary Tooth Restorative — most representative pair
 { id: "6406", label: "Class II" },
 { id: "6991", label: "SSC" },
 ],
 "URGENT": "374", // Urgent Care Exam → Urgent Care
};

// Reverse index: procedure id → the PE code(s) it satisfies, so the Steps tab
// can badge procedures that double as Performance Exams.
const PROCEDURES_WITH_PE = (() => {
 const m = {};
 for (const [peId, mapped] of Object.entries(PE_PROCEDURE_MAP)) {
 const ids = mapped == null? []
 : typeof mapped === "string"? [mapped]
 : mapped.map(x => x.id);
 for (const id of ids) (m[id] || (m[id] = [])).push(peId);
 }
 return m;
})();



/* ============================================================================
 * PEs TAB — Performance Exams reference + planning view.
 *
 * Three zones:
 *
 * 1. TIMELINE — horizontal strip showing all 26 PEs positioned in their
 * deadline semester. Click any chip to scroll to its detail card.
 * Color-coded: oxblood (past), gold (current), neutral (future). The
 * "current" semester is determined by the date — see CURRENT_SEMESTER.
 *
 * 2. PE LIBRARY — cards grouped by Part (Perio, Restorative Foundation, etc.).
 * Each card collapsed by default showing code, name, deadline, and
 * eligibility badge. Tap to expand.
 *
 * 3. EXPANDED CARD — full detail: objectives, prerequisite, case selection,
 * protocol, three-tier rubric grid, critical deficiencies.
 *
 * The eligibility badge connects to the MEE counts already saved in
 * localStorage from the RVU tab. Where prereqs map cleanly to MEE categories,
 * shows "Eligible" or "Need X more [thing]". For fuzzy prereqs (PE-completion
 * gates, mixed counts), shows just the prerequisite text.
 * ==========================================================================*/

// Determine current semester from today's date. Adjust as the academic
// calendar evolves; conservative buckets:
// Aug-Dec → Fall, Jan-Apr → Spring, May-Jul → Summer
// This drives the "today line" on the timeline.
function currentSemester() {
 const m = new Date().getMonth(); // 0-11
 if (m >= 7 && m <= 11) return "fall"; // Aug-Dec
 if (m >= 0 && m <= 3) return "spring"; // Jan-Apr
 return "summer"; // May-Jul
}

// Compare a PE's deadline semester vs today's semester. Returns "past" or
// "future". We don't try to mark anything as "current" — students range D3 to
// D4 and the app doesn't ask which year they are, so any "current" highlight
// would be misleading half the time. Past flagging stays calendar-relative
// (a deadline whose season is already behind us is past, regardless of year).
function semesterStatus(pe, current) {
 // The semester id encodes "D3-spring", "D4-fall" etc. We extract season.
 const season = pe.deadline.semester.split("-")[1];
 // Order: summer → fall → spring (academic year)
 const order = { summer: 0, fall: 1, spring: 2 };
 const peOrder = order[season]?? 0;
 const curOrder = order[current]?? 0;
 return peOrder < curOrder? "past": "future";
}

// (EligibilityBadge / useMEECounts removed: contracted PE cards show only the
// deadline now. Most students don't enter precise per-category MEE counts, so
// any "Need N more X" or "✓ Eligible" rendering was misleading. The PE's
// prereq text remains visible in the expanded view as plain prose.)

// Timeline — full-width strip at top; chips are selectable (highlight selected).
function PETimeline({ pes, selectedId, onSelect, groupBy = "semester", onGroupByChange }) {
 const current = currentSemester();
 // Iter 34: column data depends on grouping mode. Semester mode renders
 // PE_SEMESTERS as columns (existing behavior). Category mode renders
 // PE_PARTS as columns — same box-grid layout, different column labels
 // and PE filtering.
 const columns = groupBy === "type"
 ? PE_PARTS.map(p => ({ id: p.id, label: p.label, isCategory: true }))
 : PE_SEMESTERS.map(s => ({ id: s.id, label: s.label, isCategory: false }));
 return (
 <div style={{ marginBottom: "20px" }}>
 {/* The "TIMELINE" / "BY CATEGORY" header was redundant with the
 Semester/Category toggle on the right (the active button names
 the current view). Cut per Jake — the toggle alone communicates
 the group-by state. */}
 <div style={{
 display: "flex", alignItems: "center", justifyContent: "flex-end",
 marginBottom: "10px",
 }}>
 {onGroupByChange && (
 <div style={{
 display: "flex", background: "var(--paper-soft)",
 border: "1px solid var(--rule)",
 borderRadius: "3px", overflow: "hidden",
 }}>
 {[{ id: "semester", label: "Semester" }, { id: "type", label: "Category" }].map(opt => (
 <button key={opt.id} onClick={() => onGroupByChange(opt.id)}
 style={{
 padding: "4px 10px", fontSize: "10px", letterSpacing: "0.04em",
 background: groupBy === opt.id ? "var(--accent)" : "transparent",
 color: groupBy === opt.id ? "var(--paper)" : "var(--ink-soft)",
 border: "none", cursor: "pointer",
 fontFamily: "'Geist', sans-serif", fontWeight: 500,
 transition: "background 100ms, color 100ms",
 }}>{opt.label}</button>
 ))}
 </div>
 )}
 </div>
 <div style={{
 display: "grid",
 gridTemplateColumns: `repeat(${columns.length}, 1fr)`,
 gap: "6px",
 }}>
 {columns.map(col => {
 const sem = col.isCategory ? null : PE_SEMESTERS.find(s => s.id === col.id);
 // In category mode, all PEs in this part appear; track-split logic
 // doesn't apply (each PE shows once per its assigned part).
 // In semester mode, track-split PEs (PEDO_EXAM, PEDO_REST, URGENT,
 // OS) are duplicated into D3-spring (DMD) + D4-summer (AS).
 const TRACK_IDS = new Set(["PEDO_EXAM", "PEDO_REST", "URGENT", "OS"]);
 const semPes = col.isCategory
 ? pes.filter(p => p.part === col.id)
 : pes.filter(p => !TRACK_IDS.has(p.id) && p.deadline.semester === col.id);
 const trackPes = col.isCategory ? [] : pes.filter(p => TRACK_IDS.has(p.id));
 const showDMD = !col.isCategory && col.id === "D3-spring";
 const showAS = !col.isCategory && col.id === "D4-summer";
 return (
 <div key={col.id} style={{
 border: "1px solid var(--rule)",
 borderRadius: "3px",
 padding: "8px 6px",
 background: "var(--paper-soft)",
 }}>
 <div style={{
 fontSize: "9px", letterSpacing: "0.08em",
 textTransform: "uppercase",
 color: "var(--ink-soft)",
 fontWeight: 500, textAlign: "center",
 marginBottom: "6px",
 fontFamily: "'Geist', sans-serif",
 }}>
 {col.label}
 </div>
 {(() => {
 // Compact groups — rendered as a single horizontal strip.
 // Each sub-array is one group; PEs are identified by id.
 const COMPACT = [
 ["CD1","CD2","CD3","CD4","CD5"],
 ["CRN1","CRN2","CRN3"],
 ["DXTX2","DXTX3"],
 ];
 const idToGroup = {};
 COMPACT.forEach((g, i) => g.forEach(id => { idToGroup[id] = i; }));

 const rows = [];
 let buf = null; // { groupIdx, pes[] }
 for (const pe of semPes) {
 const gIdx = idToGroup[pe.id];
 if (gIdx!== undefined) {
 if (buf && buf.groupIdx === gIdx) { buf.pes.push(pe); }
 else {
 if (buf) rows.push({ kind: "compact", pes: buf.pes });
 buf = { groupIdx: gIdx, pes: [pe] };
 }
 } else {
 if (buf) { rows.push({ kind: "compact", pes: buf.pes }); buf = null; }
 rows.push({ kind: "single", pe });
 }
 }
 if (buf) rows.push({ kind: "compact", pes: buf.pes });

 const peBtn = (pe) => {
 const isPast = semesterStatus(pe, current) === "past";
 const isSelected = selectedId === pe.id;
 // Resting + hover background per state. Selected stays full
 // accent (no hover bump). Past keeps its light oxblood resting tint
 // but darkens on hover. Default is paper resting → very subtle
 // oxblood wash on hover (mirrors the Codes-table row-hover style).
 const restBg = isSelected ? "var(--accent)" : isPast ? "rgba(122,30,30,0.07)" : "var(--paper)";
 const hoverBg = isSelected ? "var(--accent)" : isPast ? "rgba(122,30,30,0.14)" : "rgba(122,30,30,0.05)";
 return (
 <button key={pe.id} onClick={() => onSelect(pe.id)} title={pe.name}
 onMouseEnter={(e) => { e.currentTarget.style.background = hoverBg; }}
 onMouseLeave={(e) => { e.currentTarget.style.background = restBg; }}
 style={{
 width: "100%",
 background: restBg,
 border: `1px solid ${isSelected || isPast? "var(--accent)": "var(--rule)"}`,
 borderRadius: "2px", padding: "4px 6px",
 fontSize: "10px", fontFamily: "'Geist', sans-serif", fontWeight: 500,
 color: isSelected? "var(--paper)": isPast? "var(--accent)": "var(--ink)",
 cursor: "pointer", textAlign: "left",
 transition: "background 120ms ease, color 80ms",
 }}>
 <span className="mono" style={{ fontVariantNumeric: "tabular-nums" }}>{pe.code}</span>
 </button>
);
 };

 // Track group — compact horizontal strip of track-split PEs with a label.
 const trackGroup = (label) => {
 const anySelected = trackPes.some(p => selectedId === p.id);
 return (
 <div style={{ marginTop: rows.length > 0? "5px": 0 }}>
 <div style={{
 fontSize: "8px", letterSpacing: "0.08em", textTransform: "uppercase",
 color: "var(--ink-faint)", marginBottom: "3px",
 fontFamily: "'Geist', sans-serif",
 }}>{label}</div>
 <div style={{
 display: "flex",
 border: `1px solid ${anySelected? "var(--accent)": "var(--rule)"}`,
 borderRadius: "2px", overflow: "hidden",
 }}>
 {trackPes.map((pe, i) => {
 const isSelected = selectedId === pe.id;
 const restBg = isSelected ? "var(--accent)" : "var(--paper)";
 const hoverBg = isSelected ? "var(--accent)" : "rgba(122,30,30,0.05)";
 return (
 <button key={pe.id} onClick={() => onSelect(pe.id)} title={pe.name}
 onMouseEnter={(e) => { e.currentTarget.style.background = hoverBg; }}
 onMouseLeave={(e) => { e.currentTarget.style.background = restBg; }}
 style={{
 flex: 1,
 background: restBg,
 border: "none",
 borderLeft: i > 0? "1px solid var(--rule)": "none",
 padding: "4px 0",
 fontSize: "9px", fontFamily: "'Geist', sans-serif", fontWeight: 500,
 color: isSelected? "var(--paper)": "var(--ink)",
 cursor: "pointer", textAlign: "center",
 transition: "background 120ms ease, color 80ms",
 }}>
 <span className="mono" style={{ fontVariantNumeric: "tabular-nums" }}>{pe.code}</span>
 </button>
);
 })}
 </div>
 </div>
);
 };

 const hasContent = rows.length > 0 || showDMD || showAS;
 return (
 <div style={{ display: "flex", flexDirection: "column", gap: "3px" }}>
 {!hasContent && (
 <div style={{ color: "var(--ink-faint)", fontSize: "10px",
 fontStyle: "italic", textAlign: "center", padding: "8px 0" }}>—</div>
)}
 {rows.map((row, ri) => {
 if (row.kind === "single") return peBtn(row.pe);
 // Compact group — horizontal strip, shared outer border, dividers between
 const anySelected = row.pes.some(p => selectedId === p.id);
 const anyPast = row.pes.some(p => semesterStatus(p, current) === "past");
 return (
 <div key={`compact-${ri}`} style={{
 display: "flex",
 border: `1px solid ${anySelected || anyPast? "var(--accent)": "var(--rule)"}`,
 borderRadius: "2px", overflow: "hidden",
 }}>
 {row.pes.map((pe, i) => {
 const isPast = semesterStatus(pe, current) === "past";
 const isSelected = selectedId === pe.id;
 const restBg = isSelected ? "var(--accent)" : isPast ? "rgba(122,30,30,0.07)" : "var(--paper)";
 const hoverBg = isSelected ? "var(--accent)" : isPast ? "rgba(122,30,30,0.14)" : "rgba(122,30,30,0.05)";
 return (
 <button key={pe.id} onClick={() => onSelect(pe.id)} title={pe.name}
 onMouseEnter={(e) => { e.currentTarget.style.background = hoverBg; }}
 onMouseLeave={(e) => { e.currentTarget.style.background = restBg; }}
 style={{
 flex: 1,
 background: restBg,
 border: "none",
 borderLeft: i > 0? "1px solid var(--rule)": "none",
 padding: "4px 0",
 fontSize: "9px", fontFamily: "'Geist', sans-serif", fontWeight: 500,
 color: isSelected? "var(--paper)": isPast? "var(--accent)": "var(--ink)",
 cursor: "pointer", textAlign: "center",
 transition: "background 120ms ease, color 80ms",
 }}>
 <span className="mono" style={{ fontVariantNumeric: "tabular-nums" }}>{pe.code}</span>
 </button>
);
 })}
 </div>
);
 })}
 {showDMD && trackGroup("DMD only")}
 {showAS && trackGroup("AS only")}
 </div>
);
 })()}
 </div>
);
 })}
 </div>
 </div>
);
}

// Rubric grid — one unified grid so header and data columns are always
// pixel-perfect aligned. All cells are direct children of the outer container;
// no per-row sub-grids that could drift.
function RubricGrid({ criteria }) {
 const COLS = "140px 1fr 1fr 1fr";
 // Every rubric cell — headers + data — centers content both
 // horizontally and vertically. Flex container with center alignment
 // on both axes; text-align: center also kicks in for multi-line
 // descriptions so wrapped lines stack centered too.
 const hdr = {
 padding: "10px 14px",
 fontSize: "10px", letterSpacing: "0.16em",
 textTransform: "uppercase", fontWeight: 500,
 background: "var(--paper-soft)",
 borderBottom: "1px solid var(--rule)",
 display: "flex", alignItems: "center", justifyContent: "center",
 textAlign: "center",
 };
 const cell = (i, isLast) => ({
 padding: "12px 14px",
 fontSize: "12px", lineHeight: 1.5,
 borderBottom: isLast? "none": "1px solid var(--rule-soft)",
 display: "flex", alignItems: "center", justifyContent: "center",
 textAlign: "center",
 });

 return (
 <div style={{
...cardStyle, padding: 0, overflow: "hidden",
 marginTop: "16px",
 display: "grid",
 gridTemplateColumns: COLS,
 }}>
 {/* Header row */}
 <div style={{...hdr, color: "var(--ink-soft)" }}>Criterion</div>
 <div style={{...hdr, color: "var(--teal)", borderLeft: "1px solid var(--rule-soft)" }}>Excellent</div>
 <div style={{...hdr, color: "var(--gold)", borderLeft: "1px solid var(--rule-soft)" }}>Clinically Acceptable</div>
 <div style={{...hdr, color: "var(--accent)", borderLeft: "1px solid var(--rule-soft)" }}>Standard Not Met</div>

 {/* Data rows — flatMap avoids Fragment import */}
 {criteria.flatMap((c, i) => {
 const isLast = i === criteria.length - 1;
 const base = cell(i, isLast);
 return [
 <div key={`${i}-name`} style={{
...base,
 background: "var(--paper-soft)",
 color: "var(--ink)", fontWeight: 500,
 }}>
 {c.name}
 </div>,
 <div key={`${i}-exc`} style={{
...base,
 borderLeft: "1px solid var(--rule-soft)",
 color: c.excellent? "var(--ink)": "var(--ink-faint)",
 fontStyle: c.excellent? "normal": "italic",
 }}>
 {c.excellent || "—"}
 </div>,
 <div key={`${i}-acc`} style={{
...base,
 borderLeft: "1px solid var(--rule-soft)",
 color: c.acceptable? "var(--ink)": "var(--ink-faint)",
 fontStyle: c.acceptable? "normal": "italic",
 }}>
 {c.acceptable || "—"}
 </div>,
 <div key={`${i}-not`} style={{
...base,
 borderLeft: "1px solid var(--rule-soft)",
 color: c.notMet? "var(--ink)": "var(--ink-faint)",
 fontStyle: c.notMet? "normal": "italic",
 }}>
 {c.notMet || "—"}
 </div>,
 ];
 })}
 </div>
);
}

// Right-panel detail — always fully expanded for the selected PE.
function PEDetail({ pe, onShowSteps }) {
 // Normalize the map value: a string becomes a single-entry array; an array
 // is used as-is. Each entry is { id, label? } — label is shown only when
 // multiple procedures map to the same PE.
 const mapped = PE_PROCEDURE_MAP[pe.id];
 const procedures = mapped == null
? []
: (typeof mapped === "string"? [{ id: mapped }]: mapped);
 const showStepsLinkStyle = {
 fontSize: "10px", color: "var(--accent)", cursor: "pointer",
 background: "none", border: "none", textDecoration: "underline",
 fontFamily: "'Geist', sans-serif", padding: 0,
 };
 return (
 <div style={{...cardStyle, padding: "20px 22px" }}>
 {/* Header — PE code (left), name (middle, flex-grow + text-center),
 Steps link(s) right-aligned at the top corner. Links are bare
 hyperlinks with no "Steps:" prefix. Title text-centers within
 its flex cell so the eye reads it as the focal element.
 Links are slightly smaller + tighter so the right side doesn't
 weigh too heavily against center. */}
 <div style={{ marginBottom: "18px", paddingBottom: "14px", borderBottom: "1px solid var(--rule-soft)" }}>
 <div style={{ display: "flex", alignItems: "baseline", gap: "12px", marginBottom: "5px", flexWrap: "wrap" }}>
 <span className="mono" style={{
 color: "var(--accent)", fontWeight: 500,
 fontSize: "14px", fontVariantNumeric: "tabular-nums",
 }}>
 {pe.code}
 </span>
 <span style={{ fontSize: "15px", fontWeight: 500, color: "var(--ink)", flex: "1 1 auto", textAlign: "center" }}>
 {pe.name}
 </span>
 {procedures.length > 0 && onShowSteps && (
 <div style={{ display: "flex", alignItems: "baseline", gap: "5px", flexWrap: "wrap" }}>
 {procedures.length === 1 ? (
 <button onClick={() => onShowSteps(procedures[0].id)} style={showStepsLinkStyle}>
 Steps →
 </button>
 ) : procedures.map((p, i) => (
 <Fragment key={p.id}>
 {i > 0 && (
 <span style={{ fontSize: "10px", color: "var(--ink-faint)" }}>·</span>
 )}
 <button onClick={() => onShowSteps(p.id)} style={showStepsLinkStyle}>
 {p.label} →
 </button>
 </Fragment>
 ))}
 </div>
 )}
 </div>
 {pe.deadline.text && (
 <div style={{ fontSize: "11px", color: "var(--ink-soft)", fontStyle: "italic" }}>
 {pe.deadline.text}
 </div>
 )}
 </div>

 {/* Prereq / Case Selection / Protocol in a 2-col grid — label on the
 left (right-aligned to read flush against the gutter), body on the
 right. Roughly halves the vertical footprint vs the old stacked-
 label-above-paragraph layout. Inline label style mirrors
 SubsectionLabel but drops its marginBottom + leading optical-correction
 (neither needed in a baseline-aligned grid). */}
 {(() => {
 const labelStyle = {
 fontSize: "10px", letterSpacing: "0.16em", textTransform: "uppercase",
 color: "var(--accent)", fontWeight: 500,
 fontFamily: "'Geist', sans-serif",
 };
 const bodyStyle = {
 fontSize: "13px", color: "var(--ink-soft)", lineHeight: 1.55, margin: 0,
 };
 return (
 <div style={{
 display: "grid",
 gridTemplateColumns: "140px 1fr",
 columnGap: "20px", rowGap: "10px",
 marginBottom: "16px",
 alignItems: "baseline",
 }}>
 <div style={{ textAlign: "right",...labelStyle }}>Prerequisite</div>
 <p style={bodyStyle}>{pe.prereq || "None specified."}</p>

 <div style={{ textAlign: "right",...labelStyle }}>Case Selection</div>
 <p style={bodyStyle}>{pe.caseSelect}</p>

 <div style={{ textAlign: "right",...labelStyle }}>Protocol</div>
 <p style={bodyStyle}>{pe.protocol}</p>
 </div>
 );
 })()}

 <div style={{ marginTop: "20px" }}>
 <SubsectionLabel>Rubric</SubsectionLabel>
 <RubricGrid criteria={pe.criteria} />
 </div>

 {/* Critical deficiencies — the boilerplate "Standard six" set
 (Case Selection / Professionalism / Patient Management /
 Time Management / Preparedness / Instructor Intervention) is
 implied across every PE, so we filter those out and only
 render this section when a PE has truly PE-specific autofails
 (e.g. "Topic not approved prior to presentation."). */}
 {(() => {
 const isStandardSix = (s) =>
 /^\s*standard six\b/i.test(s) ||
 /^\s*case selection\b/i.test(s) ||
 /^\s*professionalism\b/i.test(s) ||
 /^\s*patient management/i.test(s) ||
 /^\s*time management\b/i.test(s) ||
 /^\s*preparedness/i.test(s) ||
 /^\s*instructor intervention/i.test(s);
 const specific = (pe.criticalDeficiencies || []).filter(d => !isStandardSix(d));
 if (specific.length === 0) return null;
 return (
 <div style={{ marginTop: "20px" }}>
 <SubsectionLabel>Critical deficiencies (auto-fail)</SubsectionLabel>
 <ul style={{
 margin: "4px 0 0", padding: "0 0 0 18px",
 fontSize: "12px", color: "var(--ink-soft)",
 lineHeight: 1.55,
 }}>
 {specific.map((d, i) => (
 <li key={i} style={{ marginBottom: "3px" }}>{d}</li>
 ))}
 </ul>
 </div>
 );
 })()}
 </div>
);
}

function PEs({ onShowSteps }) {
 const [selectedId, setSelectedId] = useState(null);
 // Default to Semester grouping per Jake — semester is the lens students
 // actually plan around (which PEs are due this term vs next), and
 // grouping by Type buries the date-relevant grouping under category.
 const [groupBy, setGroupBy] = useState("semester"); // "type" | "semester"

 const selectedPE = PES_ALL.find(p => p.id === selectedId)?? null;

 const handleSelect = (peId) => {
 setSelectedId(id => (id === peId? null: peId));
 };

 // Iter 34: navGroups (left-panel grouped list) removed; PETimeline
 // now handles both Type and Semester grouping directly.

 return (
 <div>
 {/* Iter 34: the previous left-panel grouped navigation (Type/Semester
 toggle + indented PE list) was redundant — every PE in that list
 was also a clickable box in the timeline above. Removed entirely;
 the Type/Semester toggle was lifted into the timeline header
 itself. Detail panel now uses the full width below the timeline. */}
 <PETimeline pes={PES_ALL} selectedId={selectedId} onSelect={handleSelect}
 groupBy={groupBy} onGroupByChange={setGroupBy} />

 {/* Detail panel — full-width. Empty state renders nothing per Jake;
 the timeline boxes are clickable affordance enough. */}
 <div>
 {selectedPE && <PEDetail pe={selectedPE} onShowSteps={onShowSteps} />}
 </div>
 </div>
);
}


/* ============================================================================
 * RPD DESIGN ENGINE — standards
 *
 * Inputs a structured case (arch, per-tooth status, per-abutment attrs,
 * arch measurements, patient factors) and outputs a complete design:
 * Kennedy classification, major connector, per-abutment clasp + rest +
 * guide plane decisions, indirect retainers, base design, framework
 * material, red-flag warnings, Axium code, and a paste-ready lab script.
 *
 * Design philosophy (per):
 * - RPI system is the first choice for distal extensions; Combination
 * clasp is the fallback only when an ordered list of contraindications
 * fires (mesial-rest impossible, vestibular ≤5mm, frenum, soft-tissue
 * undercut >1mm, lack of attached gingiva, extreme tilt/short crown,
 * or undercut not at mid-buccal/mesio-buccal).
 * - Akers (circumferential) is the first choice for tooth-supported areas.
 * - I-bar may be used in the esthetic zone on tooth-supported abutments.
 * - Interim RPDs use wrought-wire C-clasps and ball clasps in a rigid
 * acrylic base; no rest seats, no guide planes, no reciprocation.
 *
 * No UI here — see RPDHelper below for the Phase 1 test harness.
 * ========================================================================= */

// ─── Tooth anatomy (ADA Universal numbering) ──────────────────────────────
// guide planes, retention webbing, tube tooth / facing outlines)
// Red = adjustable/non-cast (wrought-wire clasps, tissue stops, retentive
// undercut engagement points, acrylic extensions)
// Black = anatomical landmarks (survey line / height of contour, tripod marks)
// Design overlay ink — official color convention from the Performance
// Exam grading instructions:
// BLUE → all cast metal framework (rests, plates, clasps, reciprocals,
// connectors, minor connectors)
// RED → wrought wire retentive arms, retentive clasp terminal undercuts,
// tripod-mark circles, pre-prosthetic surgery outlines, tissue
// stops, acrylic resin denture base (cast-only, not on form)
// BLACK → survey lines, tooth bodies, internal occlusal anatomy
const RPD_OL_BLUE = "#1E47A6"; // cobalt blue — cast metal
const RPD_OL_RED = "#C9342E"; // fire-engine red — undercut/wrought/HOC tripod/acrylic/tissue stop
const RPD_OL_BLACK = "var(--ink)";

function RPDToothChart({
 caseInput,
 result,
 selectedTooth,
 onSelectTooth,
 onToggleTooth,
 selectedDesignEl,
 onSelectDesignEl,
 showOverlay = true,
}) {
 // ── Unified renderer ──
 // The interactive chart and the static lab-prescription drawing now share
 // the SAME rendering pipeline (RPDPaperFormArchDrawing). This component
 // simply delegates with interactive props on, then renders the legend +
 // help text below the SVG. Previously two separate visual languages
 // existed; the schematic was retired in favor of the form-faithful
 // rendering used in clinic.
 if (!result) return null;
 return (
 <div style={{ width: "100%", overflowX: "auto" }}>
 <RPDPaperFormArchDrawing
 caseInput={caseInput}
 result={result}
 interactive
 selectedTooth={selectedTooth}
 onSelectTooth={onSelectTooth}
 onToggleTooth={onToggleTooth}
 selectedDesignEl={selectedDesignEl}
 onSelectDesignEl={onSelectDesignEl}
 />
 <div className="rpd-print-hide" style={{
 fontSize: "11px", color: "var(--ink-faint)", textAlign: "center",
 marginTop: "10px", fontStyle: "italic",
 }}>
 Double-click to toggle present ↔ missing.
 </div>
 </div>
);
}
function RPDLegendDot({ label, fill, stroke, dashed, strokeWidth = 1.2, tick, ring }) {
 return (
 <div style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "11px", color: "var(--ink-soft)" }}>
 <svg width="20" height="20" viewBox="0 0 20 20">
 {ring && <circle cx="10" cy="10" r="9" fill="none" stroke={stroke} strokeWidth={0.8} />}
 <circle cx="10" cy="10" r="7" fill={fill} stroke={stroke} strokeWidth={strokeWidth}
 strokeDasharray={dashed? "2,2": undefined} />
 {tick && <line x1="10" y1="17" x2="10" y2="20" stroke="var(--ink)" strokeWidth={2} />}
 </svg>
 <span>{label}</span>
 </div>
);
}

// Small "ⓘ" hover-popover. Title shows on the icon's aria-label; children
// render inside the popover that appears when the icon is hovered.
function RPDInfoIcon({ title, children }) {
 return (
 <span className="rpd-info-icon" style={{
 position: "relative",
 display: "inline-flex",
 alignItems: "center",
 justifyContent: "center",
 width: "16px", height: "16px",
 border: "1px solid var(--ink-soft)",
 borderRadius: "50%",
 fontSize: "10px",
 fontFamily: "'Fraunces', serif",
 fontStyle: "italic",
 color: "var(--ink-soft)",
 cursor: "help",
 alignSelf: "center",
 userSelect: "none",
 }} aria-label={title}>
 i
 <span className="rpd-info-popover" role="tooltip" style={{
 position: "absolute",
 // Flush to top of icon (no visual gap) so:hover survives cursor
 // travel into the popover area. A small marginBottom keeps a
 // visible-looking gap without breaking hover continuity.
 bottom: "100%",
 marginBottom: "6px",
 left: "50%",
 transform: "translateX(-50%)",
 background: "var(--paper)",
 border: "1px solid var(--rule)",
 borderRadius: "2px",
 padding: "10px 12px",
 fontSize: "11px",
 color: "var(--ink)",
 fontStyle: "normal",
 whiteSpace: "nowrap",
 boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
 opacity: 0,
 visibility: "hidden",
 // pointerEvents must be auto when shown so cursor can traverse
 // onto the popover and keep:hover alive. We rely on
 // visibility:hidden to keep it from intercepting clicks.
 pointerEvents: "auto",
 transition: "opacity 120ms ease, visibility 120ms ease",
 zIndex: 10,
 }}>
 {title && (
 <div style={{
 fontSize: "10px", letterSpacing: "0.1em", textTransform: "uppercase",
 color: "var(--ink-faint)", marginBottom: "6px",
 }}>
 {title}
 </div>
)}
 {children}
 </span>
 </span>
);
}

// ─── Axium clinic-workflow concept glossary ──────────────────────────────
// Maps technical terms appearing in the workflow steps to short, friendly
// explanations. Each step pulls a subset of these to render as info-icon
// chips so students can hover over jargon they don't recognize.
const RPD_AXIUM_GLOSSARY = {
 "Metal allergy": "Patient-reported allergy to nickel, chrome, or cobalt. Gates the choice of NMCD (non-metal clasp denture) vs Co-Cr framework. Confirm with the patient at history-taking — don't assume.",
 "EOE / IOE": "Extra-Oral Exam / Intra-Oral Exam. Cancer screening, TMD palpation, perio probing, soft-tissue inspection, evaluation of any existing prosthesis. Done at the comprehensive oral exam.",
 "Diagnostic casts": "Stone casts poured from alginate impressions, mounted on a Denar 320 articulator. They let you survey potential abutments, plan tooth modifications, and design the RPD before touching the patient's mouth.",
 "Articulator (Denar 320)": "A mechanical jaw simulator used in dental clinics. Cast pairs are mounted with facebow + bite registration so static and dynamic occlusion can be evaluated outside the mouth.",
 "VDO": "Vertical Dimension of Occlusion — the distance between two anatomical points (typically nose-tip to chin-tip) with the teeth in maximum intercuspation. Changes in VDO are a Class IV PDI complexity flag.",
 "Surveying": "Using a dental surveyor to identify undercuts and find a path of insertion. The undercut location + depth are then transferred to the lab Rx (the red marks on the cast). Done on the diagnostic cast first, repeated on the master cast.",
 "Survey crown": "A PFM crown specifically designed for an RPD abutment: 2.5–3 mm occlusal reduction at the rest seat, with rest seats and guide planes prepared IN METAL (not porcelain). Used when the abutment can't be modified by enameloplasty alone.",
 "HOC (Height of contour)": "The widest mesio-distal circumference of the tooth, drawn in black by the surveyor. Clasps cross the HOC to engage undercuts; reciprocal arms stay above it.",
 "Applegate's Rule 1": "If a tooth is to be extracted, the Kennedy classification is determined AFTER the extraction. Apply this rule whenever Phase I active disease control creates new edentulous areas.",
 "Applegate's Rules 2 & 3": "Rule 2: a 3rd molar is included only if it's present, healthy, AND being used as an abutment. Rule 3: the most posterior edentulous area governs the classification.",
 "Phase I active disease control": "Period for extractions of hopeless teeth, periodontal scaling/root-planing, caries control. Re-evaluate 4–6 weeks after Phase I before moving to Phase II surgical / Phase III prosthetic.",
 "Tori": "Bony exostoses — palatal tori (mid-palate) or mandibular tori (lingual side of mandible). If not surgically removed, the major connector design must avoid them (e.g., U-shaped maxillary connector, lingual plate mandibular).",
 "Healing period (≥6 months)": "Standard wait time after extractions or surgical removal of tori/tuberosities before taking definitive impressions. Bone remodels significantly during this window; an interim RPD is delivered if a prosthesis is needed sooner.",
 "Prep sequence (standard sequence)": "Strict order: (1) guide planes → (2) axial contours → (3) undercuts (if needed) → (4) verification impression → (5) rest seats LAST. Reversing this risks damaging the rest seat shape during subsequent prep steps.",
 "Altered cast technique": "Two-stage functional impression done in Class I/II distal extension cases. The terminal saddle area is re-impressed under finger pressure to capture the compressible ridge mucosa in a loaded state, so the framework distributes occlusal load to both teeth and tissue.",
 "Border molding": "Functional moulding of the impression tray's periphery using stick compound or PVS, performed in the patient's mouth. Captures the vestibular sulcus and frenum attachments for an accurate denture flange.",
 "Wax rim / occlusal records": "After framework try-in, wax occlusal rims are added to the framework and used to record VDO + centric relation. The lab then mounts the casts and sets the artificial teeth to the recorded position.",
 "D5213 / D5214": "ADA / Axium procedure codes for DEFINITIVE cast-metal RPDs. D5213 = maxillary, D5214 = mandibular.",
 "D5820 / D5821": "ADA / Axium procedure codes for INTERIM (acrylic-base) RPDs. D5820 = maxillary, D5821 = mandibular.",
};

// Per-step term lists — which glossary entries are relevant for each Axium
// workflow step. The keys correspond to step numbers in RPD_AXIUM_STEPS.
const RPD_AXIUM_STEP_TERMS = {
 1: ["Metal allergy", "EOE / IOE"],
 2: ["Diagnostic casts", "Articulator (Denar 320)", "VDO"],
 3: ["Surveying", "Survey crown", "HOC (Height of contour)", "Applegate's Rules 2 & 3"],
 4: ["Applegate's Rule 1", "Phase I active disease control"],
 5: ["Tori", "Healing period (≥6 months)"],
 6: ["Prep sequence (standard sequence)", "Survey crown", "HOC (Height of contour)"],
 7: ["Altered cast technique", "Border molding", "Wax rim / occlusal records", "D5213 / D5214", "D5820 / D5821"],
};

// Phase-level "what this phase is for" blurbs.
const RPD_AXIUM_PHASE_INTROS = {
 "Diagnostic & Treatment Planning": "Build the case file. History, exam, radiographs, mounted casts, surveying — everything needed to commit to a design before the patient is treated.",
 "Phase I: Active Disease Control": "Get the mouth healthy first. Extractions, perio, caries control. The Kennedy classification often changes after Phase I — re-run the engine.",
 "Phase II: Surgical": "Pre-prosthetic surgery: tori, tuberosities, implants. Then wait 6 months for bone remodelling before any definitive impressions.",
 "Phase III: Prosthetic": "Build the prosthesis. Abutment preps in standard order, final impressions, framework, try-in, delivery.",
};

// ─── Axium Clinic Workflow ────────────────────────────────────────────────
// Friendlier presentation of the 7-step RPD workflow. Each step is a
// card with a short clinical action description, expandable for Axium entry
// details + design implications, plus info-icon chips for technical jargon.
function RPDAxiumWorkflow({ result, caseInput }) {
 const [expanded, setExpanded] = useState({});
 const toggle = (n) => setExpanded(s => ({...s, [n]:!s[n] }));
 const designIntent = caseInput.patientFactors?.designIntent || "definitive";

 // Group steps by phase, preserving order
 const phaseGroups = [];
 let currentPhase = null;
 for (const s of RPD_AXIUM_STEPS) {
 if (s.phase!== currentPhase) {
 phaseGroups.push({ phase: s.phase, steps: [] });
 currentPhase = s.phase;
 }
 phaseGroups[phaseGroups.length - 1].steps.push(s);
 }

 return (
 <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
 {phaseGroups.map(({ phase, steps }) => (
 <div key={phase}>
 {/* Phase header */}
 <div style={{
 display: "flex", alignItems: "baseline", gap: "12px",
 marginBottom: "8px", paddingBottom: "6px",
 borderBottom: "1.5px solid var(--accent)",
 }}>
 <div className="serif" style={{
 fontSize: "11px", letterSpacing: "0.22em", textTransform: "uppercase",
 color: "var(--accent)", fontWeight: 600,
 }}>
 Phase
 </div>
 <div className="serif" style={{
 fontSize: "16px", color: "var(--ink)", fontStyle: "italic",
 }}>
 {phase}
 </div>
 </div>
 {RPD_AXIUM_PHASE_INTROS[phase] && (
 <div style={{
 fontSize: "12px", color: "var(--ink-soft)", fontStyle: "italic",
 lineHeight: 1.55, marginBottom: "14px",
 fontFamily: "'Fraunces', serif",
 }}>
 {RPD_AXIUM_PHASE_INTROS[phase]}
 </div>
)}

 {/* Step cards */}
 <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
 {steps.map(s => {
 const isOpen =!!expanded[s.step];
 const terms = RPD_AXIUM_STEP_TERMS[s.step] || [];
 // Brief = first sentence / clause of action
 const brief = (s.action.split(/\.\s/)[0]) + (s.action.match(/^[^.]+\.\s/)? ".": "");
 return (
 <div key={s.step} style={{
 border: "1px solid var(--rule)", borderRadius: "3px",
 background: "var(--paper)",
 transition: "border-color 140ms ease",
 borderColor: isOpen? "var(--accent)": "var(--rule)",
 }}>
 {/* Step header */}
 <button
 onClick={() => toggle(s.step)}
 style={{
 width: "100%", background: "transparent", border: "none",
 padding: "14px 16px", cursor: "pointer", textAlign: "left",
 display: "flex", alignItems: "flex-start", gap: "14px",
 color: "var(--ink)",
 }}>
 <div style={{
 flex: "0 0 32px", width: 32, height: 32, borderRadius: "50%",
 background: isOpen? "var(--accent)": "var(--paper)",
 border: `1.5px solid var(--accent)`,
 color: isOpen? "white": "var(--accent)",
 display: "flex", alignItems: "center", justifyContent: "center",
 fontFamily: "'Fraunces', serif", fontSize: "15px", fontWeight: 600,
 transition: "background 120ms ease, color 120ms ease",
 }}>
 {s.step}
 </div>
 <div style={{ flex: 1 }}>
 <div style={{
 fontFamily: "'Fraunces', serif", fontSize: "15px",
 fontWeight: 500, color: "var(--ink)", marginBottom: "4px",
 lineHeight: 1.3,
 }}>
 {s.clinic}
 </div>
 <div style={{
 fontSize: "13px", color: "var(--ink-soft)",
 lineHeight: 1.55, marginBottom: terms.length || isOpen? "0": "0",
 }}>
 {brief}
 </div>
 </div>
 <div style={{
 flex: "0 0 18px", fontSize: "13px",
 color: "var(--ink-soft)",
 transform: isOpen? "rotate(180deg)": "rotate(0deg)",
 transition: "transform 140ms ease",
 lineHeight: 1, marginTop: "9px",
 }}>
 ⌄
 </div>
 </button>

 {/* Expanded content */}
 {isOpen && (
 <div style={{
 padding: "0 18px 16px 62px",
 display: "flex", flexDirection: "column", gap: "12px",
 }}>
 {/* Full action text */}
 <div>
 <div style={{
 fontSize: "10px", letterSpacing: "0.14em",
 textTransform: "uppercase", color: "var(--ink-faint)",
 marginBottom: "4px",
 }}>
 Clinical action
 </div>
 <div style={{
 fontSize: "13px", color: "var(--ink)", lineHeight: 1.65,
 whiteSpace: "pre-wrap",
 }}>
 {s.action}
 </div>
 </div>

 {/* Axium entry */}
 <div>
 <div style={{
 fontSize: "10px", letterSpacing: "0.14em",
 textTransform: "uppercase", color: "var(--ink-faint)",
 marginBottom: "4px",
 }}>
 Axium entry
 </div>
 <div style={{
 fontSize: "12px", color: "var(--ink-soft)", lineHeight: 1.6,
 fontStyle: "italic", padding: "8px 12px",
 background: "var(--mono-bg)", borderRadius: "2px",
 fontFamily: "'JetBrains Mono', monospace",
 }}>
 {s.axiumEntry}
 </div>
 </div>

 {/* Design implications */}
 {s.design && (
 <div>
 <div style={{
 fontSize: "10px", letterSpacing: "0.14em",
 textTransform: "uppercase", color: "var(--ink-faint)",
 marginBottom: "4px",
 }}>
 How it informs the design
 </div>
 <div style={{
 fontSize: "12px", color: "var(--ink)", lineHeight: 1.65,
 }}>
 {s.design}
 </div>
 </div>
)}

 {/* Key concepts (info-icon chips) */}
 {terms.length > 0 && (
 <div>
 <div style={{
 fontSize: "10px", letterSpacing: "0.14em",
 textTransform: "uppercase", color: "var(--ink-faint)",
 marginBottom: "6px",
 }}>
 Key concepts — hover for details
 </div>
 <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 10px" }}>
 {terms.map(term => (
 <span key={term} style={{
 display: "inline-flex", alignItems: "center", gap: "6px",
 padding: "4px 10px", border: "1px solid var(--rule)",
 borderRadius: "12px",
 fontSize: "11px", color: "var(--ink-soft)",
 background: "var(--paper)",
 }}>
 {term}
 <RPDInfoIcon title={term}>
 <div style={{ maxWidth: "320px", whiteSpace: "normal", lineHeight: 1.5 }}>
 {RPD_AXIUM_GLOSSARY[term]}
 </div>
 </RPDInfoIcon>
 </span>
))}
 </div>
 </div>
)}
 </div>
)}
 </div>
);
 })}
 </div>
 </div>
))}
 </div>
);
}

// ─── Engine Decision Tree (text illustration) ────────────────────────────
// Renders the engine's branching logic as a monospace ASCII tree with the
// chosen path highlighted in oxblood. Each option that was REJECTED for
// this specific case is shown faded so the student can see the alternatives
// the engine considered.
function RPDDecisionTree({ caseInput, result }) {
 if (!result || result.kennedy.class === null) return null;
 const arch = caseInput.arch || "mandibular";
 const pf = caseInput.patientFactors || {};
 const intent = pf.designIntent || "definitive";

 // ── Visual chip — a pill showing one option. Filled accent = chosen by the
 // engine; outlined faded = alternative considered & rejected. ──
 const Chip = ({ chosen, label, note }) => (
 <div style={{
 display: "inline-flex", flexDirection: "column", gap: "2px",
 padding: "6px 12px",
 background: chosen? "var(--accent)": "white",
 color: chosen? "white": "var(--ink-soft)",
 border: chosen? "1px solid var(--accent)": "1px solid var(--rule)",
 borderRadius: "14px",
 fontSize: "12px",
 lineHeight: 1.25,
 opacity: chosen? 1: 0.65,
 maxWidth: "280px",
 }}>
 <span style={{ fontWeight: chosen? 600: 500 }}>{label}</span>
 {note && (
 <span style={{
 fontSize: "10px", fontStyle: "italic",
 color: chosen? "rgba(255,255,255,0.85)": "var(--ink-faint)",
 }}>
 {note}
 </span>
)}
 </div>
);

 // ── Decision row — one level of the tree. The vertical spine on the left
 // connects all rows; a horizontal stub joins each row to the spine.
 // The `isLast` flag stops the spine after the bottom row. ──
 const Decision = ({ index, label, options, isLast = false, subdued = false }) => (
 <div style={{
 position: "relative",
 paddingLeft: "44px",
 paddingBottom: "18px",
 }}>
 {/* horizontal stub from spine into the row */}
 <div style={{
 position: "absolute", left: "14px", top: "12px",
 width: "20px", height: "1px",
 background: "var(--rule)",
 }} />
 {/* vertical spine — continues unless this is the final row */}
 <div style={{
 position: "absolute", left: "14px", top: 0,
 width: "1px", bottom: isLast? "calc(100% - 12px)": 0,
 background: "var(--rule)",
 }} />
 {/* numbered marker on the spine */}
 <div style={{
 position: "absolute", left: "6px", top: "4px",
 width: "18px", height: "18px", borderRadius: "50%",
 background: subdued? "var(--paper)": "var(--ink)",
 color: subdued? "var(--ink-soft)": "white",
 border: "1px solid " + (subdued? "var(--rule)": "var(--ink)"),
 display: "flex", alignItems: "center", justifyContent: "center",
 fontSize: "10px", fontWeight: 600, fontFamily: "'Geist', sans-serif",
 }}>
 {index}
 </div>
 {/* decision label */}
 <div style={{
 fontFamily: "'Geist', sans-serif", fontSize: "11px",
 textTransform: "uppercase", letterSpacing: "0.09em",
 color: "var(--ink-soft)", fontWeight: 600,
 marginBottom: "8px", marginTop: "2px",
 }}>{label}</div>
 {/* option chips */}
 <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
 {options.map(opt => (
 <Chip key={opt.id} chosen={opt.chosen} label={opt.label} note={opt.note} />
))}
 </div>
 </div>
);

 // ── Option lists ─────────────────────────────────────────────────────────
 const intentOpts = [
 { id: "definitive", label: "Definitive RPD", note: "cast metal · long-term", chosen: intent === "definitive" },
 { id: "interim", label: "Interim RPD", note: "acrylic + WW · transient", chosen: intent === "interim" },
 ];

 const kCls = result.kennedy.class;
 const kennedyOpts = ["I", "II", "III", "IV"].map(c => ({
 id: c,
 label: `Class ${c}${kCls === c && result.kennedy.modifications? ` Mod ${result.kennedy.modifications}`: ""}`,
 note: c === "I"? "bilateral distal extension"
: c === "II"? "unilateral distal extension"
: c === "III"? "tooth-supported (bounded)"
: "anterior crossing midline",
 chosen: kCls === c,
 }));

 const fwOpts = [
 { id: "Co-Cr", label: "Co-Cr", note: "default · no allergy" },
 { id: "Gold", label: "Gold (Type IV)", note: "allergy + budget" },
 { id: "Titanium", label: "Titanium", note: "metal allergy" },
 { id: "Acetyl resin", label: "Acetyl / PEEK", note: "NMCD hybrid" },
 ].map(o => ({...o, chosen: result.framework.material?.includes(o.id) }));

 const mcChoice = result.majorConnector.type;
 const mcOpts = (arch === "maxillary"? [
 { id: "A-P Strap", note: "Class II / wide coverage" },
 { id: "A-P Strap (Class III)", note: "bilateral Class III" },
 { id: "Single Palatal Strap", note: "short-span Class III" },
 { id: "Full Palatal Plate", note: "few teeth · max retention" },
 { id: "U-Shaped Connector", note: "tori obstruct palate" },
 ]: [
 { id: "Lingual Bar", note: "sulcus >8mm · preferred" },
 { id: "Lingual Plate", note: "sulcus <8mm" },
 { id: "Lingual Plate (Tori)", note: "tori not removed" },
 ]).map(o => ({...o, label: o.id, chosen: mcChoice === o.id }));

 const claspChoices = [
 { id: "RPI", note: "DE · all 8 gates pass" },
 { id: "Combination", note: "DE · ≥1 gate fired" },
 { id: "I-bar (esthetic)", note: "TS · anterior esthetic zone" },
 { id: "Akers", note: "TS · standard cast" },
 { id: "Reverse Akers", note: "TS · distal undercut" },
 { id: "Embrasure", note: "two adjacent posteriors" },
 { id: "WW C-clasp", note: "interim RPD only" },
 ];

 return (
 <div style={{
 padding: "20px 24px", marginBottom: "20px",
 background: "var(--paper)", border: "1px solid var(--rule)",
 borderRadius: "2px",
 }}>
 <div style={{
 fontSize: "11px", color: "var(--ink-faint)",
 fontStyle: "italic", marginBottom: "16px",
 }}>
 Filled pill = chosen by the engine. Outlined = alternatives ruled out for this case.
 </div>

 {/* Root: the case summary in a flag-style header. Visually anchored
 at the top of the tree spine. */}
 <div style={{
 display: "inline-flex", alignItems: "center", gap: "10px",
 padding: "8px 16px", marginBottom: "4px", marginLeft: "0",
 background: "var(--ink)", color: "white", borderRadius: "16px",
 fontFamily: "'Fraunces', serif", fontStyle: "italic", fontSize: "13px",
 }}>
 <span style={{
 width: "8px", height: "8px", borderRadius: "50%",
 background: "var(--accent)",
 }} />
 {arch === "maxillary"? "Maxillary": "Mandibular"} arch · {result.kennedy.description}
 </div>

 {/* Decisions — numbered rows with chip options. The vertical spine on
 the left visually threads all decisions together. */}
 <Decision index={1} label="Design intent" options={intentOpts} />
 <Decision index={2} label="Kennedy classification" options={kennedyOpts} />
 <Decision index={3} label="Framework material" options={fwOpts} />
 <Decision index={4} label={`Major connector (${arch === "maxillary"? "palate": "lingual"})`} options={mcOpts} />

 {/* 5. Per-abutment clasps — this decision branches: one clasp choice
 per abutment. Rendered as a numbered Decision row (consistent with
 1–4) whose "options" area holds sub-rows, one per abutment. The
 sub-rows share an inner dashed spine so they read as children of
 decision 5, not as sibling decisions of 1–4. */}
 <div style={{ position: "relative", paddingLeft: "44px", paddingBottom: "4px" }}>
 {/* horizontal stub from main spine */}
 <div style={{
 position: "absolute", left: "14px", top: "12px",
 width: "20px", height: "1px", background: "var(--rule)",
 }} />
 {/* main spine ends at decision 5 (last numbered row), so no bottom continuation */}
 <div style={{
 position: "absolute", left: "14px", top: 0,
 width: "1px", height: "12px", background: "var(--rule)",
 }} />
 {/* numbered marker — consistent ink fill, same as 1–4 */}
 <div style={{
 position: "absolute", left: "6px", top: "4px",
 width: "18px", height: "18px", borderRadius: "50%",
 background: "var(--ink)", color: "white",
 border: "1px solid var(--ink)",
 display: "flex", alignItems: "center", justifyContent: "center",
 fontSize: "10px", fontWeight: 600, fontFamily: "'Geist', sans-serif",
 }}>5</div>
 {/* decision label */}
 <div style={{
 fontFamily: "'Geist', sans-serif", fontSize: "11px",
 textTransform: "uppercase", letterSpacing: "0.09em",
 color: "var(--ink-soft)", fontWeight: 600,
 marginBottom: "10px", marginTop: "2px",
 }}>
 Clasps
 </div>
 {/* Per-abutment sub-rows. Each sits inside decision 5's content area
 with a dashed left border indicating sub-branch. */}
 {(result.abutmentDesigns || []).map((a, ai) => {
 const isLastAb = ai === (result.abutmentDesigns.length - 1);
 return (
 <div key={a.tooth} style={{
 position: "relative",
 paddingLeft: "20px",
 paddingTop: "6px",
 paddingBottom: isLastAb? "0": "16px",
 borderLeft: "1px dashed var(--rule)",
 marginBottom: isLastAb? 0: "2px",
 }}>
 {/* abutment header */}
 <div style={{
 display: "inline-flex", alignItems: "baseline", gap: "8px",
 marginBottom: "8px",
 }}>
 <span style={{
 fontFamily: "'Geist', sans-serif",
 fontSize: "12px", fontWeight: 700,
 color: "var(--ink)",
 }}>
 #{a.tooth}
 </span>
 <span style={{
 fontFamily: "'Geist', sans-serif",
 fontSize: "11px", fontStyle: "italic",
 color: "var(--ink-soft)",
 }}>
 {a.role === "embrasure-retention"
? `contralateral retention · embrasure pair with #${a.pairedWith}`
: a.role === "contralateral-akers"
? "contralateral retention · single Akers (no embrasure pair viable)"
: a.spanType === "distal-extension"
? "distal-extension terminal"
: "tooth-supported abutment"}
 </span>
 </div>
 {/* clasp chips for this abutment */}
 <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
 {claspChoices.map(c => (
 <Chip key={c.id} chosen={a.claspType === c.id} label={c.id} note={c.note} />
))}
 </div>
 </div>
);
 })}
 </div>
 </div>
);
}

// ─── Paper-form arch drawing ──────────────────────────────────────────────
// Renders the engine's RPD design as it would be drawn ON the printed 
// paper preliminary design form: schematic horseshoe arch with light printed
// teeth, design overlaid in saturated ink colors using standard prosthodontic
// drawing conventions (McCracken / Carr & Brown / standard convention):
//
// BLUE — every cast metal component: rest seats, minor connectors,
// major connector, retentive arms of cast clasps (Akers, RPI,
// reverse Akers), reciprocal arms / lingual plates, guide planes,
// denture base mesh / lattice
// RED — wrought wire (non-cast) retentive arms; undercut tick marks
// BLACK — survey line (height of contour) drawn on the buccal aspect of
// each abutment
//
// Drawing geometry conventions (paper-form school):
// • Occlusal rest: filled wedge on the occlusal surface, base at the
// marginal ridge (mesial OR distal), apex toward the
// central fossa.
// • Cingulum rest: filled V on the lingual cingulum of an anterior tooth.
// • Ball rest: small filled circle at the lingual cingulum (centrals).
// • I-bar: vertical bar approaching from the gingival vestibule,
// tip in the gingival third of the buccal surface, below
// the survey line.
// • Circumferential
// arm (Akers): curved line wrapping the buccal surface; terminal
// third drops below the survey line into the undercut.
// Reverse Akers is the same curve but originates from the
// opposite proximal corner.
// • Wrought wire: same shape as Akers but drawn in RED (signals non-cast).
// • Reciprocal arm: curved line on the LINGUAL surface, stays above HOC.
// • Lingual plate: filled crescent covering the lingual surfaces of
// anterior teeth up to the cingula.
// • Lingual bar
// (mandibular): wide blue band running along the lingual gingival
// border, inside the arch curve, between the floor of
// the mouth and the gingival margins.
// • Palatal strap wide blue band crossing the palate (single = one
// (maxillary): band, AP = two parallel bands joined by lateral struts).
// • Saddle / base: cross-hatched blue area spanning the edentulous region
// between abutments (or distal from terminal abutment).
// • Indirect
// retainer: rest seat (occlusal or cingulum) on a tooth FAR from
// the distal extension, often opposite the saddle.
//
// Tooth numbers are shown peripheral to each tooth. Missing teeth are dashed.
function RPDPaperFormArchDrawing({
 caseInput,
 result,
 // ── Interactive-mode props (optional) ──
 // When `interactive` is true, teeth + design elements become clickable,
 // selection rings appear, missing-tooth X overlays render, and perio
 // prognosis tints apply. When false (default), this is a static
 // print/preview rendering for the Lab Prescription section.
 interactive = false,
 selectedTooth = null,
 onSelectTooth,
 onToggleTooth,
 selectedDesignEl = null,
 onSelectDesignEl,
}) {
 // Static mode (Lab Prescription panel) requires a usable design output.
 // Interactive mode renders the empty arch so users can mark teeth and
 // build up a case — even before any teeth are missing.
 if (!result) return null;
 if (!interactive && result.kennedy.class === null) return null;
 const arch = caseInput.arch;
 const isMax = arch === "maxillary";
 const teethState = rpdNormalizeTeeth(caseInput);
 const isPresent = (n) => teethState[n]?.status === "present";

 // ── Design-element selection helpers (interactive mode only) ──
 const isElSelected = (kind, ctx = {}) => {
 if (!selectedDesignEl || selectedDesignEl.kind!== kind) return false;
 if (ctx.tooth!== undefined && selectedDesignEl.tooth!== ctx.tooth) return false;
 if (ctx.spanIndex!== undefined && selectedDesignEl.spanIndex!== ctx.spanIndex) return false;
 return true;
 };
 const handleElClick = (kind, ctx = {}) => (e) => {
 e.stopPropagation();
 if (!onSelectDesignEl) return;
 const sameAsCurrent =
 selectedDesignEl?.kind === kind &&
 (ctx.tooth === undefined || selectedDesignEl.tooth === ctx.tooth) &&
 (ctx.spanIndex === undefined || selectedDesignEl.spanIndex === ctx.spanIndex);
 onSelectDesignEl(sameAsCurrent? null: { kind,...ctx });
 };
 // Wrap a static design-element render in a clickable group + selection ring.
 // Returns the original content unchanged when not in interactive mode.
 const selectable = (content, kind, ctx, key) => {
 if (!interactive) return content;
 const sel = isElSelected(kind, ctx);
 const tooltip = ctx.tooltip || kind;
 return (
 <g key={key}
 className={`rpd-elem ${sel? "is-selected": ""}`}
 style={{ cursor: 'pointer' }}
 onClick={handleElClick(kind, ctx)}>
 <title>{tooltip}</title>
 {sel && (
 <g style={{ filter: "drop-shadow(0 0 4px var(--accent))" }} opacity={0.5}>
 {content}
 </g>
)}
 {content}
 </g>
);
 };

 // ── Ink colors (Performance Exam convention) ──
 // Aligned with the module-level RPD_OL_* constants used by the interactive
 // chart so both renderings stay in lockstep.
 const C_CAST = RPD_OL_BLUE; // cobalt blue — all cast metal framework
 const C_WW = RPD_OL_RED; // fire-engine red — wrought wire, undercut, HOC, tissue stop, acrylic outline
 const C_SURVEY = "#1A1A1A"; // black/carbon — survey line, tooth bodies, occlusal anatomy
 const C_TOOTH_FILL = "#FCFAF4";
 const C_TOOTH_LINE = "#3A332A"; // darker than before — black-ink tooth bodies match the form
 const C_MISSING = "#C9C2B3";
 const C_LABEL = "#3A332A";
 const C_FIXED = "#2C5F5D"; // deep teal — indicated fixed restoration (FPD pontic / implant crown). Per project's color semantics, teal = good / preferred.

 // ── Single-arch geometry ──
 // Matches lab-script form orientation:
 // Max → ∩ shape (anteriors at TOP, posteriors curving down to corners)
 // Mand → ∪ shape (anteriors at BOTTOM, posteriors curving up to corners)
 // Both: cy increases downward in standard SVG coordinates.
 // Arch dimensions sized to nearly fill the canvas (small fixed margins
 // for the peripheral annotations — "Akers", "0.01" mid-B", etc.).
 const W = 1400, H = 740;
 const midlineX = W / 2;
 const archHalfWidth = 560;
 const archDepth = 480;
 // Midline gap sized so anterior centrals have a clean visible separation
 // at the midline (was 64, which had the centrals' mesial edges meet
 // exactly at x=midline and their strokes visibly overlap into a single
 // mass). 72 leaves a ~4 px visible gap between the two central crown
 // outlines while still reading as proximal contact.
 const midGap = 72;
 // postY = y-coordinate of the most posterior (back) teeth.
 // Max: posteriors at BOTTOM corners → high y
 // Mand: posteriors at TOP corners → low y
 const postY = isMax? H - 110: 110;
 // archCurveDir controls which direction the parabola curves to reach the
 // anteriors. Max: curve goes UP (negative y direction) → anteriors at top.
 // Mand: curve goes DOWN (positive y direction) → anteriors at bottom.
 const archCurveDir = isMax? -1: +1;
 // Arch centroid (used for radial-direction math) sits roughly mid-arch.
 const archCenterY = isMax? postY - archDepth * 0.5: postY + archDepth * 0.5;

 const archTeeth = isMax
? Array.from({ length: 16 }, (_, i) => i + 1)
: Array.from({ length: 16 }, (_, i) => i + 17);

 const positionOf = (n) => {
 let sign, ord;
 if (isMax) {
 if (n <= 8) { sign = -1; ord = 8 - n; }
 else { sign = +1; ord = n - 9; }
 } else {
 if (n <= 24) { sign = +1; ord = 24 - n; }
 else { sign = -1; ord = n - 25; }
 }
 const halfGap = midGap / 2;
 const absX = halfGap + (ord / 7) * (archHalfWidth - halfGap);
 const cx = midlineX + sign * absX;
 const t = absX / archHalfWidth;
 const cy = postY + archCurveDir * archDepth * (1 - t * t);
 return { cx, cy };
 };

 // ── Per-tooth ord lookup (used by mesialUnit to compute the true arch
 // tangent at a tooth's position). ──
 const ordOf = (n) => {
 if (isMax) {
 return n <= 8? 8 - n: n - 9;
 }
 return n <= 24? 24 - n: n - 25;
 };
 const signOf = (n) => {
 if (isMax) {
 return n <= 8? -1: +1;
 }
 return n <= 24? +1: -1;
 };

 // ── Mesial direction = TRUE tangent to the parabolic arch at the tooth's
 // position, pointing TOWARD the midline.
 // cy(absX) = postY + archCurveDir * archDepth * (1 - (absX/archHalfWidth)²)
 // dcy/d(absX) = -archCurveDir * archDepth * 2 * absX / archHalfWidth²
 // For the side with sign>0 (chart-right), increasing cx ⇔ increasing absX,
 // and "toward midline" means decreasing absX. Mesial direction in (cx, cy)
 // space is (-sign, +archCurveDir * 2 * archDepth * absX / archHalfWidth²)
 // for the right side, mirrored on the left.
 //
 // The previous implementation used perpendicular-to-radial-from-centroid,
 // which is only correct for a CIRCULAR arch. For a parabolic arch with
 // posteriors near a flat horizontal tangent, the perpendicular has
 // ambiguous y-sign and picked the wrong one. ──
 const mesialUnit = (n) => {
 const sign = signOf(n);
 const ord = ordOf(n);
 const halfGap = midGap / 2;
 const absX = halfGap + (ord / 7) * (archHalfWidth - halfGap);
 // Slope dcy/d(absX) of the parabola at this absX
 const slope = -archCurveDir * archDepth * 2 * absX / (archHalfWidth * archHalfWidth);
 // Tangent in direction of decreasing absX (mesial direction):
 // (-sign in cx, -slope in cy)
 // For sign=+1 (right side): mesial cx-component is negative (toward midline)
 // For sign=-1 (left side): mesial cx-component is positive (toward midline)
 const dx = -sign;
 const dy = -slope * (-sign) * sign; // simplifies to: -slope if sign=+1, +slope if sign=-1 → multiply by -sign
 // Above is confusing — clearer:
 // d(cx)/d(absX) = sign
 // d(cy)/d(absX) = slope
 // moving toward mesial means d(absX) < 0, so mesial direction is
 // (-sign, -slope) in cx-cy space.
 const mx = -sign;
 const my = -slope;
 const len = Math.sqrt(mx * mx + my * my) || 1;
 return { x: mx / len, y: my / len };
 };

 // ── Radial direction = perpendicular to the arch tangent, pointing
 // OUTWARD (buccal side, away from arch interior). For ∩ max the outward
 // direction is UP-and-outward at posteriors; for ∪ mand it's DOWN-and-
 // outward.
 // The mesial unit vector is m = (mx, my). Rotating 90° gives two
 // perpendiculars: (-my, mx) and (my, -mx). The buccal direction is the
 // one pointing AWAY from archCenterY (the centroid). ──
 const radialUnit = (n) => {
 const { cx, cy } = positionOf(n);
 const m = mesialUnit(n);
 // Two perpendicular candidates
 const c1 = { x: -m.y, y: m.x };
 const c2 = { x: m.y, y: -m.x };
 // Pick the one pointing AWAY from arch centroid
 const dx = cx - midlineX;
 const dy = cy - archCenterY;
 const dot1 = c1.x * dx + c1.y * dy;
 const dot2 = c2.x * dx + c2.y * dy;
 return dot1 >= dot2? c1: c2;
 };

 // Per-tooth half-widths along M-D and B-L axes. Proportions loosely
 // anatomic (incisors wider M-D than B-L, premolars wider B-L, molars
 // roughly square), but anteriors are exaggerated above true anatomic
 // ratio so they're readable and clickable at the chart's display size.
 // Mandibular incisors in particular: true anatomic is ~5×6 mm; on a
 // chart that renders ~600 px wide, that's a postage stamp.
 const isMaxCentralPF = (n) => n === 8 || n === 9;
 const isMaxLateralPF = (n) => n === 7 || n === 10;
 const isMandCentralPF = (n) => n === 24 || n === 25;
 const isMandLateralPF = (n) => n === 23 || n === 26;
 // Tooth half-widths bumped ~1.4-1.7× from baseline so individual teeth
 // are clearly visible and clickable at the chart's typical display size.
 // M-D constrained by arch spacing (~72 px per ord) — molars at halfMD=36
 // have total width 72, just touching neighbors at proximal contacts.
 // B-L unconstrained by neighbors, scaled more aggressively for readability.
 // Tooth half-widths bumped up to use the wider chart real estate. MD
 // (mesiodistal) is constrained by arch spacing (~75 px between adjacent
 // ord positions) so it gets a smaller bump; BL (buccolingual) is
 // perpendicular to the arch and unconstrained by neighbors, so it gets
 // a larger bump for better visibility of internal anatomy and clasp
 // arms.
 // Tooth dimensions (half-widths along mesio-distal and bucco-lingual
 // axes). Values calibrated to real anatomic ratios:
 // Maxillary molars: M-D ≈ 0.9 × B-L (nearly square, slight BL bias)
 // Mandibular molars: M-D ≈ 1.05 × B-L (M-D WIDER than B-L)
 // Max premolars: M-D ≈ 0.85 × B-L (BL wider, more square)
 // Mand premolars: M-D ≈ B-L (nearly square)
 // Canines: M-D ≈ 0.85 × B-L
 // Incisors: M-D < B-L (narrower along arch)
 // Numbers are intentionally larger than literal anatomic mm so the
 // chart has room for internal annotations + clasp arms.
 const isMaxMolar = (n) => n >= 1 && n <= 3 || n >= 14 && n <= 16;
 const isMandMolar = (n) => n >= 17 && n <= 19 || n >= 30 && n <= 32;
 const isMaxPremolar = (n) => n === 4 || n === 5 || n === 12 || n === 13;
 const isMandPremolar = (n) => n === 20 || n === 21 || n === 28 || n === 29;
 const toothHalfMD = (n) => {
 if (isMaxMolar(n)) return 48; // max molars: nearly square
 if (isMandMolar(n)) return 50; // mand molars: MD slightly wider
 if (isMaxPremolar(n)) return 38;
 if (isMandPremolar(n)) return 40;
 if (RPD_CANINES.has(n)) return 36;
 if (isMaxCentralPF(n)) return 32;
 if (isMaxLateralPF(n)) return 28;
 if (isMandCentralPF(n)) return 28;
 if (isMandLateralPF(n)) return 30;
 return 28;
 };
 const toothHalfBL = (n) => {
 if (isMaxMolar(n)) return 52; // max molars: BL slight wider
 if (isMandMolar(n)) return 46; // mand molars: BL narrower than MD
 if (isMaxPremolar(n)) return 45;
 if (isMandPremolar(n)) return 42;
 if (RPD_CANINES.has(n)) return 44;
 if (isMaxCentralPF(n)) return 42;
 if (isMaxLateralPF(n)) return 38;
 if (isMandCentralPF(n)) return 36;
 if (isMandLateralPF(n)) return 38;
 return 34;
 };
 const toothRadius = (n) => Math.max(toothHalfMD(n), toothHalfBL(n));

 // Tooth-body path: rounded shape with modest cusp bulges at the corners
 // (matches the printed form's tooth illustrations — not pure circles).
 const toothPath = (cx, cy, halfMD, halfBL, rad, mes, r, cuspBulge = 0) => {
 const cb = cuspBulge;
 const MB = { x: cx + mes.x * halfMD + rad.x * halfBL, y: cy + mes.y * halfMD + rad.y * halfBL };
 const DB = { x: cx - mes.x * halfMD + rad.x * halfBL, y: cy - mes.y * halfMD + rad.y * halfBL };
 const DL = { x: cx - mes.x * halfMD - rad.x * halfBL, y: cy - mes.y * halfMD - rad.y * halfBL };
 const ML = { x: cx + mes.x * halfMD - rad.x * halfBL, y: cy + mes.y * halfMD - rad.y * halfBL };
 const bulge = (c, mdS, blS) => ({
 x: c.x + (mes.x * mdS + rad.x * blS) * halfMD * cb,
 y: c.y + (mes.y * mdS + rad.y * blS) * halfMD * cb,
 });
 const cMB = bulge(MB, +1, +1), cDB = bulge(DB, -1, +1), cDL = bulge(DL, -1, -1), cML = bulge(ML, +1, -1);
 // Each corner contributes TWO edge-endpoints: one on each of the two
 // edges meeting at the corner. The endpoint on a given edge is the
 // corner displaced ALONG that edge (toward the adjacent corner) by r.
 // Mesial edge runs along the radial axis (varying rad-coord at
 // fixed mes-coord = ±halfMD). To move along the mesial edge,
 // change rad.
 // Buccal/lingual edges run along the mesial axis (varying mes-coord
 // at fixed rad-coord = ±halfBL). To move along these edges,
 // change mes.
 // Distal edge runs along the radial axis (varying rad-coord at
 // mes-coord = -halfMD). To move along the distal edge, change rad.
 // BUG FIX: DL's two endpoints were swapped (DL_D used mes-shift when
 // it should have used rad-shift, and vice versa for DL_L), which made
 // the path's L-lines after the DL corner cut diagonally across the
 // tooth instead of running along the lingual + distal edges. This
 // showed up as visible "wings" sticking out at the DL corner of every
 // tooth once the cusp bulge was reduced.
 const MB_M = { x: MB.x - rad.x * r, y: MB.y - rad.y * r }; // mesial edge near MB
 const MB_B = { x: MB.x - mes.x * r, y: MB.y - mes.y * r }; // buccal edge near MB
 const DB_B = { x: DB.x + mes.x * r, y: DB.y + mes.y * r }; // buccal edge near DB
 const DB_D = { x: DB.x - rad.x * r, y: DB.y - rad.y * r }; // distal edge near DB
 const DL_D = { x: DL.x + rad.x * r, y: DL.y + rad.y * r }; // distal edge near DL (was using mes — BUG)
 const DL_L = { x: DL.x + mes.x * r, y: DL.y + mes.y * r }; // lingual edge near DL (was using rad — BUG)
 const ML_L = { x: ML.x - mes.x * r, y: ML.y - mes.y * r }; // lingual edge near ML
 const ML_M = { x: ML.x + rad.x * r, y: ML.y + rad.y * r }; // mesial edge near ML
 return `M ${MB_B.x} ${MB_B.y} `
 + `Q ${cMB.x} ${cMB.y} ${MB_M.x} ${MB_M.y} L ${ML_M.x} ${ML_M.y} `
 + `Q ${cML.x} ${cML.y} ${ML_L.x} ${ML_L.y} L ${DL_L.x} ${DL_L.y} `
 + `Q ${cDL.x} ${cDL.y} ${DL_D.x} ${DL_D.y} L ${DB_D.x} ${DB_D.y} `
 + `Q ${cDB.x} ${cDB.y} ${DB_B.x} ${DB_B.y} Z`;
 };

 // ── Tooth body with internal occlusal anatomy ──
 // Replaces the simple circle with an anatomic shape matching the form's
 // printed teeth: rounded with modest cusp bulges, internal grooves drawn
 // in to differentiate class. In interactive mode, wraps in a click target
 // and adds selection ring, missing-tooth X overlay, perio tint, frenum tick.
 // NOTE: This is a regular function returning JSX — NOT a React component.
 // Defining it as a component inside the parent's render (`const Tooth =`
 // arrow component) gave it a fresh function identity on every render,
 // causing React to fully unmount + remount the tooth `<g>` between
 // clicks. That broke `onDoubleClick` because both clicks need the same
 // DOM target. Calling it directly avoids the component remount.
 const renderTooth = (n) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const present = isPresent(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const isMolar = RPD_FIRST_MOLARS.has(n) || RPD_SECOND_MOLARS.has(n) || RPD_THIRD_MOLARS.has(n);
 const isPM = [4,5,12,13,20,21,28,29].includes(n);
 const isCanine = RPD_CANINES.has(n);

 // Interactive state
 const isSelected = interactive && selectedTooth === n;
 const attrs = teethState[n]?.attrs || {};
 const hasFrenum =!!attrs.highFrenum;
 const isPerioPoor = attrs.perioPrognosis === "poor" || attrs.perioPrognosis === "hopeless";
 const isPerioHopeless = attrs.perioPrognosis === "hopeless";

 const cornerR = Math.min(halfMD, halfBL) * 0.28;
 // Cusp bulges sized to match the form's printed teeth: visible
 // anatomic character at each corner without protruding so far that
 // proximal contacts become ambiguous. Molars get the most pronounced
 // 4-cusp shape; premolars are intermediate; canines have a slight
 // labial bulge only (real cusp tip is internal); incisors stay flat.
 const cuspBulge = isMolar? 0.18: isPM? 0.11: isCanine? 0.07: 0;
 const d = toothPath(cx, cy, halfMD, halfBL, rad, mes, cornerR, cuspBulge);
 const innerStroke = isSelected? "var(--accent)"
: present? "#7A6F5C"
: C_MISSING;
 const innerStrokeW = isSelected? 2.2: 1.4;

 // Tooth-number label placement — same rule for every tooth: centered on
 // the OUTER (buccal/labial) wall, offset radially outward by halfBL + 20.
 // Earlier we put anterior numbers on the lingual side with per-tooth
 // offsets, but the inconsistency between posterior (centered on buccal)
 // and anterior (lingual, shifted) was visually jarring. Using +rad
 // throughout puts every label on the same anatomic axis — buccal for
 // posteriors, labial for anteriors — centered across the tooth's M-D.
 const numX = cx + rad.x * (halfBL + 20);
 const numY = cy + rad.y * (halfBL + 20) + 4;

 // Internal occlusal anatomy markings (only on present teeth).
 // Aimed at matching the level of detail printed on the form:
 // - Molars: 4 cusp-tip dots (MB/DB/DL/ML) + central fossa + 3 grooves
 // - Premolars: 2 cusp-tip dots (B/L) + central B-L groove
 // - Canines: cusp tip + cingulum mark
 // - Incisors: incisal edge tangent + cingulum mark
 const anatomyStroke = "#7A6F5C";
 let anatomyMarks = null;
 if (present) {
 if (isMolar) {
 const fMD = halfMD * 0.6, fBL = halfBL * 0.55;
 // Cusp tip positions: ~70% of half-axes from center toward each corner.
 const cTip = 0.7;
 const tipMB = { x: cx + (mes.x + rad.x) * 0, y: cy + 0 }; // placeholder unused
 // Use sum of axes for each corner (avoiding direct corner = avoid overlap with bulge)
 const mbX = cx + mes.x * halfMD * cTip + rad.x * halfBL * cTip;
 const mbY = cy + mes.y * halfMD * cTip + rad.y * halfBL * cTip;
 const dbX = cx - mes.x * halfMD * cTip + rad.x * halfBL * cTip;
 const dbY = cy - mes.y * halfMD * cTip + rad.y * halfBL * cTip;
 const dlX = cx - mes.x * halfMD * cTip - rad.x * halfBL * cTip;
 const dlY = cy - mes.y * halfMD * cTip - rad.y * halfBL * cTip;
 const mlX = cx + mes.x * halfMD * cTip - rad.x * halfBL * cTip;
 const mlY = cy + mes.y * halfMD * cTip - rad.y * halfBL * cTip;
 anatomyMarks = (
 <g pointerEvents="none">
 {/* Central fossa */}
 <circle cx={cx} cy={cy} r={1.6} fill={anatomyStroke} />
 {/* Central M-D groove */}
 <line x1={cx + mes.x * fMD} y1={cy + mes.y * fMD}
 x2={cx - mes.x * fMD} y2={cy - mes.y * fMD}
 stroke={anatomyStroke} strokeWidth={0.9} strokeLinecap="round" />
 {/* Buccal groove */}
 <line x1={cx} y1={cy} x2={cx + rad.x * fBL} y2={cy + rad.y * fBL}
 stroke={anatomyStroke} strokeWidth={0.9} strokeLinecap="round" />
 {/* Lingual groove */}
 <line x1={cx} y1={cy} x2={cx - rad.x * fBL} y2={cy - rad.y * fBL}
 stroke={anatomyStroke} strokeWidth={0.9} strokeLinecap="round" />
 {/* 4 cusp tips — small dots at each corner area */}
 <circle cx={mbX} cy={mbY} r={1.6} fill={anatomyStroke} opacity={0.75} />
 <circle cx={dbX} cy={dbY} r={1.6} fill={anatomyStroke} opacity={0.75} />
 <circle cx={dlX} cy={dlY} r={1.6} fill={anatomyStroke} opacity={0.75} />
 <circle cx={mlX} cy={mlY} r={1.6} fill={anatomyStroke} opacity={0.75} />
 </g>
);
 } else if (isPM) {
 const grLen = halfBL * 0.6;
 // Cusp tips at buccal + lingual midpoints (premolars are bicuspid)
 const bX = cx + rad.x * halfBL * 0.62, bY = cy + rad.y * halfBL * 0.62;
 const lX = cx - rad.x * halfBL * 0.62, lY = cy - rad.y * halfBL * 0.62;
 anatomyMarks = (
 <g pointerEvents="none">
 <line x1={cx + rad.x * grLen} y1={cy + rad.y * grLen}
 x2={cx - rad.x * grLen} y2={cy - rad.y * grLen}
 stroke={anatomyStroke} strokeWidth={0.9} strokeLinecap="round" />
 <circle cx={bX} cy={bY} r={1.5} fill={anatomyStroke} opacity={0.75} />
 <circle cx={lX} cy={lY} r={1.5} fill={anatomyStroke} opacity={0.75} />
 </g>
);
 } else if (isCanine) {
 // Cusp tip (labial) + cingulum mark (lingual)
 const tipX = cx + rad.x * halfBL * 0.68, tipY = cy + rad.y * halfBL * 0.68;
 const cingX = cx - rad.x * halfBL * 0.50, cingY = cy - rad.y * halfBL * 0.50;
 const cingW = halfMD * 0.35;
 anatomyMarks = (
 <g pointerEvents="none">
 <circle cx={tipX} cy={tipY} r={1.6} fill={anatomyStroke} />
 {/* Cingulum — short arc/line on the lingual surface */}
 <line x1={cingX + mes.x * cingW} y1={cingY + mes.y * cingW}
 x2={cingX - mes.x * cingW} y2={cingY - mes.y * cingW}
 stroke={anatomyStroke} strokeWidth={0.9} strokeLinecap="round" opacity={0.6} />
 </g>
);
 } else {
 // Incisor — incisal edge tangent line on labial side + cingulum
 const o = halfBL * 0.7;
 const tipX = cx + rad.x * o, tipY = cy + rad.y * o;
 const tx = -rad.y, ty = rad.x;
 const edgeLen = halfMD * 0.7;
 const cingX = cx - rad.x * halfBL * 0.45, cingY = cy - rad.y * halfBL * 0.45;
 const cingW = halfMD * 0.45;
 anatomyMarks = (
 <g pointerEvents="none">
 {/* Incisal edge */}
 <line x1={tipX + tx * edgeLen} y1={tipY + ty * edgeLen}
 x2={tipX - tx * edgeLen} y2={tipY - ty * edgeLen}
 stroke={anatomyStroke} strokeWidth={1.1} strokeLinecap="round" />
 {/* Cingulum hint on lingual */}
 <line x1={cingX + mes.x * cingW} y1={cingY + mes.y * cingW}
 x2={cingX - mes.x * cingW} y2={cingY - mes.y * cingW}
 stroke={anatomyStroke} strokeWidth={0.8} strokeLinecap="round" opacity={0.55} />
 </g>
);
 }
 }

 // Perio prognosis tint (interactive mode only — internal UI signal,
 // not a form convention)
 const tintFill =!interactive? null
: isPerioHopeless? "rgba(122,30,30,0.20)"
: isPerioPoor? "rgba(212,165,116,0.28)"
: null;

 // Frenum tick — short red mark on the buccal/labial side
 const frenumLen = 10;
 const frX1 = cx + rad.x * (halfBL + 2);
 const frY1 = cy + rad.y * (halfBL + 2);
 const frX2 = cx + rad.x * (halfBL + frenumLen);
 const frY2 = cy + rad.y * (halfBL + frenumLen);

 // Missing-tooth X overlay (interactive mode only)
 const Xsize = Math.min(halfMD, halfBL) * 0.75;

 const handleClick = interactive? (e) => {
 if (e.shiftKey && onToggleTooth) onToggleTooth(n);
 else if (onSelectTooth) onSelectTooth(n);
 }: undefined;
 const handleDoubleClick = interactive && onToggleTooth? () => onToggleTooth(n) : undefined;

 return (
 <g key={`t-${n}`}
 className={interactive? "rpd-tooth-active": undefined}
 style={interactive? { cursor: "pointer" }: undefined}
 onClick={handleClick}
 onDoubleClick={handleDoubleClick}>
 {/* Invisible hit-target — covers the tooth's full bounding box so
 missing teeth (dashed outlines) still catch clicks. */}
 {interactive && (
 <circle cx={cx} cy={cy} r={Math.max(halfMD, halfBL) + 2}
 fill="rgba(0,0,0,0)" pointerEvents="all" />
)}
 {/* Tooth body */}
 <path d={d}
 fill={present? C_TOOTH_FILL: "transparent"}
 stroke={innerStroke} strokeWidth={innerStrokeW}
 strokeDasharray={present? undefined: "5,5"}
 strokeLinejoin="round" pointerEvents="none" />
 {/* Perio prognosis tint over the printed tooth */}
 {tintFill && present && (
 <path d={d} fill={tintFill} pointerEvents="none" />
)}
 {/* Missing tooth X overlay */}
 {interactive &&!present && (
 <g pointerEvents="none">
 <line x1={cx - Xsize} y1={cy - Xsize} x2={cx + Xsize} y2={cy + Xsize}
 stroke="var(--accent)" strokeWidth={3} strokeLinecap="round" opacity={0.7} />
 <line x1={cx - Xsize} y1={cy + Xsize} x2={cx + Xsize} y2={cy - Xsize}
 stroke="var(--accent)" strokeWidth={3} strokeLinecap="round" opacity={0.7} />
 </g>
)}
 {anatomyMarks}
 {/* Frenum tick */}
 {interactive && hasFrenum && present && (
 <line x1={frX1} y1={frY1} x2={frX2} y2={frY2}
 stroke="var(--accent)" strokeWidth={2.4}
 pointerEvents="none" />
)}
 <text x={numX} y={numY} fontSize="20"
 fontFamily="'JetBrains Mono', monospace"
 fill={present? C_LABEL: C_MISSING}
 textAnchor="middle" opacity={0.7} fontWeight="500"
 pointerEvents="none">
 {n}
 </text>
 </g>
);
 };

 // ── Helpers to render every element type ──

 // Smooth-path helper: midpoint quadratic Bezier smoothing for tooth-tracking
 // polylines (used by every major-connector and saddle outline).
 const buildSmoothPath = (pts) => {
 if (pts.length === 0) return "";
 let d = `M ${pts[0].x} ${pts[0].y}`;
 for (let i = 1; i < pts.length - 1; i++) {
 const midX = (pts[i].x + pts[i + 1].x) / 2;
 const midY = (pts[i].y + pts[i + 1].y) / 2;
 d += ` Q ${pts[i].x} ${pts[i].y} ${midX} ${midY}`;
 }
 d += ` L ${pts[pts.length - 1].x} ${pts[pts.length - 1].y}`;
 return d;
 };

 // Variant of buildSmoothPath that PASSES THROUGH every supplied point
 // (Catmull-Rom-to-Bezier conversion). buildSmoothPath uses interior
 // points as control points, so the curve passes near but not through
 // them — fine for outlines that just need to track the general arch
 // shape. For major-connector bands that need to physically reach each
 // abutment's lingual anchor (so the minor-connector strut visibly
 // terminates inside the band), the curve must pass through every
 // anchor — use this function instead.
 const buildPassThroughPath = (pts) => {
 if (pts.length === 0) return "";
 if (pts.length === 1) return `M ${pts[0].x} ${pts[0].y}`;
 let d = `M ${pts[0].x} ${pts[0].y}`;
 for (let i = 0; i < pts.length - 1; i++) {
 const p0 = pts[i - 1] || pts[i];
 const p1 = pts[i];
 const p2 = pts[i + 1];
 const p3 = pts[i + 2] || p2;
 const c1x = p1.x + (p2.x - p0.x) / 6;
 const c1y = p1.y + (p2.y - p0.y) / 6;
 const c2x = p2.x - (p3.x - p1.x) / 6;
 const c2y = p2.y - (p3.y - p1.y) / 6;
 d += ` C ${c1x} ${c1y} ${c2x} ${c2y} ${p2.x} ${p2.y}`;
 }
 return d;
 };

 // HOC / survey-line marker — per Lab 4 + Performance Exam convention,
 // drawn as a small RED OVAL at the tripod/HOC point on the buccal or
 // lingual surface where the undercut sits. Replaces the prior 3-dash
 // row which didn't match the form convention.
 //
 // `effectiveUcLoc` overrides the user's attrs.undercutLocation when
 // provided — for Akers on tooth-supported abutments, the engine
 // translates the default mid-buccal into the textbook-correct DB or MB
 // based on sideToward, and the survey-line oval should sit where the
 // ACTUAL undercut is engaged (DB or MB) rather than at the user's
 // un-overridden default position.
 const drawSurveyLine = (n, key, effectiveUcLoc) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const attrs = teethState[n]?.attrs || {};
 const ucLoc = effectiveUcLoc || attrs.undercutLocation || "mid-buccal";
 const radSgn = (ucLoc === "mesio-lingual" || ucLoc === "disto-lingual")? -1: +1;
 const mdSgn = (ucLoc === "mesio-buccal" || ucLoc === "mesio-lingual")? +1
: (ucLoc === "disto-buccal" || ucLoc === "disto-lingual")? -1
: 0;
 const ox = cx + mes.x * mdSgn * (halfMD * 0.45) + rad.x * radSgn * (halfBL * 0.92);
 const oy = cy + mes.y * mdSgn * (halfMD * 0.45) + rad.y * radSgn * (halfBL * 0.92);
 const angle = Math.atan2(mes.y, mes.x) * 180 / Math.PI;
 return (
 <ellipse key={key} cx={ox} cy={oy} rx={5} ry={3}
 transform={`rotate(${angle} ${ox} ${oy})`}
 fill="none" stroke={C_WW} strokeWidth={1.3} />
);
 };

 // Occlusal rest — anatomic spoon drawn INSIDE the tooth at the marginal
 // ridge area. Per Lab 3 spec: rounded triangular outline, base at the
 // marginal ridge, apex toward central fossa. B-L width ≈ 1/3 of B-L
 // dimension; M-D depth ≈ 1/4 (molars) or 1/3 (PMs) of M-D.
 const drawOcclusalRest = (n, surface, key) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const mes = mesialUnit(n);
 const rad = radialUnit(n);
 const sgn = surface === "mesial"? +1: -1;
 const isMolar = RPD_FIRST_MOLARS.has(n) || RPD_SECOND_MOLARS.has(n) || RPD_THIRD_MOLARS.has(n);
 const mdDepthFrac = isMolar? 0.50: 0.60;
 const blHalf = halfBL * 0.33;
 const baseDist = halfMD * 0.85;
 const baseCx = cx + sgn * mes.x * baseDist;
 const baseCy = cy + sgn * mes.y * baseDist;
 const b1 = { x: baseCx + rad.x * blHalf, y: baseCy + rad.y * blHalf };
 const b2 = { x: baseCx - rad.x * blHalf, y: baseCy - rad.y * blHalf };
 const apexDist = halfMD * (0.85 - mdDepthFrac);
 const apex = { x: cx + sgn * mes.x * apexDist, y: cy + sgn * mes.y * apexDist };
 // Mid-side control points for the spoon curve
 const midSideX = cx + sgn * mes.x * (baseDist - mdDepthFrac * halfMD * 0.5);
 const midSideY = cy + sgn * mes.y * (baseDist - mdDepthFrac * halfMD * 0.5);
 const ms1 = { x: midSideX + rad.x * blHalf * 0.6, y: midSideY + rad.y * blHalf * 0.6 };
 const ms2 = { x: midSideX - rad.x * blHalf * 0.6, y: midSideY - rad.y * blHalf * 0.6 };
 const d = `M ${b1.x} ${b1.y} Q ${ms1.x} ${ms1.y} ${apex.x} ${apex.y} Q ${ms2.x} ${ms2.y} ${b2.x} ${b2.y} Z`;
 return <path key={key} d={d} fill={C_CAST} stroke={C_CAST} strokeWidth={0.5} />;
 };

 // Cingulum rest — V/U notch on the lingual surface, peaked toward the
 // labial. M-D extent ridge-to-ridge per Lab 3 spec.
 const drawCingulumRest = (n, key) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const baseR = halfBL * 0.85; // depth from center toward lingual edge
 const tipR = halfBL * 0.30; // peak depth toward labial
 const lipHalf = halfMD * 0.7;
 const lipM = { x: cx + mes.x * lipHalf - rad.x * baseR, y: cy + mes.y * lipHalf - rad.y * baseR };
 const lipD = { x: cx - mes.x * lipHalf - rad.x * baseR, y: cy - mes.y * lipHalf - rad.y * baseR };
 const peak = { x: cx - rad.x * tipR, y: cy - rad.y * tipR };
 return (
 <path key={key}
 d={`M ${lipM.x} ${lipM.y} Q ${peak.x} ${peak.y} ${lipD.x} ${lipD.y} Z`}
 fill={C_CAST} stroke={C_CAST} strokeWidth={0.5} />
);
 };

 // Ball rest: small filled blue circle on the lingual cingulum.
 const drawBallRest = (n, key) => {
 const { cx, cy } = positionOf(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 return (
 <circle key={key}
 cx={cx - rad.x * halfBL * 0.6} cy={cy - rad.y * halfBL * 0.6}
 r={halfBL * 0.28} fill={C_CAST} />
);
 };

 // I-bar: standard convention from the filled-in paper forms shows TWO elements
 // for the I-bar drawing:
 // (1) BLUE solid bar from the major connector area up to the buccal
 // gingival third — this is the actual I-bar metal.
 // (2) RED DASHED CURVE arcing through the buccal vestibule, showing the
 // exact undercut path the tip engages (the "create 0.01 mid-buccal
 // undercut" instruction, marked in red per standard convention).
 //
 // I-bar (and its T-bar / Y-bar variants) — V2 textbook rendering.
 // Calibrated against the Fall 2022 "Bar Clasps" slide deck and the
 // hand-drawn Design Case 1 forms.
 //
 // All three variants share the same approach geometry — a horizontal
 // limb from the saddle, a vertical approach stem rising gingivally to
 // the tooth — and differ only at the terminal:
 //
 // I-bar → short horizontal engagement segment parallel to the
 // buccal contour. Single contact point at the gingival
 // third of the tooth.
 //
 // T-bar → longer horizontal CROSS-PIECE at the tip with a short
 // connecting wing up to it from the stem. The cross-piece
 // lies along the gingival contour and gives broader buccal
 // contact. Used when a wider engagement footprint is
 // indicated.
 //
 // Y-bar → forked tip: two short arms diverging from the top of the
 // stem, each contacting the tooth at the gingival third.
 // Used when a single I-bar tip would be too short to engage
 // adequately on a narrow tooth.
 //
 // `variant` accepts "I" (default), "T", or "Y".
 const drawIBar = (n, ucLocation, saddleSurface, key, variant = "I") => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const mdBias = ucLocation === "mesio-buccal"? +0.28
: ucLocation === "disto-buccal"? -0.28: 0;
 const saddleSgn = saddleSurface === "mesial"? +1: -1; // direction toward saddle

 // ── Engagement terminal: a short horizontal segment AT the tooth
 // surface, running parallel to the contour. This is the actual
 // contact with the undercut, drawn as a short line ~10–14 px long. ──
 const tipBase = halfBL * 0.95;
 // Terminal sits at tooth's buccal surface. The two ends of the
 // engagement segment are offset slightly along the mesial-distal axis
 // (M-D parallel to the buccal contour at this point).
 const engLen = Math.min(halfMD * 0.40, 10);
 const engCenter = {
 x: cx + rad.x * tipBase + mes.x * mdBias * halfMD,
 y: cy + rad.y * tipBase + mes.y * mdBias * halfMD,
 };
 const engA = {
 x: engCenter.x - mes.x * engLen,
 y: engCenter.y - mes.y * engLen,
 };
 const engB = {
 x: engCenter.x + mes.x * engLen,
 y: engCenter.y + mes.y * engLen,
 };

 // ── Vertical approach: from the saddle-side end of the engagement
 // segment, drop radially outward to the vestibule (the "I" stem). ──
 // Bias toward the saddle side so the vertical bar visibly connects
 // up to the contact rather than coming straight in from the middle.
 const stemTop = saddleSgn > 0? engB: engA;
 const stemBottom = {
 x: cx + rad.x * (halfBL + 18) + (saddleSgn * mes.x * engLen),
 y: cy + rad.y * (halfBL + 18) + (saddleSgn * mes.y * engLen),
 };

 // ── Horizontal limb: from the bottom of the stem, run toward the
 // saddle so the bar visually connects into the framework lattice. ──
 const tail = {
 x: stemBottom.x + saddleSgn * mes.x * (halfMD + 14),
 y: stemBottom.y + saddleSgn * mes.y * (halfMD + 14),
 };

 // Red dashed undercut curve in the vestibule, just outside buccal edge.
 const curveStart = {
 x: cx + (rad.x * (halfBL + 14)) - (mes.x * 0.5 * halfMD),
 y: cy + (rad.y * (halfBL + 14)) - (mes.y * 0.5 * halfMD),
 };
 const curveEnd = {
 x: cx + (rad.x * (halfBL + 14)) + (mes.x * 0.5 * halfMD),
 y: cy + (rad.y * (halfBL + 14)) + (mes.y * 0.5 * halfMD),
 };
 const curveCtrl = {
 x: cx + rad.x * (halfBL + 24),
 y: cy + rad.y * (halfBL + 24),
 };
 // ── Variant-specific terminal geometry ──
 // T-bar: extend the engagement segment ~1.6× wider as a cross-piece.
 // Y-bar: replace the single segment with two diverging arms from the
 // top of the stem to the engagement endpoints.
 const isT = variant === "T";
 const isY = variant === "Y";
 const crossLen = isT? engLen * 1.6: engLen;
 const termA = {
 x: engCenter.x - mes.x * crossLen,
 y: engCenter.y - mes.y * crossLen,
 };
 const termB = {
 x: engCenter.x + mes.x * crossLen,
 y: engCenter.y + mes.y * crossLen,
 };

 return (
 <g key={key}>
 {/* Red dashed undercut curve (drawn first, so I-bar sits on top) */}
 <path d={`M ${curveStart.x} ${curveStart.y} Q ${curveCtrl.x} ${curveCtrl.y} ${curveEnd.x} ${curveEnd.y}`}
 stroke={C_WW} strokeWidth={1.8} fill="none"
 strokeDasharray="4,3" strokeLinecap="round" opacity={0.85} />
 {/* Horizontal limb (widest — rigid framework connection) */}
 <path d={`M ${tail.x} ${tail.y} L ${stemBottom.x} ${stemBottom.y}`}
 stroke={C_CAST} strokeWidth={5.0} fill="none"
 strokeLinecap="round" strokeLinejoin="round" />
 {/* Vertical approach stem (medium — the "I" of I-bar) */}
 <path d={`M ${stemBottom.x} ${stemBottom.y} L ${stemTop.x} ${stemTop.y}`}
 stroke={C_CAST} strokeWidth={4.5} fill="none"
 strokeLinecap="round" strokeLinejoin="round" />
 {/* Terminal — geometry depends on variant. */}
 {isY? (
 // Y-bar: two diverging short arms from the top of the stem.
 // Each arm runs from stemTop out to one of the cross-piece ends.
 <>
 <path d={`M ${stemTop.x} ${stemTop.y} L ${termA.x} ${termA.y}`}
 stroke={C_CAST} strokeWidth={3.5} fill="none" strokeLinecap="round" />
 <path d={`M ${stemTop.x} ${stemTop.y} L ${termB.x} ${termB.y}`}
 stroke={C_CAST} strokeWidth={3.5} fill="none" strokeLinecap="round" />
 <circle cx={termA.x} cy={termA.y} r={2.5} fill={C_CAST} />
 <circle cx={termB.x} cy={termB.y} r={2.5} fill={C_CAST} />
 </>
): (
 // I-bar or T-bar: single horizontal contact segment.
 // T-bar's contact is wider (crossLen = 1.6× engLen).
 <>
 <path d={`M ${termA.x} ${termA.y} L ${termB.x} ${termB.y}`}
 stroke={C_CAST} strokeWidth={isT? 4.2: 3.8} fill="none"
 strokeLinecap="round" />
 {/* Contact dot at the engagement center (I-bar only — T-bar's
 wider contact is its own marker). */}
 {!isT && (
 <circle cx={engCenter.x} cy={engCenter.y} r={3} fill={C_CAST} />
)}
 </>
)}
 </g>
);
 };

 // Circumferential arm (Akers retentive) — V3 textbook rendering.
 //
 // Anatomically the clasp arm sits ON the tooth surface, just gingival
 // to the height of contour for most of its length, dipping into the
 // undercut only at the terminal tip. V2 bowed the entire arm OUTWARD
 // past the tooth perimeter to emphasize "wrap"; that read as the arm
 // floating off the tooth, which isn't how it looks in McCracken's
 // figures or the hand-drawn design forms.
 //
 // V3 honors:
 //
 // 1. Arm HUGS the buccal/lingual contour. All anchors sit at ~halfBL
 // (right on the surface) so the path follows the perimeter
 // faithfully.
 //
 // 2. Origin TOUCHES the proximal plate's buccal corner. Arm visibly
 // emerges from the plate instead of starting in mid-air.
 //
 // 3. Encirclement >180° — arm reaches near the far proximal corner
 // (tipMD = 0.85 halfMD). The wrap is shown by the angular extent
 // of the path, not by pushing it outward.
 //
 // 4. Terminal tip dips just past the contour (1.05 halfBL) in the
 // LAST segment only. This is the only place the arm is "outside"
 // the perimeter — it represents the actual undercut engagement.
 //
 // 5. Taper from rigid proximal (5.5–6 px) to flexible tip (2.5 px).
 //
 // 6. Small contact dot at the terminal tip marks the engagement.
 //
 // `plateSide` is the side of the rest/plate (where the arm originates).
 // `onBuccal` toggles between buccal Akers and lingual Reverse Akers.
 const drawCircumferentialArm = (n, opts, key) => {
 const { color = C_CAST, plateSide = "mesial", onBuccal = true,
 tapered = false, undercutDepthFactor = 1.0 } = opts;
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const radSign = onBuccal? +1: -1;
 const plateSgn = plateSide === "mesial"? +1: -1;
 // ── Origin: at the proximal plate's buccal-outer corner so the arm
 // visibly emerges from the plate (no floating gap). The plate is
 // drawn centered at (halfMD + 3.5) along the mesial axis with
 // ±halfThick (5 px) thickness and ±0.55*halfBL extent radially; the
 // outer-buccal corner sits at (halfMD + 8.5, +0.55*halfBL). ──
 const plateOuterMes = halfMD + 8.5;
 const plateBL = halfBL * 0.55;
 const start = {
 x: cx + plateSgn * mes.x * plateOuterMes + radSign * rad.x * plateBL,
 y: cy + plateSgn * mes.y * plateOuterMes + radSign * rad.y * plateBL,
 };
 // ── Terminal tip: only the very tip dips slightly past the contour
 // — that's where the undercut is engaged. Rest of the arm hugs the
 // surface. tipMD = 0.92 halfMD reaches near the far proximal corner;
 // tipBL = 1.05 halfBL puts the tip just past the perimeter so the
 // engagement reads visually without making the whole arm look
 // detached from the tooth. ──
 const undercutSgn = -plateSgn;
 const tipMD = halfMD * 0.92;
 const tipBL = halfBL * (1.05 + 0.04 * undercutDepthFactor);
 const tip = {
 x: cx + undercutSgn * mes.x * tipMD + radSign * rad.x * tipBL,
 y: cy + undercutSgn * mes.y * tipMD + radSign * rad.y * tipBL,
 };
 // ── Control points pull the bezier ON the contour (1.02 halfBL),
 // not outside it. The midpoint of the curve lands at ~(0, 0.965*halfBL)
 // — right on the buccal surface — so the arm hugs the tooth for its
 // entire length except the final tip. ──
 const ctrlA = {
 x: cx + plateSgn * mes.x * (halfMD * 0.50) + radSign * rad.x * (halfBL * 1.02),
 y: cy + plateSgn * mes.y * (halfMD * 0.50) + radSign * rad.y * (halfBL * 1.02),
 };
 const ctrlB = {
 x: cx + undercutSgn * mes.x * (halfMD * 0.50) + radSign * rad.x * (halfBL * 1.02),
 y: cy + undercutSgn * mes.y * (halfMD * 0.50) + radSign * rad.y * (halfBL * 1.02),
 };
 // Build interpolated points along the bezier so we can render the
 // taper as 5 segments of decreasing stroke width.
 // Cubic Bezier formula: B(t) = (1-t)³P0 + 3(1-t)²t·P1 + 3(1-t)t²·P2 + t³P3
 const bezPt = (t) => {
 const u = 1 - t;
 return {
 x: u*u*u*start.x + 3*u*u*t*ctrlA.x + 3*u*t*t*ctrlB.x + t*t*t*tip.x,
 y: u*u*u*start.y + 3*u*u*t*ctrlA.y + 3*u*t*t*ctrlB.y + t*t*t*tip.y,
 };
 };
 const p0 = start;
 const p1 = bezPt(0.25);
 const p2 = bezPt(0.50);
 const p3 = bezPt(0.75);
 const p4 = tip;
 // Stroke widths follow the alloy type:
 // - Cast clasps (half-round cross-section, flex in one plane only):
 // dramatic taper proximal → tip ~2.4× ratio. Matches McCracken's
 // "uniform taper in BOTH thickness AND width" for cast retentive
 // arms (page 14 of Retainers slide deck).
 // - Wrought wire clasps (round cross-section, flex in all planes):
 // UNIFORM width along the length. Per McCracken: "Wrought wire
 // clasps are round and flex in all spatial planes" — they don't
 // taper. Used for Combination clasp's retentive arm, WW C-clasp,
 // Ball clasp.
 const isWroughtWire = color === C_WW;
 const wMax = isWroughtWire? 3.2: (tapered? 6.0: 5.5);
 const wMin = isWroughtWire? 3.2: 2.5;
 // Linear interpolation across 4 segments.
 const w = (i) => wMax - (wMax - wMin) * (i / 4);
 return (
 <g key={key}>
 {/* Segment 1 (proximal, rigid) — widest */}
 <path d={`M ${p0.x} ${p0.y} L ${p1.x} ${p1.y}`}
 stroke={color} strokeWidth={w(0.5)} fill="none"
 strokeLinecap="round" />
 {/* Segment 2 */}
 <path d={`M ${p1.x} ${p1.y} L ${p2.x} ${p2.y}`}
 stroke={color} strokeWidth={w(1.5)} fill="none"
 strokeLinecap="round" />
 {/* Segment 3 (middle, limited-flex) */}
 <path d={`M ${p2.x} ${p2.y} L ${p3.x} ${p3.y}`}
 stroke={color} strokeWidth={w(2.5)} fill="none"
 strokeLinecap="round" />
 {/* Segment 4 (terminal, flexible) — narrowest */}
 <path d={`M ${p3.x} ${p3.y} L ${p4.x} ${p4.y}`}
 stroke={color} strokeWidth={w(3.5)} fill="none"
 strokeLinecap="round" />
 {/* Terminal tip marker — shows where the undercut is engaged */}
 <circle cx={tip.x} cy={tip.y} r={3} fill={color} />
 </g>
);
 };

 // Ring clasp — specialty clasp for tilted mandibular molars (mesially
 // tilted with undercut on the mesio-lingual surface). Per the 
 // Retainers slide deck (page 26):
 //
 // - Primary rest: mesial occlusal (same as Akers)
 // - Auxiliary rest: distal occlusal (smaller)
 // - Supportive strut: lingual surface, supports the clasp arm against
 // collapse (rigidly braces the arm during seating)
 // - Retentive tip: engages mesio-lingual undercut (mandibular case)
 //
 // The clasp arm encircles ~330° of the tooth — starts at the primary
 // rest, wraps around the buccal contour, around the distal corner past
 // the auxiliary rest, along the lingual surface (supported by the
 // strut), and terminates at the retentive tip near the mesio-lingual
 // undercut. This near-complete "ring" gives the clasp its name.
 //
 // `plateSide` = "mesial" by default (mesial proximal plate / saddle).
 // `ucLoc` selects the undercut location; defaults to mesio-lingual for
 // typical mandibular Ring use (can be mesio-buccal for maxillary).
 const drawRingClasp = (n, opts, key) => {
 const { plateSide = "mesial", ucLoc = "mesio-lingual" } = opts;
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const plateSgn = plateSide === "mesial"? +1: -1;
 // Buccal undercut → buccal side approach. Default lingual.
 const tipOnBuccal = ucLoc === "mesio-buccal" || ucLoc === "disto-buccal";
 const tipRadSign = tipOnBuccal? +1: -1;
 // ── Primary rest anchor: at the mesial buccal corner (proximal plate
 // origin). Same as Akers proximal origin. ──
 const origin = {
 x: cx + plateSgn * mes.x * (halfMD + 3) + rad.x * (halfBL * 0.92),
 y: cy + plateSgn * mes.y * (halfMD + 3) + rad.y * (halfBL * 0.92),
 };
 // ── Mid-buccal anchor: bows outward past the buccal contour. ──
 const buccalMid = {
 x: cx + rad.x * (halfBL * 1.08),
 y: cy + rad.y * (halfBL * 1.08),
 };
 // ── Distal buccal corner: where the auxiliary rest sits. ──
 const distalBuccal = {
 x: cx - plateSgn * mes.x * (halfMD * 0.85) + rad.x * (halfBL * 1.0),
 y: cy - plateSgn * mes.y * (halfMD * 0.85) + rad.y * (halfBL * 1.0),
 };
 // ── Distal lingual corner: arm wraps to the lingual side. ──
 const distalLingual = {
 x: cx - plateSgn * mes.x * (halfMD * 0.85) - rad.x * (halfBL * 1.0),
 y: cy - plateSgn * mes.y * (halfMD * 0.85) - rad.y * (halfBL * 1.0),
 };
 // ── Mid-lingual anchor: supportive strut location. ──
 const lingualMid = {
 x: cx - rad.x * (halfBL * 1.05),
 y: cy - rad.y * (halfBL * 1.05),
 };
 // ── Terminal tip: engages the undercut. Position near the mesio-
 // lingual (or mesio-buccal) corner per ucLoc. ──
 const tip = {
 x: cx + plateSgn * mes.x * (halfMD * 0.75) + tipRadSign * rad.x * (halfBL * 1.15),
 y: cy + plateSgn * mes.y * (halfMD * 0.75) + tipRadSign * rad.y * (halfBL * 1.15),
 };
 // ── Auxiliary rest at distal occlusal (small filled marker). ──
 const auxRest = {
 x: cx - plateSgn * mes.x * (halfMD * 0.7),
 y: cy - plateSgn * mes.y * (halfMD * 0.7),
 };
 // Build the encircling arm as a cubic Bezier going through all the
 // anchors. Uses three Bezier segments for smooth wrap.
 const arm = [origin, buccalMid, distalBuccal, distalLingual, lingualMid, tip];
 const armD = `M ${arm[0].x} ${arm[0].y}` +
 ` Q ${arm[1].x} ${arm[1].y} ${arm[2].x} ${arm[2].y}` +
 ` Q ${arm[3].x} ${arm[3].y} ${arm[4].x} ${arm[4].y}` +
 ` Q ${(arm[4].x + tip.x) / 2 - rad.x * halfBL * 0.1} ${(arm[4].y + tip.y) / 2 - rad.y * halfBL * 0.1} ${tip.x} ${tip.y}`;
 return (
 <g key={key}>
 {/* Encircling arm — single continuous cast metal path */}
 <path d={armD}
 stroke={C_CAST} strokeWidth={4.5} fill="none"
 strokeLinecap="round" strokeLinejoin="round" />
 {/* Supportive strut — short perpendicular brace on lingual */}
 <line x1={lingualMid.x} y1={lingualMid.y}
 x2={lingualMid.x - rad.x * 14} y2={lingualMid.y - rad.y * 14}
 stroke={C_CAST} strokeWidth={3.2} strokeLinecap="round" />
 {/* Auxiliary rest — small filled square on distal occlusal */}
 <circle cx={auxRest.x} cy={auxRest.y} r={3.5}
 fill={C_CAST} />
 {/* Terminal tip marker — engagement point */}
 <circle cx={tip.x} cy={tip.y} r={3} fill={C_CAST} />
 </g>
);
 };

 // Embrasure clasp — used in a quadrant with no edentulous space when a
 // clasp is needed on a single tooth without an adjacent saddle. Per the
 // Retainers slide deck (page 24):
 //
 // - Two adjacent abutments share a prepared occlusal groove in the
 // embrasure between them (interproximal contact preserved).
 // - Each tooth gets its own rest seat in the embrasure.
 // - Each tooth has a retentive arm engaging the opposite-side
 // undercut (one buccal, one lingual — or both buccal on opposite
 // sides of the embrasure).
 // - Looks like "back-to-back Akers" from the top-down view.
 //
 // This renderer draws ONE side of the embrasure (single tooth view).
 // When two adjacent abutments both have claspType = "Embrasure", both
 // teeth get their own render that visually meet in the middle.
 //
 // `plateSide` = side of the embrasure (which proximal surface of the
 // tooth abuts the shared embrasure groove).
 const drawEmbrasureClasp = (n, opts, key) => {
 const { plateSide = "mesial", onBuccal = true } = opts;
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const radSign = onBuccal? +1: -1;
 const plateSgn = plateSide === "mesial"? +1: -1;
 // Origin: at the embrasure (proximal surface that abuts the partner
 // tooth), at HOC height.
 const origin = {
 x: cx + plateSgn * mes.x * (halfMD + 1) + radSign * rad.x * (halfBL * 0.92),
 y: cy + plateSgn * mes.y * (halfMD + 1) + radSign * rad.y * (halfBL * 0.92),
 };
 // Wrap around the buccal (or lingual) contour to the opposite proximal
 // corner — similar to Akers but the wrap is shorter (~140°) since
 // the arm doesn't need to encircle the tooth.
 const mid = {
 x: cx + radSign * rad.x * (halfBL * 1.05),
 y: cy + radSign * rad.y * (halfBL * 1.05),
 };
 const tip = {
 x: cx - plateSgn * mes.x * (halfMD * 0.70) + radSign * rad.x * (halfBL * 1.15),
 y: cy - plateSgn * mes.y * (halfMD * 0.70) + radSign * rad.y * (halfBL * 1.15),
 };
 // Embrasure rest seat (small filled marker AT the embrasure side,
 // shared with the partner tooth).
 const restSeat = {
 x: cx + plateSgn * mes.x * (halfMD * 0.85),
 y: cy + plateSgn * mes.y * (halfMD * 0.85),
 };
 // Smooth Bezier path: origin → buccal mid → tip
 const ctrl = {
 x: cx + plateSgn * mes.x * (halfMD * 0.5) + radSign * rad.x * (halfBL * 1.08),
 y: cy + plateSgn * mes.y * (halfMD * 0.5) + radSign * rad.y * (halfBL * 1.08),
 };
 const armD = `M ${origin.x} ${origin.y} Q ${ctrl.x} ${ctrl.y} ${mid.x} ${mid.y} Q ${(mid.x + tip.x)/2} ${(mid.y + tip.y)/2 + radSign * 2} ${tip.x} ${tip.y}`;
 return (
 <g key={key}>
 {/* Retentive arm: tapered from rest origin to tip */}
 <path d={armD}
 stroke={C_CAST} strokeWidth={4.0} fill="none"
 strokeLinecap="round" />
 {/* Embrasure rest seat marker */}
 <rect x={restSeat.x - 3} y={restSeat.y - 3} width={6} height={6}
 fill={C_CAST} />
 {/* Terminal tip marker */}
 <circle cx={tip.x} cy={tip.y} r={3} fill={C_CAST} />
 </g>
);
 };

 // Reciprocal arm — V2. STAYS ABOVE HOC throughout (never engages an
 // undercut), provides bracing (must be rigid). Drawn so the arm HUGS
 // the lingual surface from proximal corner to proximal corner.
 //
 // Visually distinguished from the retentive Akers arm:
 // - Wider (4.5 px vs the retentive arm's 6→2.5 taper) — reflects
 // McCracken's "tapers in thickness BUT NOT width to maintain
 // rigidity" rule for reciprocal arms.
 // - No terminal tip marker — reciprocal arm has no engagement point.
 // - Blunter end caps (butt instead of round) — reads as a bracing
 // ribbon rather than a flexible retentive arm.
 //
 // McCracken / form illustrations show a rounded arc that follows
 // the convex lingual contour — start, midpoint, and end all sit AT or
 // just inside the lingual surface (never bulging past it, never
 // cutting diagonally across the proximal corners).
 const drawReciprocalArm = (n, plateSide, key) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const radSign = -1; // lingual side (opposite the retentive arm)
 const plateSgn = plateSide === "mesial"? +1: -1;
 // Start at the proximal plate's lingual-outer corner so the arm
 // visibly emerges from the plate (mirrors the retentive arm origin
 // on the buccal side). Plate is centered at (halfMD + 3.5) along
 // mesial with ±5 px thickness and ±0.55*halfBL extent — lingual-outer
 // corner sits at (halfMD + 8.5, −0.55*halfBL).
 const start = {
 x: cx + plateSgn * mes.x * (halfMD + 8.5) + radSign * rad.x * (halfBL * 0.55),
 y: cy + plateSgn * mes.y * (halfMD + 8.5) + radSign * rad.y * (halfBL * 0.55),
 };
 // End at the OPPOSITE proximal-lingual corner of the tooth (no plate
 // there — the arm just terminates at the tooth's proximal edge).
 const end = {
 x: cx - plateSgn * mes.x * (halfMD * 0.92) + radSign * rad.x * (halfBL * 0.95),
 y: cy - plateSgn * mes.y * (halfMD * 0.92) + radSign * rad.y * (halfBL * 0.95),
 };
 // Control points pulled to the lingual surface so the arc follows the
 // convex lingual contour without bulging past it.
 const surfaceDepth = halfBL * 1.0;
 const ctrl1 = {
 x: cx + plateSgn * mes.x * (halfMD * 0.45) + radSign * rad.x * surfaceDepth,
 y: cy + plateSgn * mes.y * (halfMD * 0.45) + radSign * rad.y * surfaceDepth,
 };
 const ctrl2 = {
 x: cx - plateSgn * mes.x * (halfMD * 0.45) + radSign * rad.x * surfaceDepth,
 y: cy - plateSgn * mes.y * (halfMD * 0.45) + radSign * rad.y * surfaceDepth,
 };
 return (
 <path key={key}
 d={`M ${start.x} ${start.y} C ${ctrl1.x} ${ctrl1.y} ${ctrl2.x} ${ctrl2.y} ${end.x} ${end.y}`}
 stroke={C_CAST} strokeWidth={4.5} fill="none" strokeLinecap="butt" />
);
 };

 // Lingual / palatal reciprocal PLATE: drawn when reciprocation.type === "plate"
 // (e.g. RPI's distal proximal plate continues lingually as a reciprocal
 // plate, or a free-standing lingual plate on a tooth-supported abutment).
 // In the paper form this appears as a SOLID FILLED BLUE crescent
 // hugging the lingual surface of the abutment, contacting the cingulum
 // height and connecting laterally to the major connector.
 const drawReciprocalPlate = (n, key) => {
 const { cx, cy } = positionOf(n);
 const R = toothRadius(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 // Inner edge: sits just inside the lingual contour of the tooth (the
 // cingulum height). Outer edge: extends radially inward into the palate
 // / floor of mouth toward the major connector.
 const innerHalf = R * 0.85;
 const outerHalf = R * 0.7;
 const innerDepth = R * 0.45;
 const outerDepth = R * 1.05;
 const i1 = { x: cx + mes.x * innerHalf - rad.x * innerDepth,
 y: cy + mes.y * innerHalf - rad.y * innerDepth };
 const i2 = { x: cx - mes.x * innerHalf - rad.x * innerDepth,
 y: cy - mes.y * innerHalf - rad.y * innerDepth };
 const o2 = { x: cx - mes.x * outerHalf - rad.x * outerDepth,
 y: cy - mes.y * outerHalf - rad.y * outerDepth };
 const o1 = { x: cx + mes.x * outerHalf - rad.x * outerDepth,
 y: cy + mes.y * outerHalf - rad.y * outerDepth };
 return (
 <path key={key}
 d={`M ${i1.x} ${i1.y} L ${i2.x} ${i2.y} L ${o2.x} ${o2.y} L ${o1.x} ${o1.y} Z`}
 fill={C_CAST} stroke={C_CAST} strokeWidth={0.8} fillOpacity={0.85} />
);
 };

 // Proximal plate / minor connector: SOLID FILLED BLUE RECTANGLE sitting
 // FLUSH against the proximal surface. Inner edge pulled slightly inside
 // the tooth's perimeter so the plate visually attaches to (is prepared
 // on) the abutment rather than floating outside it.
 // Uses halfMD for the mesial-direction offset (not max(halfMD,halfBL))
 // since the mesial edge of the tooth is at halfMD along that axis. Uses
 // halfBL for the bucco-lingual extent of the plate (covers ~1/2 of B-L).
 const drawGuidePlane = (n, surface, key) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const mes = mesialUnit(n);
 const rad = radialUnit(n);
 const sgn = surface === "mesial"? +1: -1;
 const halfLen = halfBL * 0.55; // B-L coverage of the plate
 const halfThick = 5;
 // Plate center sits at (halfMD + halfThick - 1.5) along the mesial
 // direction: inner edge ~1.5 px inside the tooth perimeter, outer edge
 // ~3.5 px outside. This makes the plate visually "attached to" the
 // tooth's proximal surface rather than floating away.
 const px = cx + sgn * mes.x * (halfMD + halfThick - 1.5);
 const py = cy + sgn * mes.y * (halfMD + halfThick - 1.5);
 const c1 = { x: px + rad.x * halfLen + sgn * mes.x * halfThick, y: py + rad.y * halfLen + sgn * mes.y * halfThick };
 const c2 = { x: px - rad.x * halfLen + sgn * mes.x * halfThick, y: py - rad.y * halfLen + sgn * mes.y * halfThick };
 const c3 = { x: px - rad.x * halfLen - sgn * mes.x * halfThick, y: py - rad.y * halfLen - sgn * mes.y * halfThick };
 const c4 = { x: px + rad.x * halfLen - sgn * mes.x * halfThick, y: py + rad.y * halfLen - sgn * mes.y * halfThick };
 return (
 <polygon key={key}
 points={`${c1.x},${c1.y} ${c2.x},${c2.y} ${c3.x},${c3.y} ${c4.x},${c4.y}`}
 fill={C_CAST} stroke={C_CAST} strokeWidth={0.8} />
);
 };

 // Saddle / denture base — pattern depends on base type:
 // "Open Lattice" → LADDER pattern (two parallel rails + perpendicular
 // rungs). Used at distal-extension saddles.
 // "Mesh" → tight GRID pattern. Used at shorter anterior saddles.
 // Default → mesh.
 // Matches paper-form convention where the student draws either a
 // ladder or a tight grid depending on what's specified.
 const drawSaddleSpan = (spanTeeth, baseType, key) => {
 if (!spanTeeth || spanTeeth.length === 0) return null;
 const archSpan = spanTeeth.filter(n => archTeeth.includes(n));
 if (archSpan.length === 0) return null;
 const isOpenLattice = (baseType || "").toLowerCase().includes("open lattice")
 || (baseType || "").toLowerCase().includes("lattice");
 const buccalPts = archSpan.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx + r.x * (R + 6), y: cy + r.y * (R + 6) };
 });
 const lingualPts = [...archSpan].reverse().map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R + 8), y: cy - r.y * (R + 8) };
 });
 // Smooth the buccal sweep and the lingual return sweep separately so the
 // saddle outline matches the soft curves of the alveolar ridge instead of
 // a polyline with kinks.
 const buccalSmooth = buildSmoothPath(buccalPts);
 const lingualSmooth = buildSmoothPath(lingualPts);
 const pathD = `${buccalSmooth} L ${lingualPts[0].x} ${lingualPts[0].y} ${lingualSmooth.replace(/^M [^ ]+ [^ ]+/, '')} Z`;

 // Interior pattern: ladder for open lattice, tight grid for mesh
 let interior;
 if (isOpenLattice) {
 // Draw 2 rails along the saddle long axis + perpendicular rungs
 // Take the tooth positions and offset slightly buccal/lingual
 const rail1 = archSpan.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx + r.x * (R * 0.35), y: cy + r.y * (R * 0.35) };
 });
 const rail2 = archSpan.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R * 0.35), y: cy - r.y * (R * 0.35) };
 });
 const rail1D = rail1.map((p, i) => i === 0? `M ${p.x} ${p.y}`: `L ${p.x} ${p.y}`).join(" ");
 const rail2D = rail2.map((p, i) => i === 0? `M ${p.x} ${p.y}`: `L ${p.x} ${p.y}`).join(" ");
 interior = (
 <g>
 <path d={rail1D} stroke={C_CAST} strokeWidth={1.8} fill="none" strokeLinecap="round" />
 <path d={rail2D} stroke={C_CAST} strokeWidth={1.8} fill="none" strokeLinecap="round" />
 {rail1.map((p, i) => (
 <line key={`rung-${i}`} x1={p.x} y1={p.y} x2={rail2[i].x} y2={rail2[i].y}
 stroke={C_CAST} strokeWidth={1.4} strokeLinecap="round" />
))}
 </g>
);
 } else {
 const patternId = `pf-mesh-${key}`;
 interior = (
 <>
 <defs>
 <pattern id={patternId} patternUnits="userSpaceOnUse" width="6" height="6">
 <line x1="0" y1="0" x2="6" y2="0" stroke={C_CAST} strokeWidth="0.7" />
 <line x1="0" y1="0" x2="0" y2="6" stroke={C_CAST} strokeWidth="0.7" />
 </pattern>
 </defs>
 <path d={pathD} fill={`url(#${patternId})`} stroke="none" />
 </>
);
 }

 return (
 <g key={key}>
 {/* Invisible hit-target — covers the entire saddle bounding area so
 clicks register anywhere on the saddle, including the empty
 space between lattice rungs. Sits underneath the visible
 interior + outline so it doesn't visually obscure them. */}
 <path d={pathD} fill="rgba(0,0,0,0)" pointerEvents="all" />
 {interior}
 <path d={pathD} fill="none"
 stroke={C_CAST} strokeWidth={2.2}
 strokeLinejoin="round" />
 {/* Denture teeth — dashed circle outlines floating on the saddle */}
 {archSpan.map(n => {
 const { cx, cy } = positionOf(n);
 const R = toothRadius(n);
 return (
 <circle key={`pf-base-tooth-${n}`} cx={cx} cy={cy} r={R}
 fill="rgba(255,255,255,0.75)" stroke={C_CAST} strokeWidth={1.4}
 strokeDasharray="3,3" />
);
 })}
 </g>
);
 };

 // Tissue stop — small red T-shape at the DISTAL END of a distal-extension
 // saddle. Per Performance Exam color code: drawn in RED. Per the 2025
 // Connectors lecture: mandatory on all Class I/II distal-extension cases;
 // stabilizes the framework during acrylic processing.
 //
 // The T-shape (a short horizontal bar perpendicular to a vertical stem)
 // matches the hand-drawn convention better than the previous small
 // oval — it visually reads as a "stop" hitting tissue rather than just
 // a marker.
 const drawTissueStop = (spanTeeth, key) => {
 if (!spanTeeth || spanTeeth.length === 0) return null;
 const archSpan = spanTeeth.filter(n => archTeeth.includes(n));
 if (archSpan.length === 0) return null;
 // The distal-most tooth in the span is the one furthest from midline
 // (highest ord). Find it by comparing ord values.
 let distalN = archSpan[0];
 let distalOrd = ordOf(distalN);
 for (const n of archSpan) {
 const o = ordOf(n);
 if (o > distalOrd) { distalOrd = o; distalN = n; }
 }
 const { cx, cy } = positionOf(distalN);
 const rad = radialUnit(distalN);
 const mes = mesialUnit(distalN);
 // Tissue stop sits at the DISTAL end of the saddle, projecting past
 // its outline. Crucially it must visibly CONNECT to the saddle (it's
 // a continuous piece of the framework), so we draw a short blue
 // connector segment from the saddle edge to the stop's cross-bar.
 const halfMD = toothHalfMD(distalN);
 const halfBL = toothHalfBL(distalN);
 // Saddle outline distal edge: 6 px past the tooth's distal proximal
 // face (matches drawSaddleSpan's R + 6 buccal offset for the outline).
 const saddleEdge = {
 x: cx - mes.x * (halfMD + 6),
 y: cy - mes.y * (halfMD + 6),
 };
 // Tissue-stop center: another ~12 px distal of the saddle edge so
 // there's a visible connector segment between them.
 const tsX = saddleEdge.x - mes.x * 12 + rad.x * (halfBL * 0.3);
 const tsY = saddleEdge.y - mes.y * 12 + rad.y * (halfBL * 0.3);
 // T-shape: horizontal cross-bar (perpendicular to saddle long axis)
 // + short vertical stem (along saddle long axis, pointing distally).
 const crossHalf = 7;
 const stemLen = 7;
 const crossA = { x: tsX + rad.x * crossHalf, y: tsY + rad.y * crossHalf };
 const crossB = { x: tsX - rad.x * crossHalf, y: tsY - rad.y * crossHalf };
 const stemEnd = { x: tsX - mes.x * stemLen, y: tsY - mes.y * stemLen };
 return (
 <g key={key}>
 {/* Invisible hit pad — comfortable click target. */}
 {interactive && (
 <circle cx={tsX} cy={tsY} r={28}
 fill="rgba(0,0,0,0)" pointerEvents="all" />
)}
 {/* Connector segment from the saddle edge to the cross-bar.
 Drawn in cast-metal blue so it reads as a continuous piece of
 the framework, then transitions to the red T-shape for the
 tissue-stop marker itself. */}
 <line x1={saddleEdge.x} y1={saddleEdge.y} x2={tsX} y2={tsY}
 stroke={C_CAST} strokeWidth={2.6} strokeLinecap="round" />
 {/* Horizontal cross-bar of the T */}
 <line x1={crossA.x} y1={crossA.y} x2={crossB.x} y2={crossB.y}
 stroke={C_WW} strokeWidth={2.4} strokeLinecap="round" />
 {/* Vertical stem of the T (distal-pointing) */}
 <line x1={tsX} y1={tsY} x2={stemEnd.x} y2={stemEnd.y}
 stroke={C_WW} strokeWidth={2.4} strokeLinecap="round" />
 <text className="rpd-elem-label"
 x={tsX + rad.x * 20} y={tsY + rad.y * 20 + 4}>
 Tissue stop
 </text>
 </g>
);
 };

 // Per-abutment annotation: handwritten-style note placed near the tooth,
 // showing clasp shorthand + undercut depth & location.
 // Examples: "RPI / 0.01" MB", "Akers / 0.01" MB", "WW C / 0.02" MB"
 const drawAbutmentAnnotation = (a, key) => {
 const tooth = a.tooth;
 const { cx, cy } = positionOf(tooth);
 const R = toothRadius(tooth);
 const rad = radialUnit(tooth);
 const attrs = teethState[tooth]?.attrs || {};
 // Prefer the engine's effective undercut (e.g. Akers default DB based
 // on sideToward) over the raw user attrs default. Falls back to
 // attrs.undercutLocation if the engine didn't compute one.
 const ucLoc = a.effectiveUndercutLocation || attrs.undercutLocation || "mid-buccal";
 const ucDepth = attrs.undercutDepth || "0.01\"";
 const ucShort = ucLoc === "mesio-buccal"? "MB"
: ucLoc === "disto-buccal"? "DB"
: ucLoc === "mesio-lingual"? "ML"
: ucLoc === "disto-lingual"? "DL": "mid-B";
 const ct = a.claspType || "";
 const claspShort = ct.includes("RPI")? "RPI"
: ct.includes("I-bar")? "I-bar"
: ct === "Akers"? "Akers"
: ct === "Reverse Akers"? "R.Akers"
: ct === "Combination"? "Comb"
: ct === "Embrasure"? "Embr"
: ct === "WW C-clasp"? "WW C"
: ct === "Ball Clasp"? "Ball"
: ct.includes("Rest Only")? "Rest only"
: ct;
 const hasClasp =!ct.includes("Rest Only");
 // Annotation placed radially OUT from the tooth (buccal), past the
 // tooth-number label so the two never visually collide. Tooth number
 // sits at halfBL + 20 along radial; annotation starts further out at
 // R + 58 to clear it with breathing room. The undercut-spec line is
 // placed an additional 30 px FURTHER OUT along the radial direction
 // (not just below in screen-Y) — this keeps the second line away from
 // the tooth on both arches rather than collapsing inward on maxillary
 // teeth where rad.y is negative. 30 px (vs 22 previously) accounts
 // for the 22 px clasp glyph height + 17 px undercut glyph height so
 // the two labels don't overlap.
 // Annotation position with viewport clamp so labels on teeth at the
 // far ends of the arch (#1/#16/#17/#32 area) don't get cut off the
 // right or left edge of the SVG. viewBox is 1400 wide; reserve ~50
 // px on each edge so the label text (with text-anchor middle and
 // ~50–70 px width) stays fully visible.
 const VIEW_W = 1400;
 const LABEL_PAD = 50;
 const rawAx = cx + rad.x * (R + 58);
 const rawAy = cy + rad.y * (R + 58);
 const ax = Math.max(LABEL_PAD, Math.min(VIEW_W - LABEL_PAD, rawAx));
 const ay = rawAy;
 // ax2 = ax (same x) so the clasp name and the undercut depth/loc
 // line are vertically aligned — both share text-anchor="middle"
 // so equal x centers them on the same axis. The vertical offset
 // (rad.y * 30) still pushes the second line radially outward
 // (above for maxillary / below for mandibular), keeping the two
 // labels from overlapping. The previous code applied rad.x * 30
 // too, which threw "0.01" MB" off-center relative to "Akers" on
 // every tooth not at the dead-center top/bottom of the arch.
 const ax2 = ax;
 const ay2 = ay + rad.y * 30;
 // Clasp name text → selects the clasp element. Undercut spec text →
 // selects the undercut. For Rest-only abutments (no clasp), the
 // single label selects the rest seat instead.
 const claspKind = hasClasp? 'clasp': 'rest';
 return (
 <g key={key}>
 <text x={ax} y={ay} fontSize="22"
 fontFamily="'Geist', sans-serif" fontWeight="700"
 fill={C_LABEL} textAnchor="middle"
 style={interactive? { cursor: 'pointer' }: undefined}
 onClick={interactive? handleElClick(claspKind, { tooth }): undefined}>
 {claspShort}
 </text>
 {hasClasp && (
 <text x={ax2} y={ay2} fontSize="17"
 fontFamily="'Geist', sans-serif" fontStyle="italic"
 fill={C_WW} textAnchor="middle"
 style={interactive? { cursor: 'pointer' }: undefined}
 onClick={interactive? handleElClick('undercut', { tooth }): undefined}>
 {ucDepth} {ucShort}
 </text>
)}
 </g>
);
 };

 // Minor connector — thin blue strut linking a rest seat / proximal plate
 // to the major connector. Per the 2025 Major/Minor Connectors lecture:
 // - Joins clasp assembly + rest to the major connector
 // - Generally forms a RIGHT ANGLE with the major connector
 // - Drawn as a thin (~2px) blue line from the rest/plate lingually
 // inward to where the major connector outline sits.
 // For each abutment, drop a short strut from the tooth's lingual edge
 // straight inward (radially negative) until it meets the major connector.
 const drawMinorConnectorStrut = (n, key) => {
 const { cx, cy } = positionOf(n);
 const halfBL = toothHalfBL(n);
 const R = toothRadius(n);
 const rad = radialUnit(n);
 // Start at the lingual edge of the tooth (where rest/plate meets the
 // tooth on the lingual side) and run radially inward to R + 28. That
 // lands INSIDE every major-connector variant we draw — lingual bar
 // (R+14→R+30), single palatal strap (R+22→R+36), U-shape (R+14→R+34),
 // AP strap (R+19→R+41), full palatal plate (R+24→inward) — without
 // poking out past any of them. The connector is drawn first; the strut
 // is drawn after, so the strut visibly bridges the tooth-to-connector
 // gap, then blends into the connector's fill once it crosses the inner
 // edge. Stroke thickened to 3.2 px for visibility against the bigger
 // chart sizes.
 const start = {
 x: cx - rad.x * halfBL,
 y: cy - rad.y * halfBL,
 };
 const end = {
 x: cx - rad.x * (R + 28),
 y: cy - rad.y * (R + 28),
 };
 return (
 <line key={key} x1={start.x} y1={start.y} x2={end.x} y2={end.y}
 stroke={C_CAST} strokeWidth={3.2} strokeLinecap="round" />
);
 };

 // Lingual bar (mandibular): drawn as a smooth OUTLINE pair of curves
 // following the lingual gingival border — matches paper-form
 // convention where the student draws the upper and lower edges of the
 // bar in blue ink.
 const drawLingualBar = (key) => {
 // paper-form convention: lingual bar drawn as a SOLID BLUE FILLED
 // crescent band sitting in the lingual sulcus, NOT touching the teeth.
 // Upper edge ~14 px lingual of the teeth; lower edge ~30 px further in.
 const upperEdge = archTeeth.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R + 14), y: cy - r.y * (R + 14) };
 });
 const lowerEdge = archTeeth.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R + 30), y: cy - r.y * (R + 30) };
 });
 const upperD = buildSmoothPath(upperEdge);
 const reverseLowerD = buildSmoothPath([...lowerEdge].reverse());
 const closedD = `${upperD} L ${lowerEdge[lowerEdge.length - 1].x} ${lowerEdge[lowerEdge.length - 1].y} ${reverseLowerD.replace(/^M [^ ]+ [^ ]+/, '')} Z`;
 return (
 <g key={key}>
 <path d={closedD} fill={C_CAST} fillOpacity={0.7}
 stroke={C_CAST} strokeWidth={1.6}
 strokeLinejoin="round" strokeLinecap="round" />
 </g>
);
 };

 // Sublingual bar (mandibular): alternative to standard Lingual Bar
 // when a high lingual frenum prevents normal placement. Sits in the
 // sublingual space (floor of mouth) — inferior to and slightly wider
 // than the Lingual Bar position. Drawn as a SOLID BLUE FILLED crescent
 // band sitting deeper in the floor of mouth than the standard Lingual
 // Bar would sit. Width is similar but the band is shifted inferiorly
 // by ~10 px and is slightly wider.
 const drawSublingualBar = (key) => {
 const upperEdge = archTeeth.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 // Upper edge sits ~24 px lingual (vs Lingual Bar's 14 px) —
 // visibly below the standard Lingual Bar position.
 return { x: cx - r.x * (R + 24), y: cy - r.y * (R + 24) };
 });
 const lowerEdge = archTeeth.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 // Lower edge ~44 px lingual — slightly wider band than Lingual
 // Bar (44-24 = 20 px, vs Lingual Bar's 30-14 = 16 px).
 return { x: cx - r.x * (R + 44), y: cy - r.y * (R + 44) };
 });
 const upperD = buildSmoothPath(upperEdge);
 const reverseLowerD = buildSmoothPath([...lowerEdge].reverse());
 const closedD = `${upperD} L ${lowerEdge[lowerEdge.length - 1].x} ${lowerEdge[lowerEdge.length - 1].y} ${reverseLowerD.replace(/^M [^ ]+ [^ ]+/, '')} Z`;
 return (
 <g key={key}>
 <path d={closedD} fill={C_CAST} fillOpacity={0.7}
 stroke={C_CAST} strokeWidth={1.6}
 strokeLinejoin="round" strokeLinecap="round" />
 </g>
);
 };

 // Lingual plate (mandibular): SOLID BLUE FILLED region covering the
 // lingual surfaces of mand anteriors up to the cingula AND extending
 // inferiorly into the lingual sulcus. Matches the paper-form colored-
 // pencil rendering — a contiguous solid-blue shape from one terminal
 // abutment's lingual surface across the anteriors to the opposite
 // terminal abutment.
 const drawLingualPlate = (key) => {
 // Plate spans from PM-to-PM (or wherever present teeth start/end in the
 // anterior-premolar region) — covers the lingual surfaces of all present
 // anteriors and premolars from one side to the other. Extended to also
 // include any abutments outside that range so the plate reaches the
 // terminal abutments instead of stopping short.
 const abutTeethSet = new Set((result.abutmentDesigns || []).map(a => a.tooth));
 const inDefaultPlateRange = (n) => n >= 20 && n <= 29;
 const plateRange = archTeeth.filter(n =>
 (inDefaultPlateRange(n) || abutTeethSet.has(n)) && isPresent(n));
 if (plateRange.length === 0) return drawLingualBar(key);
 // Top edge: rides along the cingula of each tooth (just past the
 // lingual surface, where the plate makes contact).
 const topEdge = plateRange.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * R * 0.55, y: cy - r.y * R * 0.55 };
 });
 // Bottom edge: ~30 px past the lingual surface of the SAME range of
 // teeth, so the plate has consistent width along its whole span and
 // doesn't fan out laterally into the molar sulcus.
 const bottomEdge = plateRange.map(n => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R + 30), y: cy - r.y * (R + 30) };
 });
 const topSmooth = buildSmoothPath(topEdge);
 const reverseBottomSmooth = buildSmoothPath([...bottomEdge].reverse());
 const pathD = `${topSmooth} L ${bottomEdge[bottomEdge.length - 1].x} ${bottomEdge[bottomEdge.length - 1].y} ${reverseBottomSmooth.replace(/^M [^ ]+ [^ ]+/, '')} Z`;
 return (
 <g key={key}>
 <path d={pathD} fill={C_CAST} fillOpacity={0.7}
 stroke={C_CAST} strokeWidth={1.6}
 strokeLinejoin="round" strokeLinecap="round" />
 </g>
);
 };

 // Palatal strap (maxillary): blue band crossing the palate.
 // Engine emits: "Full Palatal Plate", "A-P Strap", "U-Shaped Connector",
 // "Single Palatal Strap". Each gets a distinct visual.
 const drawPalatalConnector = (type, key) => {
 const t = (type || "").toLowerCase();
 // Match "a-p" (the engine's actual hyphenated form) plus the legacy
 // forms. Check AP BEFORE isComplete since "A-P Strap" doesn't contain
 // "plate" anyway — but defensive ordering avoids future regressions.
 const isAP = t.includes("a-p") || t.includes("ap strap") || t.includes("anterior-posterior") || t.includes("ap palatal");
 const isHorseshoe = t.includes("horseshoe") || t.includes("u-shaped");
 const isComplete =!isAP && (t.includes("complete") || t.includes("full palat") || t.includes("palatal plate"));
 // Reference points: where the band crosses the palate near each abutment
 const palatalAt = (n, depthMul = 1.0) => {
 const { cx, cy } = positionOf(n);
 const r = radialUnit(n);
 const R = toothRadius(n);
 return { x: cx - r.x * (R + 24 * depthMul), y: cy - r.y * (R + 24 * depthMul) };
 };
 // Strap helper: connect lingual points across teeth from #X to #Y with a thick band
 const strap = (toothRange, strokeWidth, opacityVal, depthMul = 1.0, fillIt = false) => {
 const pts = toothRange.map(n => palatalAt(n, depthMul));
 const pathD = pts.map((p, i) => i === 0? `M ${p.x} ${p.y}`: `L ${p.x} ${p.y}`).join(" ");
 return (
 <path d={pathD}
 stroke={C_CAST} strokeWidth={strokeWidth} fill={fillIt? C_CAST: "none"}
 fillOpacity={fillIt? 0.4: undefined}
 strokeLinecap="round" strokeLinejoin="round" opacity={opacityVal} />
);
 };
 // Helper: build a SOLID BLUE FILLED band between an upper edge curve
 // and a lower edge curve, closed at both ends — matches form's
 // colored-pencil rendering of palatal connectors.
 const filledBand = (upper, lower) => {
 const upperSmooth = buildSmoothPath(upper);
 const reverseLowerSmooth = buildSmoothPath([...lower].reverse());
 const closedD = `${upperSmooth} L ${lower[lower.length - 1].x} ${lower[lower.length - 1].y} ${reverseLowerSmooth.replace(/^M [^ ]+ [^ ]+/, '')} Z`;
 return (
 <path d={closedD} fill={C_CAST} fillOpacity={0.7}
 stroke={C_CAST} strokeWidth={1.6}
 strokeLinejoin="round" strokeLinecap="round" />
);
 };
 if (isComplete) {
 // Full / complete palatal plate: SOLID BLUE FILLED shape covering the
 // ENTIRE palate from the lingual surfaces of every tooth position
 // (whether present or missing) back to the junction of hard and soft
 // palates.
 //
 // Geometry: the lingual surfaces of all 16 tooth POSITIONS trace a ∩
 // (max) curve. The PALATE sits INSIDE that arch — between the lingual
 // U-shape and the back of the mouth. We close the lingual curve back
 // on itself ALONG the INSIDE of the arch, not the outside. For
 // maxillary, "inside" = HIGHER Y (toward chart bottom, where the
 // throat/soft palate would be in this view); for mandibular (which
 // doesn't actually use this rendering — mand gets a Lingual Plate —
 // but defensive), "inside" = LOWER Y.
 //
 // We use ALL tooth positions, not just present ones, so the plate
 // outline covers the whole palate even when most posteriors are
 // missing. The plate covers the missing-tooth area with a saddle
 // anyway — drawing the plate to the back of the arch matches the
 // clinical full-coverage extent and the textbook drawing.
 //
 // Previously this closed to `archCenterY * 0.55` (Y≈214 for max),
 // which is on the LABIAL side of the lingual curve, filling the area
 // OUTSIDE the arch (where the lips would be) — a giant rectangle
 // covering most of the chart.
 const linguals = archTeeth.map(n => palatalAt(n));
 if (linguals.length < 2) return null;
 const smoothLingualD = buildSmoothPath(linguals);
 // Back boundary: ~30 px past the most posterior tooth center, on the
 // palate side of the lingual curve. postY is the y-coordinate of the
 // most posterior teeth — see the geometry setup near line 15193.
 const backY = isMax? postY + 30: postY - 30;
 const closedD =
 `${smoothLingualD} ` +
 `L ${linguals[linguals.length - 1].x} ${backY} ` +
 `L ${linguals[0].x} ${backY} Z`;
 return (
 <g key={key}>
 <path d={closedD} fill={C_CAST} fillOpacity={0.7}
 stroke={C_CAST} strokeWidth={1.6}
 strokeLinejoin="round" strokeLinecap="round" />
 </g>
);
 }
 // Abutment teeth in the active arch. Strap paths must include these
 // so the major connector visually reaches the minor connector strut
 // from each abutment, even when abutments sit outside the standard
 // strap range (e.g. terminal molar at #2 with a single palatal
 // strap whose default range is #4–#13).
 const abutTeethSet = new Set((result.abutmentDesigns || []).map(a => a.tooth));
 const inActiveArch = (n) => isMax? (n >= 1 && n <= 16): (n >= 17 && n <= 32);
 const archAbutments = [...abutTeethSet].filter(inActiveArch);
 // Indirect retainer teeth ALSO have a minor connector strut drawn (see
 // line ~16423) — so the major connector must pass through THEIR lingual
 // anchor too, or there's a visible gap between the indirect retainer's
 // rest seat and the strap. Union with abutments to form the full set of
 // strap perimeter anchor points. Used only for strap path building;
 // abutTeethSet itself is unchanged so downstream "is this an abutment?"
 // checks still mean abutment-with-clasp (or rest-only), not just an IR.
 const indirectTeethSet = new Set((result.indirectRetainers || []).map(r => r.tooth));
 const strapAnchorSet = new Set([...abutTeethSet,...indirectTeethSet]);

 if (isAP) {
 // A-P (Anterior-Posterior) Strap: rectangular FRAME around the
 // central palate, anchored to the four corner abutments.
 //
 // Right-anterior corner: lingual of the most-anterior abutment
 // on the patient's right side.
 // Left-anterior corner: lingual of the most-anterior abutment
 // on the left side.
 // Right-posterior corner: lingual of the most-posterior abutment
 // on the right side.
 // Left-posterior corner: lingual of the most-posterior abutment
 // on the left side.
 //
 // Four edges connect the corners:
 // - Anterior band = R-ant ↔ L-ant
 // - Posterior band = R-post ↔ L-post
 // - Right lateral = R-ant ↔ R-post
 // - Left lateral = L-ant ↔ L-post
 //
 // Each edge is drawn as a thick filled polygon (rectangle) along
 // the line between its two corners. The frame creates the open
 // central window characteristic of the A-P strap — bands don't
 // cross or overlap. Matches McCracken Fig 5-16 and the hand-
 // drawn design forms.
 const isRight = (n) => isMax? (n >= 1 && n <= 8): (n >= 25 && n <= 32);
 const isLeft = (n) => isMax? (n >= 9 && n <= 16): (n >= 17 && n <= 24);
 // "More anterior" = closer to the midline (higher tooth number on
 // max-right, lower on max-left; lower on mand-right, higher on
 // mand-left). Use ordOf as a normalized position along the arch.
 const rightAbut = [...abutTeethSet].filter(isRight).sort((a, b) => ordOf(b) - ordOf(a));
 const leftAbut = [...abutTeethSet].filter(isLeft).sort((a, b) => ordOf(b) - ordOf(a));
 // ordOf increases monotonically from one end of the arch to the
 // other; sorting descending puts the most-anterior (highest ord
 // for one side, depends on traversal) first. For both sides, the
 // most-anterior is closer to the midline, the most-posterior is
 // at the back. Identify by ord distance from midline.
 const midOrd = (ordOf(isMax? 8: 25) + ordOf(isMax? 9: 24)) / 2;
 const rightAnt = rightAbut.length
? rightAbut.reduce((best, n) => Math.abs(ordOf(n) - midOrd) < Math.abs(ordOf(best) - midOrd)? n: best, rightAbut[0])
: null;
 const rightPost = rightAbut.length
? rightAbut.reduce((best, n) => Math.abs(ordOf(n) - midOrd) > Math.abs(ordOf(best) - midOrd)? n: best, rightAbut[0])
: null;
 const leftAnt = leftAbut.length
? leftAbut.reduce((best, n) => Math.abs(ordOf(n) - midOrd) < Math.abs(ordOf(best) - midOrd)? n: best, leftAbut[0])
: null;
 const leftPost = leftAbut.length
? leftAbut.reduce((best, n) => Math.abs(ordOf(n) - midOrd) > Math.abs(ordOf(best) - midOrd)? n: best, leftAbut[0])
: null;
 if (!rightAnt ||!leftAnt ||!rightPost ||!leftPost) {
 // Not enough abutments on each side to define the frame. Fall
 // back to a single curved band so we render SOMETHING.
 const all = archTeeth.filter(n => isPresent(n) || abutTeethSet.has(n));
 if (all.length < 2) return null;
 const upper = all.map(n => palatalAt(n, 1.0));
 const lower = all.map(n => palatalAt(n, 1.7));
 return <g key={key}>{filledBand(upper, lower)}</g>;
 }
 // Lingual anchor at each corner. Use depth 1.0 (24 px lingual of
 // the tooth surface) so the band sits just inside the lingual
 // surface where minor-connector struts terminate.
 const rA = palatalAt(rightAnt, 1.0);
 const lA = palatalAt(leftAnt, 1.0);
 const rP = palatalAt(rightPost, 1.0);
 const lP = palatalAt(leftPost, 1.0);
 // Render an edge as a thick filled rectangle between two points.
 // perp direction = 90° rotation of the line direction; thickness
 // applied perpendicular to the line.
 // Per the Design Case I photos (the actual cast
 // photos), the A-P strap covers ~70% of the palate area, with a
 // SMALL central window. Render as a filled path with evenodd
 // fill rule: outer polygon traces through every abutment (sharp
 // corners), minus inner polygon (smooth rounded window). The
 // filled area between them is the strap.
 //
 // OUTER PERIMETER: trace through every abutment's lingual point
 // along the arch. This guarantees every abutment's minor connector
 // strut visibly terminates INSIDE the strap fill, not in a gap
 // between the strap and the tooth.
 //
 // Path order:
 // right anteriors → right posteriors (along arch back)
 // → left posteriors (cross posterior palate)
 // → left anteriors (along arch front)
 // → close back to right anteriors
 //
 // Each abutment is a SHARP polygon vertex; no Q-curve rounding
 // at the outer perimeter. McCracken's hand-drawn A-P straps have
 // sharp angles at the abutment anchors anyway.
 //
 // When a side has only ONE abutment (typical Class I bilateral DE
 // with single terminal per side), synthesize a posterior corner by
 // projecting from the abutment toward the back of the palate. This
 // ensures the strap always has a proper 4+ vertex closed perimeter.
 // Include indirect retainers (strapAnchorSet) so the strap polygon
 // traces through their lingual point too — guarantees their minor
 // connector strut visibly terminates inside the strap fill.
 const rightAbutsByArch = [...strapAnchorSet].filter(isRight).sort((a, b) =>
 // Most anterior first (closer to midline = smaller |ord - midOrd|).
 Math.abs(ordOf(a) - midOrd) - Math.abs(ordOf(b) - midOrd));
 const leftAbutsByArch = [...strapAnchorSet].filter(isLeft).sort((a, b) =>
 Math.abs(ordOf(a) - midOrd) - Math.abs(ordOf(b) - midOrd));
 // Synthesize an extra posterior corner for any side with only one
 // abutment. The corner is positioned at the same arch position as
 // the abutment but pushed DEEPER toward the back of the palate by
 // a fixed offset, creating the posterior anchor of the A-P frame.
 const synthesizePosteriorCorner = (sideAbuts) => {
 if (sideAbuts.length >= 2) return null;
 if (sideAbuts.length === 0) return null;
 const anchor = sideAbuts[0];
 const a = palatalAt(anchor, 1.0);
 // Push toward postY (the y-coord at the back of the palate)
 const offsetX = (a.x - midlineX) * 0.20; // slight lateral shift away from midline
 const dy = (postY - a.y) * 0.55; // 55% of distance toward posterior palate
 return { x: a.x + offsetX, y: a.y + dy };
 };
 const rightSyntheticPost = synthesizePosteriorCorner(rightAbutsByArch);
 const leftSyntheticPost = synthesizePosteriorCorner(leftAbutsByArch);
 // right side, anterior → posterior
 const rightOuterPts = [
...rightAbutsByArch.map(n => palatalAt(n, 1.0)),
...(rightSyntheticPost? [rightSyntheticPost]: []),
 ];
 // left side, posterior → anterior (reverse so we trace the perimeter)
 const leftOuterPts = [
...(leftSyntheticPost? [leftSyntheticPost]: []),
...[...leftAbutsByArch].reverse().map(n => palatalAt(n, 1.0)),
 ];
 const outerPts = [...rightOuterPts,...leftOuterPts];
 // INNER PERIMETER (window): derive from outer perimeter so it always
 // has the same vertex count and never degenerates. Inner point i =
 // outer point i scaled toward the centroid by innerFrac.
 // McCracken's hand-drawn straps have a smooth rounded inner window,
 // so we keep the Q-curve rounding for inner corners.
 const cornerEaseInner = 0.18;
 const centroidOuter = {
 x: outerPts.reduce((s, p) => s + p.x, 0) / outerPts.length,
 y: outerPts.reduce((s, p) => s + p.y, 0) / outerPts.length,
 };
 const innerScale = 0.50;
 const innerPts = outerPts.map(p => ({
 x: p.x + (centroidOuter.x - p.x) * innerScale,
 y: p.y + (centroidOuter.y - p.y) * innerScale,
 }));
 const sharpRectPath = (pts) => {
 // Straight-line polygon, sharp corners
 if (pts.length === 0) return "";
 let path = `M ${pts[0].x} ${pts[0].y}`;
 for (let i = 1; i < pts.length; i++) {
 path += ` L ${pts[i].x} ${pts[i].y}`;
 }
 return path + " Z";
 };
 const roundedRectPath = (pts, ease) => {
 const trims = pts.map((c, i) => {
 const prev = pts[(i + pts.length - 1) % pts.length];
 const next = pts[(i + 1) % pts.length];
 return {
 fromPrev: { x: c.x + (prev.x - c.x) * ease, y: c.y + (prev.y - c.y) * ease },
 toNext: { x: c.x + (next.x - c.x) * ease, y: c.y + (next.y - c.y) * ease },
 };
 });
 let path = `M ${trims[0].fromPrev.x} ${trims[0].fromPrev.y}`;
 for (let i = 0; i < pts.length; i++) {
 const cur = trims[i];
 const nextIdx = (i + 1) % pts.length;
 const nextCorner = pts[nextIdx];
 const nextTrim = trims[nextIdx];
 path += ` L ${cur.toNext.x} ${cur.toNext.y}` +
 ` Q ${nextCorner.x} ${nextCorner.y} ${nextTrim.fromPrev.x} ${nextTrim.fromPrev.y}`;
 }
 return path + " Z";
 };
 const d = sharpRectPath(outerPts) +
 " " +
 roundedRectPath(innerPts, cornerEaseInner);
 return (
 <g key={key}>
 <path d={d} fillRule="evenodd"
 fill={C_CAST} fillOpacity={0.75}
 stroke={C_CAST} strokeWidth={1.4} strokeLinejoin="round" />
 </g>
);
 }
 if (isHorseshoe) {
 // Horseshoe: solid U-shape following lingual surfaces of every
 // present tooth, with depth into the palate.
 const present = archTeeth.filter(n => isPresent(n));
 const upper = present.map(n => palatalAt(n, 0.6));
 const lower = present.map(n => palatalAt(n, 1.4));
 return (
 <g key={key}>
 {filledBand(upper, lower)}
 </g>
);
 }
 // Default: single palatal strap.
 //
 // Render as a THICK STROKED PATH passing through every abutment's
 // lingual anchor (palatalAt depth 1.0). Each abutment's anchor is
 // a point ON the strap centerline; with thickness 22 px the strap
 // extends ±11 px perpendicularly, comfortably enclosing the minor
 // connector strut endpoints (which sit at depth ~1.17 from tooth
 // center, ~4 px deeper than the strap centerline). This guarantees
 // every minor connector strut visibly TERMINATES INSIDE the strap.
 //
 // Multiple iterations of this code tried to compute a fixed Y for
 // the strap and then place it horizontally — each failed in some
 // direction (avgY-across-all-teeth pulled forward by anteriors;
 // abutment-only avgY left the strut endpoints sitting on the
 // wrong side of the band; per-Y palatal walls produced bands that
 // didn't reach abutments at other Ys). The pass-through approach
 // makes the connectivity property structural — by construction
 // the strap passes through every abutment anchor, so the struts
 // always meet the strap.
 // Include indirect retainer teeth as anchors so the strap centerline
 // passes through their lingual point too — guarantees their minor
 // connector strut meets the strap (otherwise the strap interpolates
 // between abutments only, leaving an IR-only tooth's strut hanging).
 const abutAnchors = [...strapAnchorSet]
.filter(n => inActiveArch(n))
.map(n => palatalAt(n, 1.0))
.sort((a, b) => a.x - b.x);
 if (abutAnchors.length < 1) {
 // No abutments yet — fall back to the curve-following render.
 const inDefaultRange = (n) => isMax? (n >= 4 && n <= 13): (n >= 20 && n <= 29);
 const midTeeth = archTeeth.filter(n => inDefaultRange(n) || abutTeethSet.has(n));
 const upper = midTeeth.map(n => palatalAt(n, 0.9));
 const lower = midTeeth.map(n => palatalAt(n, 1.5));
 return <g key={key}>{filledBand(upper, lower)}</g>;
 }
 if (abutAnchors.length === 1) {
 // Single abutment — just draw a small dot at its anchor so there's
 // something visible.
 const p = abutAnchors[0];
 return <g key={key}><circle cx={p.x} cy={p.y} r={11}
 fill={C_CAST} fillOpacity={0.75} stroke={C_CAST} strokeWidth={1.4} /></g>;
 }
 // Build a smooth path passing through every abutment anchor.
 // buildPassThroughPath (Catmull-Rom helper) handles 2+ points.
 const centerlineD = buildPassThroughPath(abutAnchors);
 return (
 <g key={key}>
 <path d={centerlineD}
 stroke={C_CAST} strokeWidth={22}
 strokeLinecap="round" strokeLinejoin="round"
 fill="none" opacity={0.75} />
 </g>
);
 };

 // ── Assemble layers (back to front) ──
 const abutments = result.abutmentDesigns || [];
 const baseDesigns = result.baseDesigns || [];
 const indirects = result.indirectRetainers || [];
 // hasDesign — only render the framework overlay (major connector, saddles,
 // clasps, etc.) when there's an actual case. When no teeth are missing,
 // result.kennedy.class is null and we should show just the empty arch so
 // the user can mark teeth missing — no phantom lingual bar / palatal strap.
 const hasDesign = result.kennedy.class!== null;

 // ── Single-tooth case — recommended treatment is fixed, not removable ──
 // When only one tooth is missing in a definitive plan, the textbook first
 // choice is an implant-supported crown (Class II — no distal abutment
 // available for a bridge) or an implant / FPD (Class III — bounded on
 // both sides). We render the fixed replacement instead of the RPD
 // framework so the chart shows the model's actual recommendation rather
 // than an "outrageous RPD" for a tooth that shouldn't get one.
 const designIntentLocal = caseInput.patientFactors?.designIntent || "definitive";
 // Wisdoms are excluded from the "missing teeth that need replacement"
 // count — they're typically omitted (Applegate Rule 2) and clinically
 // you don't replace a missing wisdom. So a case with only #15 + #16
 // (wisdom) missing reads as a SINGLE-tooth replacement scenario for
 // #15, not as a two-tooth RPD case. See the matching exclusion in
 // singleToothMissing below the RPDHelper definition.
 const missingArchTeeth = archTeeth.filter(n =>
 caseInput.teeth?.[n]?.status === "missing" &&!RPD_THIRD_MOLARS.has(n));
 const isSingleToothCase = missingArchTeeth.length === 1
 && (result.kennedy.class === "II" || result.kennedy.class === "III")
 && designIntentLocal === "definitive";
 const singleToothId = isSingleToothCase? missingArchTeeth[0]: null;
 // Engine signals "fixed treatment recommended" via majorConnector.recommendsFixed
 // for cases where an RPD is overtreatment — currently a short unilateral
 // Class III (≤3 missing teeth bounded by abutments on one side). For these
 // cases we render the multi-unit FPD overlay instead of the RPD framework,
 // matching the single-tooth FPD treatment but spanning multiple pontics.
 const engineRecommendsFixed =!!result.majorConnector?.recommendsFixed;
 const isFixedTreatmentCase = (isSingleToothCase || engineRecommendsFixed)
 && designIntentLocal === "definitive";
 // The list of teeth that need replacement — for a single-tooth case this is
 // the one missing tooth; for a multi-tooth FPD case this is all the missing
 // teeth in the affected span(s).
 const fixedTreatmentTeeth = isFixedTreatmentCase? missingArchTeeth: [];
 // Bridge only when the tooth being replaced has present abutments on
 // BOTH sides (Kennedy Class III = tooth-bounded space). For Class II
 // — terminal tooth missing, no distal abutment — a bridge would be
 // a cantilever (clinically contraindicated in the posterior). Engine
 // implies implant instead in that case. For multi-tooth FPD cases the
 // engine signals FPD via recommendsFixed; for single-tooth cases we
 // derive from Kennedy class.
 // For an engine-flagged fixed case, render the bridge only for short spans
 // (≤2 pontics). A 3-pontic span is where implants become the better choice
 // (matches the engine rationale), so render implants there, not an FPD.
 const isFPD = (isSingleToothCase && result.kennedy.class === "III")
 || (engineRecommendsFixed && missingArchTeeth.length <= 2);

 // FPD bridge or implant crown — rendered IN PLACE OF the RPD framework
 // when isFixedTreatmentCase. Pontics (FPD) or crowns (implant) sit at each
 // missing-tooth position; FPD tints the BOUNDING abutment teeth to indicate
 // they get full-coverage crowns. Handles both:
 // - Single-tooth case (1 pontic, 2 abutment crowns for Class III)
 // - Multi-tooth FPD case (engine recommends fixed — 2-3 pontics for a
 // short unilateral tooth-bounded span)
 const drawFixedReplacement = () => {
 if (!isFixedTreatmentCase) return null;
 const teeth = fixedTreatmentTeeth;
 if (teeth.length === 0) return null;

 const isMolar = (an) => RPD_FIRST_MOLARS.has(an) || RPD_SECOND_MOLARS.has(an) || RPD_THIRD_MOLARS.has(an);
 const isPM = (an) => [4,5,12,13,20,21,28,29].includes(an);
 const isCanine = (an) => RPD_CANINES.has(an);
 const cuspBulgeFor = (an) => isMolar(an)? 0.18: isPM(an)? 0.11: isCanine(an)? 0.07: 0;

 // Build a tooth path for any tooth index — used for both pontics and
 // abutment-crown overlays.
 const pathFor = (n) => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 const rad = radialUnit(n);
 const mes = mesialUnit(n);
 const cornerR = Math.min(halfMD, halfBL) * 0.28;
 return toothPath(cx, cy, halfMD, halfBL, rad, mes, cornerR, cuspBulgeFor(n));
 };

 // Identify the abutment teeth — the present teeth that bound the
 // missing run(s). For a single-tooth Class III those are the two
 // immediate neighbors. For a multi-tooth FPD span those are the
 // closest present teeth on each side of the contiguous missing run.
 const sortedTeeth = [...teeth].sort((a, b) => archTeeth.indexOf(a) - archTeeth.indexOf(b));
 const firstIdx = archTeeth.indexOf(sortedTeeth[0]);
 const lastIdx = archTeeth.indexOf(sortedTeeth[sortedTeeth.length - 1]);
 const mesialAbutment = (() => {
 for (let i = firstIdx - 1; i >= 0; i--) {
 const t = archTeeth[i];
 if (isPresent(t)) return t;
 }
 return null;
 })();
 const distalAbutment = (() => {
 for (let i = lastIdx + 1; i < archTeeth.length; i++) {
 const t = archTeeth[i];
 if (isPresent(t)) return t;
 }
 return null;
 })();
 const abutments = isFPD? [mesialAbutment, distalAbutment].filter(Boolean): [];

 // Label position — centered on the missing run, lingual to avoid the
 // tooth-number label on the buccal side.
 const labelTooth = sortedTeeth[Math.floor(sortedTeeth.length / 2)];
 const { cx: lcx, cy: lcy } = positionOf(labelTooth);
 const lrad = radialUnit(labelTooth);
 const lhalfBL = toothHalfBL(labelTooth);
 const labelOffset = lhalfBL + 28;
 const labelX = lcx - lrad.x * labelOffset;
 const labelY = lcy - lrad.y * labelOffset + 5;
 // For multi-pontic FPDs we also label the bridge units, e.g. "4-unit FPD".
 const labelText = isFPD
? (teeth.length > 1? `${teeth.length + 2}-unit FPD`: "FPD")
: (teeth.length > 1? "Implants": "Implant");

 // pointerEvents="none" on every overlay element so clicks pass THROUGH
 // the FPD/implant rendering to the tooth <g>'s click handler underneath.
 return (
 <g key="fixed-replacement" pointerEvents="none">
 {/* FPD only — tint abutment teeth to show full-coverage crowns */}
 {abutments.map(an => (
 <path key={`crown-${an}`} d={pathFor(an)}
 fill={C_FIXED} fillOpacity={0.22}
 stroke={C_FIXED} strokeWidth={2.4} strokeLinejoin="round"
 pointerEvents="none" />
))}
 {/* Pontic(s) (FPD) or implant crown(s) — solid teal tooth shapes */}
 {sortedTeeth.map(n => {
 const { cx, cy } = positionOf(n);
 const halfMD = toothHalfMD(n);
 const halfBL = toothHalfBL(n);
 return (
 <g key={`pontic-${n}`} pointerEvents="none">
 <path d={pathFor(n)}
 fill={C_FIXED} fillOpacity={0.7}
 stroke={C_FIXED} strokeWidth={2.6} strokeLinejoin="round"
 pointerEvents="none" />
 {/* Implant fixture marker — small bullseye on each crown
 to distinguish implant cases from FPD pontics. */}
 {!isFPD && (
 <g pointerEvents="none">
 <circle cx={cx} cy={cy} r={Math.min(halfMD, halfBL) * 0.32}
 fill="none" stroke="white" strokeWidth={2.4}
 pointerEvents="none" />
 <circle cx={cx} cy={cy} r={Math.min(halfMD, halfBL) * 0.14}
 fill="white" pointerEvents="none" />
 </g>
)}
 </g>
);
 })}
 {/* Treatment label — lingual side, in teal, distinct from RPD blue */}
 <text x={labelX} y={labelY} fontSize="18"
 fontFamily="'Geist', sans-serif" fontWeight="700"
 fill={C_FIXED} textAnchor="middle"
 letterSpacing="0.08em" style={{ textTransform: "uppercase" }}
 pointerEvents="none">
 {labelText}
 </text>
 </g>
);
 };

 return (
 <div style={{ position: "relative" }}>
 <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", display: "block", background: "#FDFCF7", userSelect: "none", WebkitUserSelect: "none" }}>
 {/* Midline guide */}
 <line x1={midlineX} y1={12} x2={midlineX} y2={H - 12}
 stroke={C_MISSING} strokeDasharray="4,5" strokeWidth={0.6} />

 {/* RPD framework overlay — suppressed for single-tooth cases where
 the recommended treatment is an FPD or implant, not an RPD. */}
 {!isFixedTreatmentCase && (
 <>
 {/* 1. Major connector (background) — only when there's a case */}
 {hasDesign && selectable(
 isMax
? drawPalatalConnector(result.majorConnector?.type, "mc")
: (result.majorConnector?.type || "").toLowerCase().includes("sublingual")
? drawSublingualBar("mc")
: (result.majorConnector?.type || "").toLowerCase().includes("plate")
? drawLingualPlate("mc")
: drawLingualBar("mc"),
 'connector', { tooltip: `Major connector — ${result.majorConnector?.type || "unspecified"}` },
 "mc-w"
)}

 {/* 2. Saddles / denture bases (between abutments) */}
 {baseDesigns.map((b, i) => selectable(
 drawSaddleSpan(b.spanTeeth, b.type, `saddle-${i}`),
 'base', { spanIndex: i, tooltip: `Denture base / saddle — ${b.type}` },
 `saddle-w-${i}`
))}

 {/* (Tissue stops moved later in the render order so their hit
 pads sit on top of the teeth's invisible 64-px hit circles
 — otherwise clicks land on the adjacent tooth instead of
 the stop.) */}
 </>
)}

 {/* 3. Schematic teeth — always rendered, both case types need them */}
 {archTeeth.map(n => renderTooth(n))}

 {/* Fixed replacement overlay — only when isSingleToothCase. Drawn
 after teeth so it sits on top of the missing-tooth outline. */}
 {drawFixedReplacement()}

 {!isFixedTreatmentCase && (
 <>
 {/* 4. Survey lines / HOC ovals on abutments — positioned at
 the engine's EFFECTIVE undercut (DB / MB for Akers) rather
 than the user's raw attrs default, so the marker sits where
 the clasp actually engages. The survey line is a closed loop
 around the entire tooth (it exists on every axial surface),
 but the marker convention draws an oval only at the
 RETENTIVE-clasp engagement point. */}
 {abutments.map((a, i) => selectable(
 drawSurveyLine(a.tooth, `sl-${i}`, a.effectiveUndercutLocation),
 'surveyLine', { tooth: a.tooth, tooltip: `Survey line / HOC on ${rpdToothName(a.tooth)} (retentive side — clasp crosses HOC to engage undercut below)` },
 `sl-w-${i}`
))}
 {/* 4b. Lingual survey-line marker on abutments that carry a
 RECIPROCAL ARM (not plate). The reciprocal arm sits ABOVE
 the lingual HOC in the suprabulge zone — it doesn't engage
 an undercut, but the HOC is what defines where the arm can
 sit. Drawn at "mid-lingual" so it's visually opposite the
 buccal undercut marker. Reciprocal PLATES cover the cingulum
 region entirely, so no marker is needed there — the plate
 IS the visual indicator. */}
 {abutments.map((a, i) => (a.reciprocation && a.reciprocation.type === "arm")
 ? selectable(
 drawSurveyLine(a.tooth, `sl-recip-${i}`, "mid-lingual"),
 'surveyLine', { tooth: a.tooth, tooltip: `Lingual HOC marker on ${rpdToothName(a.tooth)} — reciprocal arm sits above this line in the suprabulge zone` },
 `sl-recip-w-${i}`
 )
 : null
 ).filter(Boolean)}

 {/* 5a. Minor connector struts */}
 {abutments.map((a, i) => selectable(
 drawMinorConnectorStrut(a.tooth, `mc-${i}`),
 'minorConnector', { tooth: a.tooth, tooltip: `Minor connector — links rest assembly on ${rpdToothName(a.tooth)} to major connector` },
 `mc-w-${i}`
))}
 {(result.indirectRetainers || []).map((r, i) => selectable(
 drawMinorConnectorStrut(r.tooth, `mc-ir-${i}`),
 'minorConnector', { tooth: r.tooth, tooltip: `Minor connector — links indirect retainer on ${rpdToothName(r.tooth)} to major connector` },
 `mc-ir-w-${i}`
))}

 {/* 5b. Guide planes / proximal plates */}
 {abutments.flatMap((a, i) => a.guidePlane
? [selectable(
 drawGuidePlane(a.tooth, a.guidePlane.surface, `gp-${i}`),
 'guidePlane', { tooth: a.tooth, tooltip: `Guide plane / proximal plate on ${rpdToothName(a.tooth)} — ${a.guidePlane.surface} surface` },
 `gp-w-${i}`
)]
: [])}

 {/* 6. Rest seats */}
 {abutments.flatMap((a, i) => {
 if (!a.restSeat) return [];
 const tip = `Rest seat on ${rpdToothName(a.tooth)} — ${a.restSeat.surface} ${a.restSeat.type}`;
 let el;
 if (a.restSeat.type === "occlusal") el = drawOcclusalRest(a.tooth, a.restSeat.surface, `rs-${i}`);
 else if (a.restSeat.type === "cingulum") el = drawCingulumRest(a.tooth, `rs-${i}`);
 else if (a.restSeat.type === "ball") el = drawBallRest(a.tooth, `rs-${i}`);
 else el = drawOcclusalRest(a.tooth, a.restSeat.surface || "mesial", `rs-${i}`);
 return [selectable(el, 'rest', { tooth: a.tooth, tooltip: tip }, `rs-w-${i}`)];
 })}

 {/* 7. Reciprocation */}
 {abutments.flatMap((a, i) => {
 if (!a.reciprocation) return [];
 const plateSide = a.guidePlane?.surface || (a.restSeat?.surface === "mesial"? "distal": "mesial");
 let el;
 if (a.reciprocation.type === "plate") {
 el = drawReciprocalPlate(a.tooth, `recip-${i}`);
 } else if (a.reciprocation.type === "arm") {
 el = drawReciprocalArm(a.tooth, plateSide, `recip-${i}`);
 } else {
 return [];
 }
 return [selectable(el, 'reciprocal', { tooth: a.tooth, tooltip: `Reciprocal arm on ${rpdToothName(a.tooth)}` }, `recip-w-${i}`)];
 })}

 {/* 8. Retentive arms / I-bars */}
 {abutments.flatMap((a, i) => {
 const ct = a.claspType || "";
 const attrs = teethState[a.tooth]?.attrs || {};
 // Prefer engine-computed effective undercut (e.g. Akers DB
 // default) over raw user attrs default.
 const ucLoc = a.effectiveUndercutLocation || attrs.undercutLocation || "mid-buccal";
 const plateSide = a.guidePlane?.surface || (a.restSeat?.surface === "mesial"? "distal": "mesial");
 if (ct.includes("Rest Only")) return [];
 let el;
 if (ct === "RPI" || ct === "I-bar (esthetic)") {
 el = drawIBar(a.tooth, ucLoc, plateSide, `clasp-${i}`, "I");
 } else if (ct === "T-bar") {
 el = drawIBar(a.tooth, ucLoc, plateSide, `clasp-${i}`, "T");
 } else if (ct === "Y-bar") {
 el = drawIBar(a.tooth, ucLoc, plateSide, `clasp-${i}`, "Y");
 } else if (ct === "Ring" || ct === "Ring Clasp") {
 el = drawRingClasp(a.tooth, { plateSide, ucLoc }, `clasp-${i}`);
 } else if (ct === "Embrasure") {
 const onBuccal =!(ucLoc === "disto-lingual" || ucLoc === "mesio-lingual");
 el = drawEmbrasureClasp(a.tooth, { plateSide, onBuccal }, `clasp-${i}`);
 } else if (ct === "Combination" || ct === "WW C-clasp" || ct === "Ball Clasp") {
 el = drawCircumferentialArm(a.tooth, { color: C_WW, plateSide, onBuccal: true }, `clasp-${i}`);
 } else if (ct === "Reverse Akers") {
 const onBuccal =!(ucLoc === "disto-lingual" || ucLoc === "mesio-lingual");
 el = drawCircumferentialArm(a.tooth, { color: C_CAST, plateSide, onBuccal }, `clasp-${i}`);
 } else {
 el = drawCircumferentialArm(a.tooth, { color: C_CAST, plateSide, onBuccal: true }, `clasp-${i}`);
 }
 return [selectable(el, 'clasp', { tooth: a.tooth, tooltip: `${ct} on ${rpdToothName(a.tooth)} — engages ${ucLoc} undercut` }, `clasp-w-${i}`)];
 })}

 {/* 9. Indirect retainers — pick the right rest glyph by restType:
 - ball rest (max centrals #8/#9 with distal ball; mand
 canine with ML ball; Class IV bounding canines) → use
 drawBallRest (small filled circle on incisal/lingual)
 - cingulum rest (max canines/laterals or anteriors) →
 V-shaped cingulum glyph via drawCingulumRest
 - occlusal rest (premolars) → spoon-shaped occlusal glyph
 via drawOcclusalRest on the appropriate surface */}
 {indirects.flatMap((r, i) => {
 const restTypeLc = (r.restType || "").toLowerCase();
 const isBall = restTypeLc.includes("ball");
 const isCing = restTypeLc.includes("cingulum")
 || (!isBall && (RPD_CANINES.has(r.tooth)
 || (r.tooth >= 7 && r.tooth <= 10) || (r.tooth >= 23 && r.tooth <= 26)));
 const isOccl = restTypeLc.includes("occlusal") || restTypeLc.includes("mesial");
 let el;
 if (isBall) {
 el = drawBallRest(r.tooth, `ir-${i}`);
 } else if (isCing) {
 el = drawCingulumRest(r.tooth, `ir-${i}`);
 } else if (isOccl || RPD_FIRST_PREMOLARS.has(r.tooth) || RPD_SECOND_PREMOLARS.has(r.tooth)) {
 // Default surface for indirect occlusal rest: mesial (toward
 // fulcrum line). Engine doesn't carry the surface on indirect
 // retainer objects; the standard is mesial on premolars.
 el = drawOcclusalRest(r.tooth, "mesial", `ir-${i}`);
 } else {
 el = drawCingulumRest(r.tooth, `ir-${i}`);
 }
 return [selectable(el, 'indirect', { tooth: r.tooth, tooltip: `Indirect retainer on ${rpdToothName(r.tooth)} — ${r.restType || "rest"}` }, `ir-w-${i}`)];
 })}

 {/* 10. Per-abutment annotations */}
 {abutments.map((a, i) => drawAbutmentAnnotation(a, `ann-${i}`))}

 {/* 11. Tissue stops — rendered LAST so their 28-px hit pads
 sit on top of every other element (teeth hit circles, in
 particular). Visually they're small red ovals near the
 distal end of the distal-extension saddle. */}
 {baseDesigns.map((b, i) => {
 const hasTissueStop = (b.note || "").toLowerCase().includes("tissue stop")
 || b.distalExtension === true;
 if (!hasTissueStop) return null;
 return selectable(
 drawTissueStop(b.spanTeeth, `ts-${i}`),
 'tissueStop', { spanIndex: i, tooltip: `Tissue stop — stabilizes framework during acrylic processing of distal extension` },
 `ts-w-${i}`
);
 })}
 </>
)}

 {/* Arch label was redundant with the Mx/Mn toggle above the chart;
 removed. */}
 {/* "*or implant" footnote — only when FPD is shown (Class III single
 tooth, where implant is a valid alternative). For Class II we
 already show "Implant" as the only option, so no footnote needed.
 Bottom-left of SVG, in the verdict italic-Fraunces accent style. */}
 {isFixedTreatmentCase && isFPD && (
 <text x={28} y={isMax? 38: H - 22} fontSize="28"
 fontFamily="'Fraunces', serif" fontStyle="italic"
 fill="var(--accent)" textAnchor="start">
 *or implant{fixedTreatmentTeeth.length > 1? "s": ""}
 </text>
)}
 </svg>
 </div>
);
}

// ─── Preliminary Partial Denture Design Form ──────────────────────────
// Recreates the Preliminary [Maxillary/Mandibular] Partial Denture
// Design form layout, pre-filled from the engine output. Designed to be
// printable / screenshot-able so it can be copied directly to the paper
// form.
function RPDPreliminaryDesignForm({ caseInput, result, compact = false, verbose = false }) {
 const [drawingOpen, setDrawingOpen] = useState(false);
 // Rationale verbosity is controlled by the parent's `verbose` prop so a
 // single toggle drives both the Preliminary Design Form rationale column
 // AND the Lab Rx spec callouts. Default OFF = compressed (form-style,
 // 1-line per decision, deduped per clasp type, 1:1 with sample forms).
 // ON = expands to full educational paragraph with page refs.
 const showFullRationale = verbose;
 if (!result || result.kennedy.class === null) return null;
 const arch = caseInput.arch === "maxillary"? "MAXILLARY": "MANDIBULAR";
 const pf = caseInput.patientFactors || {};

 // ─── Direct retainers table data ──
 const directRetainers = (result.abutmentDesigns || []).map(a => {
 const attrs = a.attrs || {};
 // Cingulum rests don't have a mesial/distal axis — they sit on
 // the lingual cingulum, period. Don't prefix with M/D for those.
 // Occlusal rests are correctly surface-oriented (MO, DO).
 const restCell = a.restSeat
? (a.restSeat.type === "cingulum"
? "Cingulum"
: `${a.restSeat.surface?.[0]?.toUpperCase() || ""}O`)
: "—";
 // Examples: "MO", "DO" (mesio-occlusal, disto-occlusal); "Cingulum" for cingulum rests.
 const retention = a.claspType?.includes("Rest Only")
? "—"
: `${attrs.undercutDepth || "0.01\""} ${(() => {
 const u = attrs.undercutLocation || "mid-buccal";
 return u === "mesio-buccal"? "MB": u === "disto-buccal"? "DB"
: u === "mesio-lingual"? "ML": u === "disto-lingual"? "DL": "mid-B";
 })()}`;
 const bracing = a.reciprocation
? (a.reciprocation.type === "plate"? `${caseInput.arch === "maxillary"? "Palatal": "Lingual"} plate`
: a.reciprocation.type === "arm"? `${caseInput.arch === "maxillary"? "Palatal": "Lingual"} arm`
: a.reciprocation.text || "—")
: "—";
 return {
 tooth: a.tooth,
 clasp: a.claspType,
 rest: restCell,
 retention,
 bracing,
 };
 });

 // ─── Indirect retainers ──
 const indirectList = (result.indirectRetainers || [])
.map(r => `#${r.tooth} ${r.restType || "rest"}`)
.join(", ");

 // ─── Facings / metal pontics / tube teeth ──
 const facingsList = (result.baseDesigns || [])
.filter(b => b.type === "Tube Tooth" || b.type === "Facing")
.flatMap(b => (b.spanTeeth || []).map(t => `#${t} ${b.type}`))
.join(", ");

 // ─── Retention webbing ──
 const webbingList = (result.baseDesigns || [])
.filter(b => b.type === "Open Lattice" || b.type === "Mesh")
.map(b => {
 const teeth = (b.spanTeeth || []).map(t => `#${t}`).join(", ");
 const tStop = b.note && /distal tissue stop/i.test(b.note)? " with distal tissue stop": "";
 return `${teeth} ${b.type}${tStop}`;
 })
.join("; ");

 // ─── Abutment preparations (single consolidated field per the UIC
 // paper form). The paper form has ONE box labelled
 // "Abutment preparations, guide planes, recontouring, restorations:"
 // — so guide planes, undercut modifications (composite / survey
 // crown / enameloplasty), HOC adjustments, axial recontouring, and
 // esthetic-driven exceptions all collapse into one line per abutment.
 const HOC_ADJUST_LABELS = {
 "lower-DB": "lower DB HOC",
 "lower-MB": "lower MB HOC",
 "lower-DL": "lower DL HOC",
 "lower-ML": "lower ML HOC",
 "general": "general axial re-contour",
 };
 const MODIFICATION_LABELS = {
 "enameloplasty": "enameloplasty",
 "composite": "composite addition",
 "survey-crown": "survey crown",
 };
 const ESTHETIC_LABELS = {
 "no-buccal-clasp": "no buccal clasp (esthetic)",
 "no-visible-metal": "no visible metal (esthetic)",
 };
 const abutmentPrepLines = (result.abutmentDesigns || [])
.map(a => {
 const parts = [];
 if (a.guidePlane) parts.push(`${a.guidePlane.surface[0].toUpperCase()} guide plane`);
 const attrs = a.attrs || {};
 if (a.surveyCrown?.indicated) {
 parts.push("survey crown");
 } else if (attrs.modification && attrs.modification !== "auto" && attrs.modification !== "none" && MODIFICATION_LABELS[attrs.modification]) {
 parts.push(MODIFICATION_LABELS[attrs.modification]);
 }
 if (a.crownLengthening?.indicated) parts.push("crown lengthening");
 if (attrs.hocAdjustment && attrs.hocAdjustment !== "none" && HOC_ADJUST_LABELS[attrs.hocAdjustment]) {
 parts.push(HOC_ADJUST_LABELS[attrs.hocAdjustment]);
 }
 if (attrs.recontour) parts.push(`axial recontouring (${attrs.recontour})`);
 if (attrs.esthetic && attrs.esthetic !== "none" && ESTHETIC_LABELS[attrs.esthetic]) {
 parts.push(ESTHETIC_LABELS[attrs.esthetic]);
 }
 return parts.length? `#${a.tooth} ${parts.join(", ")}`: null;
 })
.filter(Boolean)
.join("; ");

 // ─── Rationale lines ──
 // Two modes:
 // VERBOSE (showFullRationale=true): paragraph-length, page-referenced,
 // one block per tooth/component (current behavior, kept for study use).
 // COMPRESSED (default): first sentence only, page references stripped,
 // per-tooth lines grouped by clasp type so #2 + #4 (both Akers)
 // appear once as "#2, #4 (Akers):..." instead of twice.
 //
 // Helpers:
 const firstSentence = (s) => {
 if (!s) return "";
 // Split on the first period followed by a space (or end of string).
 // Avoids splitting on decimal numbers like "0.01" because there's no
 // following space.
 const m = String(s).match(/^[^.]+\./);
 return (m? m[0]: String(s)).trim();
 };
 const stripPageRefs = (s) => {
 if (!s) return "";
 return String(s)
 // Inline parenthetical page refs: "(Retainers PDF p. 14)", "(p. 12)",
 // "(Lecture 4A pp. 7-14)", "(Design Case II p. 8)",
 // "(default per Final Impressions p. 18)" — drop them.
.replace(/\s*\([^)]*\bp{1,2}\.\s*\d[^)]*\)/g, "")
 // Collapse repeated whitespace + trim.
.replace(/\s+/g, " ")
.trim();
 };
 // Verbose mode: full prose, page refs stripped (they break flow visually
 // and the engine's source-of-truth is the docs file, not these chips).
 const cleanVerbose = (s) => stripPageRefs(s);
 const compress = (s) => stripPageRefs(firstSentence(s));

 const rationaleLines = [];

 // Framework + major connector (always one line each; cheap to compress)
 rationaleLines.push({
 key: "framework",
 verbose: `Framework: ${result.framework.material} — ${cleanVerbose(result.framework.rationale)}`,
 compressed: `Framework: ${result.framework.material} — ${compress(result.framework.rationale)}`,
 });
 rationaleLines.push({
 key: "major",
 verbose: `Major connector: ${cleanVerbose(result.majorConnector.rationale)}`,
 compressed: `Major connector: ${compress(result.majorConnector.rationale)}`,
 });

 if (abutmentPrepLines) {
 const guideLine = "Guide planes establish path of insertion; axial recontouring lowers HOC where needed for favorable clasp placement.";
 rationaleLines.push({ key: "abutprep", verbose: guideLine, compressed: guideLine });
 }

 // Per-tooth clasp rationales — DEDUPE by claspType in compressed mode.
 // Group: claspType → { teeth: [...], verboseRationale: "...", firstA: <one verbose line per tooth (still>" }
 const claspGroups = new Map;
 (result.abutmentDesigns || []).forEach(a => {
 if (!a.claspRationale) return;
 const key = a.claspType;
 if (!claspGroups.has(key)) {
 claspGroups.set(key, { teeth: [], verboseRationale: a.claspRationale });
 }
 claspGroups.get(key).teeth.push(a.tooth);
 });
 claspGroups.forEach((group, claspType) => {
 const teethList = group.teeth.map(t => `#${t}`).join(", ");
 // Verbose mode keeps one entry per tooth (current behavior).
 group.teeth.forEach(tooth => {
 rationaleLines.push({
 key: `clasp-${tooth}`,
 verbose: `#${tooth} (${claspType}): ${cleanVerbose(group.verboseRationale)}`,
 // Compressed mode entries are deduped — see filter below.
 compressed: null,
 });
 });
 // One compressed entry per claspType, regardless of tooth count.
 rationaleLines.push({
 key: `clasp-grouped-${claspType}`,
 verbose: null,
 compressed: `${teethList} (${claspType}): ${compress(group.verboseRationale)}`,
 });
 });

 // Indirect retainers — same dedupe approach.
 const indirectGroups = new Map;
 (result.indirectRetainers || []).forEach(r => {
 if (!r.rationale) return;
 const key = r.restType || "indirect";
 if (!indirectGroups.has(key)) {
 indirectGroups.set(key, { teeth: [], verboseRationale: r.rationale });
 }
 indirectGroups.get(key).teeth.push(r.tooth);
 });
 indirectGroups.forEach((group, restType) => {
 const teethList = group.teeth.map(t => `#${t}`).join(", ");
 group.teeth.forEach(tooth => {
 rationaleLines.push({
 key: `ind-${tooth}`,
 verbose: `#${tooth} indirect: ${cleanVerbose(group.verboseRationale)}`,
 compressed: null,
 });
 });
 rationaleLines.push({
 key: `ind-grouped-${restType}`,
 verbose: null,
 compressed: `${teethList} indirect retainer: ${compress(group.verboseRationale)}`,
 });
 });

 // Base designs (Open Lattice, Mesh, Tube Tooth, Facing) — group by type.
 const baseGroups = new Map;
 (result.baseDesigns || []).forEach(b => {
 if (!b.rationale) return;
 const key = b.type;
 if (!baseGroups.has(key)) {
 baseGroups.set(key, { spans: [], verboseRationale: b.rationale });
 }
 baseGroups.get(key).spans.push(...(b.spanTeeth || []));
 });
 // Verbose: one entry per baseDesign block (the current behavior).
 (result.baseDesigns || []).forEach(b => {
 if (!b.rationale) return;
 rationaleLines.push({
 key: `base-v-${b.type}-${(b.spanTeeth || []).join("-")}`,
 verbose: `${b.type}: ${cleanVerbose(b.rationale)}`,
 compressed: null,
 });
 });
 // Compressed: one entry per base type with all teeth listed.
 baseGroups.forEach((group, baseType) => {
 const teethList = group.spans.length
? `${group.spans.map(t => `#${t}`).join(", ")} (${baseType})`
: baseType;
 rationaleLines.push({
 key: `base-grouped-${baseType}`,
 verbose: null,
 compressed: `${teethList}: ${compress(group.verboseRationale)}`,
 });
 });

 // Choose which lines to render based on the toggle.
 const visibleRationaleLines = rationaleLines
.map(l => showFullRationale? l.verbose: l.compressed)
.filter(Boolean);

 const fieldRow = (label, value) => (
 <div style={{ display: "flex", alignItems: "baseline", gap: "8px", marginBottom: "8px" }}>
 <span style={{ fontWeight: 600, fontSize: "11px", whiteSpace: "nowrap" }}>{label}:</span>
 <span style={{
 flex: 1, fontSize: "12px", borderBottom: "1px solid var(--ink)",
 paddingBottom: "2px", minHeight: "16px", color: "var(--ink)",
 fontFamily: "'Geist', sans-serif",
 }}>
 {value || " "}
 </span>
 </div>
);

 const checkboxRow = (label, checked) => (
 <div style={{ display: "flex", alignItems: "center", gap: "6px", marginBottom: "3px", fontSize: "11px" }}>
 <span style={{
 display: "inline-block", width: "10px", height: "10px",
 border: "1px solid var(--ink)", boxSizing: "border-box",
 background: "var(--paper)", position: "relative",
 }}>
 {checked && (
 <span style={{
 position: "absolute", inset: 0, display: "flex",
 alignItems: "center", justifyContent: "center",
 fontSize: "9px", lineHeight: 1, color: "var(--ink)",
 }}>✓</span>
)}
 </span>
 <span>{label}</span>
 </div>
);

 return (
 <div className="rpd-uic-form" style={{
 background: "white",
 border: "1.5px solid var(--ink)",
 padding: "24px",
 marginBottom: "20px",
 fontFamily: "'Geist', sans-serif",
 color: "var(--ink)",
 fontSize: "12px",
 lineHeight: 1.5,
 }}>
 {/* Header */}
 <div style={{ display: "grid", gridTemplateColumns: "1fr auto", gap: "16px", alignItems: "start", marginBottom: "16px", paddingBottom: "12px", borderBottom: "1.5px solid var(--ink)" }}>
 <div>
 <div style={{ fontSize: "13px", fontWeight: 600, letterSpacing: "0.04em", lineHeight: 1.3 }}>
 PRELIMINARY {arch}<br/>
 PARTIAL DENTURE DESIGN
 </div>
 </div>
 </div>

 {/* Student / Patient / Date */}
 <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 140px", gap: "20px", marginBottom: "20px" }}>
 {fieldRow("Student", "")}
 {fieldRow("Patient", "")}
 {fieldRow("Date", new Date().toISOString().slice(0,10))}
 </div>

 {/* Opposing / mold / shade row */}
 <div style={{
 display: "grid", gridTemplateColumns: "1fr 1fr",
 gap: "20px", marginBottom: "20px", padding: "12px 14px",
 border: "1px solid var(--rule)",
 }}>
 <div>
 <div style={{ fontSize: "10px", fontWeight: 600, marginBottom: "6px", textTransform: "uppercase", letterSpacing: "0.06em" }}>Opposing:</div>
 {checkboxRow("Natural dentition", pf.opposingArch === "natural" ||!pf.opposingArch)}
 {checkboxRow("Existing partial denture", pf.opposingArch === "partial_denture")}
 {checkboxRow("Existing complete denture", pf.opposingArch === "complete_denture")}
 {checkboxRow("New prosthesis/restoration to be made", pf.opposingArch === "new_prosthesis")}
 </div>
 <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "8px", alignItems: "end" }}>
 <div>
 <div style={{ fontSize: "10px", fontWeight: 600, marginBottom: "4px" }}>Anterior mold</div>
 <div style={{ border: "1px solid var(--ink)", height: "20px" }} />
 </div>
 <div>
 <div style={{ fontSize: "10px", fontWeight: 600, marginBottom: "4px" }}>Posterior mold</div>
 <div style={{ border: "1px solid var(--ink)", height: "20px" }} />
 </div>
 <div>
 <div style={{ fontSize: "10px", fontWeight: 600, marginBottom: "4px" }}>Shade</div>
 <div style={{ border: "1px solid var(--ink)", height: "20px" }} />
 </div>
 </div>
 </div>

 {/* Arch drawing — paper-form rendering of the design with ink colors.
 Skipped when showArchDrawing=false (e.g. when this form is rendered
 directly below the interactive chart; no need to redraw). */}
 {/* Arch drawing — collapsible toggle */}
 <div style={{ marginBottom: "20px" }}>
 <button
 onClick={() => setDrawingOpen(o =>!o)}
 style={{
 display: "flex", alignItems: "center", gap: "8px",
 background: "none", border: "none", padding: "6px 0",
 cursor: "pointer", color: "var(--ink-soft)",
 fontSize: "11px", fontWeight: 700, letterSpacing: "0.08em",
 textTransform: "uppercase",
 }}
 >
 <span style={{ fontSize: "10px" }}>{drawingOpen? "▾": "▸"}</span>
 Design drawing — {arch === "MAXILLARY"? "Maxillary": "Mandibular"} arch (occlusal view)
 </button>
 {drawingOpen && (
 <div style={{ marginTop: "8px", padding: "18px 20px", border: "1.5px solid var(--ink)", background: "#FDFCF7" }}>
 <RPDPaperFormArchDrawing caseInput={caseInput} result={result} />
 </div>
)}
 </div>

 {/* Body: 2-column layout — Design on left, Rationale on right */}
 <div style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr", gap: "24px" }}>
 {/* Design column */}
 <div>
 <div style={{ fontSize: "12px", fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", marginBottom: "12px", paddingBottom: "4px", borderBottom: "1.5px solid var(--ink)" }}>
 Partial Denture Design
 </div>

 {/* Layout mirrors the actual UIC paper form field-by-field:
 Framework metal → Major connector → Abutment teeth →
 Abutment preparations (consolidated) → Direct retainers table →
 Indirect retainers → Facings/pontics/tube teeth → Retention webbing.
 Path of insertion, HOC adjustments, undercut modifications, and
 esthetic exceptions all fold into the "Abutment preparations" line
 because that's how the paper form is laid out. */}
 {fieldRow("Framework metal", result.framework.material)}
 {fieldRow("Major connector", `${result.majorConnector.type}${result.majorConnector.width? ` (${result.majorConnector.width})`: ""}`)}
 {fieldRow("Abutment teeth", (result.abutmentDesigns || []).map(a => `#${a.tooth}`).join(", "))}

 <div style={{ marginBottom: "12px" }}>
 <div style={{ fontWeight: 600, fontSize: "11px", marginBottom: "4px" }}>Abutment preparations, guide planes, recontouring, restorations:</div>
 <div style={{
 border: "1px solid var(--ink)", padding: "6px 8px",
 minHeight: "36px", fontSize: "11px", whiteSpace: "pre-wrap",
 }}>
 {abutmentPrepLines || ""}
 </div>
 </div>

 {/* Direct retainers table — the form has one row per abutment with
 columns: tooth # / clasp / rest / retention / bracing. */}
 <div style={{ marginBottom: "12px" }}>
 <div style={{ fontWeight: 600, fontSize: "11px", marginBottom: "4px" }}>Direct retainers:</div>
 <table style={{
 width: "100%", borderCollapse: "collapse", fontSize: "11px",
 border: "1px solid var(--ink)",
 }}>
 <thead>
 <tr>
 {["Tooth #", "Clasp", "Rest", "Retention", "Bracing"].map(h => (
 <th key={h} style={{
 padding: "4px 6px",
 borderBottom: "1px solid var(--ink)",
 borderRight: "1px solid var(--rule)",
 fontWeight: 600, textAlign: "left",
 background: "var(--paper)",
 fontSize: "10px",
 textTransform: "uppercase",
 letterSpacing: "0.04em",
 }}>
 {h}
 </th>
))}
 </tr>
 </thead>
 <tbody>
 {directRetainers.length === 0? (
 <tr><td colSpan={5} style={{ padding: "8px", fontStyle: "italic", color: "var(--ink-soft)", textAlign: "left" }}>No abutments</td></tr>
): directRetainers.map((r, i) => (
 <tr key={i}>
 <td style={{ padding: "4px 6px", textAlign: "left", borderRight: "1px solid var(--rule)", borderBottom: i === directRetainers.length - 1? "none": "1px solid var(--rule)" }}>#{r.tooth}</td>
 <td style={{ padding: "4px 6px", textAlign: "left", borderRight: "1px solid var(--rule)", borderBottom: i === directRetainers.length - 1? "none": "1px solid var(--rule)" }}>{r.clasp}</td>
 <td style={{ padding: "4px 6px", textAlign: "left", borderRight: "1px solid var(--rule)", borderBottom: i === directRetainers.length - 1? "none": "1px solid var(--rule)" }}>{r.rest}</td>
 <td style={{ padding: "4px 6px", textAlign: "left", borderRight: "1px solid var(--rule)", borderBottom: i === directRetainers.length - 1? "none": "1px solid var(--rule)" }}>{r.retention}</td>
 <td style={{ padding: "4px 6px", textAlign: "left", borderBottom: i === directRetainers.length - 1? "none": "1px solid var(--rule)" }}>{r.bracing}</td>
 </tr>
))}
 </tbody>
 </table>
 </div>

 {fieldRow("Indirect retainers, additional rests", indirectList)}
 {fieldRow("Facings, metal pontics, tube teeth", facingsList)}
 {fieldRow("Retention webbing", webbingList)}
 </div>

 {/* Rationale column */}
 <div>
 <div style={{
 display: "flex", justifyContent: "space-between", alignItems: "baseline",
 marginBottom: "12px", paddingBottom: "4px", borderBottom: "1.5px solid var(--ink)",
 }}>
 <span style={{ fontSize: "12px", fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase" }}>
 Rationale / Comments
 </span>
 {/* Verbose toggle lives in the parent RPDHelper (top-right above the
 forms); no secondary mode label here — the toggle itself is the
 single source of state truth. */}
 </div>
 <div style={{ fontSize: "11px", lineHeight: 1.55 }}>
 {visibleRationaleLines.map((line, i) => (
 <div key={i} style={{
 marginBottom: "8px",
 paddingBottom: "6px",
 borderBottom: i === visibleRationaleLines.length - 1? "none": "1px dotted var(--rule)",
 }}>
 {line}
 </div>
))}
 </div>
 </div>
 </div>

 {/* Footer */}
 <div style={{ marginTop: "24px", paddingTop: "12px", borderTop: "1px solid var(--ink)", display: "grid", gridTemplateColumns: "2fr 1fr", gap: "20px" }}>
 {fieldRow("Preliminary design approved by", "")}
 {fieldRow("Date", "")}
 </div>
 </div>
);
}

