// Facial-form silhouettes (Williams/Trubyte classification viewed frontally).
// SVG path drawn inside a 32×40 viewBox — small frontal-face outlines that
// let the student visually match the patient's face shape rather than reading
// labels. Square = rectangular with parallel sides; Tapering = wide temples
// narrowing to chin; Ovoid = egg-shape; combinations interpolate.
// SVG silhouettes are traced from the 7 facial-form icons in the Portrait
// IPN / Bioform IPN Mould Chart (Dentsply Sirona pub. 905473-Rev10) — page
// 4 reference card + cross-checked against the maxillary anterior photos on
// pages 9-10. Each path renders a recognizable central-incisor outline in
// a 32×40 viewBox: cervical at top with a gentle gingival arch, mesial /
// distal contacts at the widest point, gently curved incisal edge.
const TOOTH_MOULD_FORMS = [
 { id: "1", label: "Square",
 // Parallel sides, gentle gingival arch, gently curved incisal.
 // Matches catalog moulds 11G, 12E, 12F, 12G, 13D, 13E.
 path: "M7 5 Q11 3 16 3 Q21 3 25 5 L25 30 Q25 36 16 36 Q7 36 7 30 Z" },
 { id: "2", label: "Square Tapering",
 // Wider at cervical, tapers strongly toward a narrower incisal edge.
 // Matches 21C, 21D, 21E, 21F, 21G, 21J, 22C, 22E, 22G, 22H, 24F, 25G.
 path: "M6 5 Q10 3 16 3 Q22 3 26 5 Q24 18 22 28 Q19 36 16 36 Q13 36 10 28 Q8 18 6 5 Z" },
 { id: "3", label: "Square Ovoid",
 // Square upper contour, ovoid (curved) lower two-thirds.
 // Matches 31F, 32B, 32E, 32G, 35E, 36F.
 path: "M7 5 Q11 3 16 3 Q21 3 25 5 Q26 18 23 28 Q19 36 16 36 Q13 36 9 28 Q6 18 7 5 Z" },
 { id: "4", label: "Tapering",
 // Pronounced triangular taper from wide cervical to narrow incisal.
 path: "M5 5 Q10 3 16 3 Q22 3 27 5 L23 22 L20 32 L18 36 Q16 36 14 36 L12 32 L9 22 Z" },
 { id: "5", label: "Tapering Ovoid",
 // Tapered overall but with ovoid (curved) sides instead of straight.
 path: "M6 5 Q10 3 16 3 Q22 3 26 5 Q23 18 20 28 Q18 36 16 36 Q14 36 12 28 Q9 18 6 5 Z" },
 { id: "6", label: "Ovoid",
 // True oval — narrow at cervical and incisal, widest at the middle.
 path: "M16 3 Q21 3 24 7 Q27 14 26 22 Q24 32 20 36 Q16 37 12 36 Q8 32 6 22 Q5 14 8 7 Q11 3 16 3 Z" },
 { id: "7", label: "Square Tapering Ovoid",
 // Squared cervical with a tapering profile and curved (ovoid) sides.
 path: "M7 5 Q11 3 16 3 Q21 3 25 5 Q26 14 24 22 Q21 32 18 35 Q17 36 16 36 Q15 36 14 35 Q11 32 8 22 Q6 14 7 5 Z" },
];

// Proportion of tooth (long / medium / short) × facial contour (straight / curved).
//
// PROPORTION is the cervical-incisal length of the tooth: long, medium, or short.
// FACIAL CONTOUR (per IPN chart p.5 step 2) is matched to the patient's FACIAL
// PROFILE in SIDE view — NOT a tooth surface, so it works on an edentulous
// patient. A flat/straight facial profile → STRAIGHT (flat labial); a convex/
// curved profile → CURVED (bulging labial). The Dentsply Sirona Tooth Indicator
// (#98981) is a flat gauge held along the profile to judge straight vs curved.
//
// To make the distinction VISIBLE in the picker, these SVGs draw a side-profile
// (mesio-distal cross-section) of the tooth — cervical at top, incisal at
// bottom — with the LABIAL face on the right of each glyph and the LINGUAL
// face on the left. The straight variants render the right edge as a vertical
// line; the curved variants render it as a convex bulge. Length scales the
// overall glyph height to reflect long / medium / short proportion. 16×22
// viewBox; box edges on the lingual side stay constant so the proportion
// signal reads clearly against the labial profile signal.
const TOOTH_MOULD_PROPORTIONS = [
 { id: "1", label: "Long · Straight (flat labial)",
   // Tall glyph, RIGHT (labial) edge is straight vertical line.
   path: "M5 2 Q6 1 8 1 L13 1 L13 21 L8 21 Q6 21 5 20 Z" },
 { id: "2", label: "Medium · Straight (flat labial)",
   // Medium glyph, straight labial.
   path: "M5 4 Q6 3 8 3 L13 3 L13 19 L8 19 Q6 19 5 18 Z" },
 { id: "3", label: "Short · Straight (flat labial)",
   // Short glyph, straight labial.
   path: "M5 6 Q6 5 8 5 L13 5 L13 17 L8 17 Q6 17 5 16 Z" },
 { id: "4", label: "Long · Curved (convex labial)",
   // Tall glyph, RIGHT (labial) edge bulges outward in a smooth convex curve.
   path: "M5 2 Q6 1 8 1 L11 1 Q14 6 14 11 Q14 16 11 21 L8 21 Q6 21 5 20 Z" },
 { id: "5", label: "Medium · Curved (convex labial)",
   // Medium glyph, convex labial.
   path: "M5 4 Q6 3 8 3 L11 3 Q14 7 14 11 Q14 15 11 19 L8 19 Q6 19 5 18 Z" },
 { id: "6", label: "Short · Curved (convex labial)",
   // Short glyph, convex labial.
   path: "M5 6 Q6 5 8 5 L11 5 Q14 8 14 11 Q14 14 11 17 L8 17 Q6 17 5 16 Z" },
];

// Width of upper six anterior teeth on curve, distal-to-distal
const TOOTH_MOULD_WIDTHS = [
 { letter: "B", range: "<44.00 mm" },
 { letter: "C", range: "44.00–45.50 mm" },
 { letter: "D", range: "45.50–48.00 mm" },
 { letter: "E", range: "48.00–49.00 mm" },
 { letter: "F", range: "49.00–51.50 mm" },
 { letter: "G", range: "51.50–54.00 mm" },
 { letter: "H", range: "54.00–56.00 mm" },
 { letter: "J", range: "≥56.00 mm" },
];

const TOOTH_MOULD_CUSP_ANGLES = [
 { key: "p0", label: "0°", brand: "Portrait IPN", category: "Non-anatomical (flat plane)",
 desc: "Flat-plane occlusal. Best for poor ridges, severe resorption, Class II/III jaw relationships, and patients who can't tolerate any lateral interference (severe TMD, neuromuscular issues). No interlocking cusps — the prosthesis moves freely in excursions but loses chewing efficiency vs anatomical." },
 { key: "b0", label: "0°", brand: "Bioform IPN Monoline", category: "Non-anatomical (flat plane)",
 desc: "Bioform's flat-plane equivalent. Same indications as Portrait 0°: poor ridge support, severe resorption, Class II/III, TMD that cannot accept any lateral interference." },
 { key: "a10", label: "10°", brand: "Portrait IPN / Bioform Anatoline", category: "Semi-anatomical (modified cusp)",
 desc: "Shallow 10° cusps. Look of well-worn natural teeth with a definite centric. Upper lingual cusps form a 'lingual cutting knife' in occlusion. Good middle ground when ridges are adequate but neuromuscular control is questionable." },
 { key: "a20", label: "20°", brand: "Portrait / Bioform IPN", category: "Semi-anatomical (modified cusp)",
 desc: "Shallow 20° cusps with minimal lateral interference. Specially contoured occlusal ridges + clearance spaces for chewing efficiency. Good default for the average complete-denture patient with reasonable ridges and no parafunctional issues." },
 { key: "p22", label: "22°", brand: "Portrait IPN", category: "Semi-anatomical (modified cusp)",
 desc: "Portrait 22° BioStabil. Aesthetic and functional middle ground — shallow non-interfering cusps with freedom in all excursions. Indicated for complete and partial dentures opposing natural dentition with normal occlusal relationships." },
 { key: "b30", label: "30°", brand: "Bioform IPN PT", category: "Anatomical (deep cusp)",
 desc: "Bioform 30° Pilkington-Turner posteriors. Upper premolars slope inward gingival-to-occlusal for a natural smile look. Best for good ridges, Class I jaw relationships, opposing well-developed natural teeth, and patients with good neuromuscular coordination." },
 { key: "a33", label: "33°", brand: "Portrait / Bioform IPN", category: "Anatomical (deep cusp)",
 desc: "Fully anatomical 33° with natural cusp contours. Ideal for complete and partial dentures occluding with well-developed natural teeth (especially when balanced occlusion is achievable). Needs excellent ridge support — contraindicated for poor ridges or severe resorption." },
 { key: "p40", label: "40°", brand: "Portrait IPN EuroLine", category: "Anatomical (deep cusp)",
 desc: "EuroLine 40° — German-designed natural-looking 'young' occlusal pattern with wide food table and long crown form. Set with 30° incisal/condylar guidance for maximum efficiency. Best for younger patients with good ridges + Class I, or implant-supported overdentures where load isn't a concern." },
];

// Translate a measured upper-six-anterior-curve width (mm) → letter range.
function rpdMouldWidthLetter(mm) {
 const n = parseFloat(mm);
 if (isNaN(n)) return null;
 if (n < 44.0) return "B";
 if (n < 45.5) return "C";
 if (n < 48.0) return "D";
 if (n < 49.0) return "E";
 if (n < 51.5) return "F";
 if (n < 54.0) return "G";
 if (n < 56.0) return "H";
 return "J";
}

// Explain how a closest-match mould code differs from the requested code,
// in plain language. Used in the (i) popover when the requested combination
// isn't in the chart. Returns a short sentence per axis that differs.
function explainMouldDiff(want, have) {
 if (!want || !have || want === have) return null;
 const parts = [];
 const wForm = want[0], hForm = have[0];
 const wProp = want[1], hProp = have[1];
 const wWidth = want.slice(2), hWidth = have.slice(2);
 if (wForm !== hForm) {
 const wL = TOOTH_MOULD_FORMS.find(f => f.id === wForm)?.label || wForm;
 const hL = TOOTH_MOULD_FORMS.find(f => f.id === hForm)?.label || hForm;
 parts.push(`Facial form is ${hL} instead of ${wL}`);
 }
 if (wProp !== hProp) {
 const wL = TOOTH_MOULD_PROPORTIONS.find(p => p.id === wProp)?.label || wProp;
 const hL = TOOTH_MOULD_PROPORTIONS.find(p => p.id === hProp)?.label || hProp;
 parts.push(`Proportion is ${hL} instead of ${wL}`);
 }
 if (wWidth !== hWidth) {
 const wR = TOOTH_MOULD_WIDTHS.find(w => w.letter === wWidth)?.range || wWidth;
 const hR = TOOTH_MOULD_WIDTHS.find(w => w.letter === hWidth)?.range || hWidth;
 const wider = "BCDEFGHJ".indexOf(hWidth) > "BCDEFGHJ".indexOf(wWidth);
 parts.push(`Width ${hWidth} (${hR}) — ${wider ? "wider" : "narrower"} than the ${wWidth} (${wR}) you entered`);
 }
 return parts.join("; ") + ".";
}

// Gingival (Lucitone 199 / HIPA) shade options. we commonly use
// Original + Dark Pink + the 50/50 mix; Light, Light Reddish Pink, and
// Original Opaque (HIPA-only) round out the set. Colors are visual
// approximations for the swatch — actual shade selection is chairside.
const GINGIVAL_SHADES = [
 { code: "L199-OR", label: "Original", color: "#D58E83" },
 { code: "50/50 OR+DK", label: "50% OR + 50% DK", color: "#B57367" },
 { code: "L199-DK", label: "Dark Pink", color: "#8D5950" },
 { code: "L199-LT", label: "Light", color: "#E7B5AB" },
 { code: "L199-LR", label: "Light Reddish Pink", color: "#CC8B80" },
 { code: "L199-OPQ", label: "Original Opaque", color: "#C49A8E" },
];

// Visual gingival-shade picker modeled on the Vita ShadeInput. Pink
// swatches keyed to the Lucitone 199 / HIPA palette. Click input → pop
// swatch grid → pick → close.
function GingivalShadeInput({ value, onChange }) {
 const [open, setOpen] = useState(false);
 const [focused, setFocused] = useState(false);
 const panelRef = useRef(null);
 useEffect(() => {
 if (!open) return;
 const h = (e) => {
 if (panelRef.current && !panelRef.current.contains(e.target)) setOpen(false);
 };
 document.addEventListener("mousedown", h);
 return () => document.removeEventListener("mousedown", h);
 }, [open]);
 return (
 <div ref={panelRef} style={{ position: "relative" }}>
 <input readOnly value={value || ""}
 placeholder="e.g. L199-OR"
 onClick={() => setOpen(o => !o)}
 onFocus={() => setFocused(true)}
 onBlur={() => setFocused(false)}
 style={{
 padding: "5px 8px", width: "100%", boxSizing: "border-box",
 border: `1px solid ${(open || focused) ? "var(--accent)" : "var(--rule)"}`,
 borderRadius: "2px",
 fontFamily: "'Geist', sans-serif", fontSize: "11px",
 cursor: "pointer",
 boxShadow: (open || focused) ? "0 0 0 3px rgba(122,26,26,0.08)" : "none",
 }} />
 {open && (
 <div style={{
 position: "absolute", top: "calc(100% + 2px)", left: 0,
 background: "var(--paper)", border: "1px solid var(--rule)",
 borderRadius: "4px", padding: "10px 12px",
 zIndex: 200, boxShadow: "0 4px 20px rgba(0,0,0,0.16)",
 minWidth: "260px",
 }}>
 <div style={{
 fontSize: "9px", letterSpacing: "0.16em",
 textTransform: "uppercase", color: "var(--ink-faint)",
 fontFamily: "'Geist', sans-serif", marginBottom: "8px",
 }}>Gingival shade (Lucitone 199 / HIPA)</div>
 <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "6px" }}>
 {GINGIVAL_SHADES.map(s => {
 const isActive = value === s.code;
 return (
 <button key={s.code}
 onClick={() => { onChange(s.code); setOpen(false); }}
 style={{
 display: "flex", flexDirection: "column",
 alignItems: "center", gap: "4px",
 background: isActive ? "rgba(122,26,26,0.07)" : "transparent",
 border: `1.5px solid ${isActive ? "var(--accent)" : "var(--rule)"}`,
 borderRadius: "3px", padding: "6px 4px",
 cursor: "pointer", transition: "border-color 100ms",
 }}>
 <div style={{
 width: "28px", height: "18px",
 background: s.color,
 borderRadius: "9px 9px 3px 3px",
 border: "1px solid rgba(0,0,0,0.12)",
 }} />
 <span style={{
 fontSize: "9px",
 fontFamily: "'JetBrains Mono', monospace",
 color: isActive ? "var(--accent)" : "var(--ink-soft)",
 letterSpacing: "-0.2px", lineHeight: 1.1,
 textAlign: "center",
 }}>{s.code}</span>
 <span style={{
 fontSize: "8px", color: "var(--ink-faint)",
 textAlign: "center", lineHeight: 1.1,
 }}>{s.label}</span>
 </button>
 );
 })}
 </div>
 </div>
 )}
 </div>
 );
}

// Generic circled-(i) popover. Click to toggle, click outside or press
// Escape to dismiss. Used by the tooth mould picker's "Upper six anterior
// curve width" hint and could be reused anywhere else that needs a
// click-to-reveal explanation.
function InfoPopover({ text }) {
 const [open, setOpen] = useState(false);
 const wrapRef = useRef(null);
 useEffect(() => {
 if (!open) return;
 const onClick = (e) => {
 if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false);
 };
 const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
 document.addEventListener("mousedown", onClick);
 document.addEventListener("keydown", onKey);
 return () => {
 document.removeEventListener("mousedown", onClick);
 document.removeEventListener("keydown", onKey);
 };
 }, [open]);
 return (
 <span ref={wrapRef} style={{ position: "relative", display: "inline-flex", alignItems: "center" }}>
 <button type="button" onClick={() => setOpen(o => !o)}
 aria-label={open ? "Hide hint" : "Show hint"}
 style={{
 width: "14px", height: "14px", borderRadius: "50%",
 border: `1px solid ${open ? "var(--accent)" : "var(--ink-faint)"}`,
 background: open ? "var(--accent)" : "transparent",
 color: open ? "white" : "var(--ink-soft)",
 fontSize: "9px", fontFamily: "'Fraunces', serif",
 fontStyle: "italic", lineHeight: 1, cursor: "pointer",
 display: "inline-flex", alignItems: "center", justifyContent: "center",
 padding: 0, userSelect: "none",
 }}>i</button>
 {open && (
 <div style={{
 position: "absolute", top: "20px", left: "0",
 width: "340px", zIndex: 10,
 padding: "10px 12px", background: "var(--paper)",
 border: "1px solid var(--accent)", borderRadius: "3px",
 fontSize: "11px", lineHeight: 1.5, color: "var(--ink)",
 fontStyle: "normal", textTransform: "none", letterSpacing: 0,
 boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
 // Preserve newlines in the text prop so callers can split a long
 // explanation into paragraphs with \n\n rather than passing JSX.
 whiteSpace: "pre-wrap",
 }}>
 {text}
 </div>
 )}
 </span>
 );
}

