// ── Patch GUIDES with real content from the JSON-imported guides-data ────
// The GUIDES const above defines the Part / Chapter navigation structure
// with hand-curated taglines and grouping. Most chapters are { stub: true }
// placeholders. This patcher walks the generated JSON (produced by
// /tmp/extract_guides_json.py from build_*.py) and:
// 1. For chapters present in both: copies real.blocks (+ updates.title)
// so the chapter renders full content instead of "Coming soon".
// 2. For chapters in JSON but NOT in GUIDES: appends a synthetic
// "Other chapters" Part so Pathways can still resolve them.
// Idempotent — safe to run on hot-reload.
(() => {
 const registry = new Map;
 GUIDES_DATA.forEach(g => {
 g.parts.forEach(p => {
 p.chapters.forEach(c => registry.set(c.id, c));
 });
 });

 GUIDES.forEach(g => {
 g.parts.forEach(p => {
 p.chapters.forEach(c => {
 const real = registry.get(c.id);
 if (real) {
 c.title = real.title || c.title;
 c.blocks = real.blocks;
 // Verdict: JSON wins if set. Previously the JSON italic-intro
 // paragraph duplicated chapter.verdict; we extracted those into
 // verdict server-side and dropped blocks[0] — so a JSON-side
 // verdict here is the authoritative one.
 if (real.verdict) c.verdict = real.verdict;
 if (c.stub) delete c.stub;
 }
 });
 });
 });

 // Append any JSON chapters not in GUIDES as a fallback "Other" part.
 GUIDES_DATA.forEach(jsonGuide => {
 const guideEntry = GUIDES.find(g => g.id === jsonGuide.id);
 if (!guideEntry) return;
 const existingIds = new Set;
 guideEntry.parts.forEach(p => p.chapters.forEach(c => existingIds.add(c.id)));
 const missing = (jsonGuide.parts[0]?.chapters || [])
.filter(c =>!existingIds.has(c.id));
 if (missing.length > 0) {
 guideEntry.parts.push({
 id: `${jsonGuide.id}-extras`,
 label: "Other chapters",
 tagline: "Additional chapters from the source guide not yet sorted into the main parts.",
 chapters: missing,
 });
 }
 });
})();

// Inline-markdown renderer: bold (**) and italic (*). No HTML escaping needed
// since content is hand-authored above. Returns an array of React nodes.
function renderInline(text) {
 const out = [];
 const pattern = /(\*\*[^*]+\*\*|\*[^*]+\*)/g;
 const parts = text.split(pattern);
 // Render `**bold**` / `*italic*` runs as <strong>/<em>; treat `\n` as a
 // line break so callout bodies and other long strings can be structured
 // with explicit line breaks rather than rendering as one wall of text.
 let keyCounter = 0;
 const pushText = (chunk) => {
 if (!chunk) return;
 const lines = chunk.split("\n");
 lines.forEach((line, j) => {
 if (line) out.push(line);
 if (j < lines.length - 1) out.push(<br key={`br-${keyCounter++}`} />);
 });
 };
 parts.forEach((part, i) => {
 if (!part) return;
 if (part.startsWith("**") && part.endsWith("**")) {
 out.push(<strong key={`b-${i}`}>{part.slice(2, -2)}</strong>);
 } else if (part.startsWith("*") && part.endsWith("*")) {
 out.push(<em key={`i-${i}`}>{part.slice(1, -1)}</em>);
 } else {
 pushText(part);
 }
 });
 return out;
}

// Collapsible block — used for "Issues" troubleshooting sections (and any
// other content that's useful when you need it but clutters the chapter
// when always-open). Renders as a clickable header with a chevron that
// rotates when expanded. Closed by default.
function DropdownBlock({ title, body }) {
 const [open, setOpen] = useState(false);
 return (
 <div style={{
 border: "1px solid var(--rule)",
 borderRadius: "3px",
 margin: "14px 0",
 overflow: "hidden",
 }}>
 <button
 type="button"
 onClick={() => setOpen((o) => !o)}
 aria-expanded={open}
 style={{
 all: "unset",
 display: "flex", alignItems: "center", gap: "10px",
 width: "100%", boxSizing: "border-box",
 padding: "10px 14px", cursor: "pointer",
 background: open ? "var(--paper, #FBF8F2)" : "transparent",
 transition: "background 140ms ease",
 }}
 onMouseEnter={(e) => { if (!open) e.currentTarget.style.background = "var(--paper, #FBF8F2)"; }}
 onMouseLeave={(e) => { if (!open) e.currentTarget.style.background = "transparent"; }}
 >
 <span style={{
 fontSize: "0.82rem", letterSpacing: "0.01em", color: "var(--accent)",
 fontWeight: 600, flex: 1,
 }}>{title}</span>
 <span aria-hidden="true" style={{
 fontSize: "1rem", color: "var(--ink-faint)",
 transition: "transform 160ms ease",
 transform: open ? "rotate(180deg)" : "rotate(0deg)",
 }}>▾</span>
 </button>
 {open && (
 <div style={{
 padding: "10px 14px 12px",
 fontSize: "0.95rem", lineHeight: 1.55, color: "var(--ink)",
 borderTop: "1px solid var(--rule-soft, var(--rule))",
 }}>{renderInline(body)}</div>
 )}
 </div>
 );
}

function GuideBlock({ block }) {
 switch (block.kind) {
 case "dropdown":
 return <DropdownBlock title={block.title} body={block.body} />;
 case "h2":
 return (
 <h3 className="serif" style={{
 fontSize: "1.05rem", fontWeight: 500, color: "var(--ink)",
 margin: "20px 0 8px", letterSpacing: "0.01em",
 }}>{renderInline(block.text)}</h3>
);
 case "section":
 return (
 <div style={{
 fontSize: "0.78rem", textTransform: "uppercase", letterSpacing: "0.08em",
 color: "var(--accent)", fontWeight: 600,
 margin: "16px 0 6px", borderBottom: "1px solid var(--rule-soft)",
 paddingBottom: "4px",
 }}>{renderInline(block.text)}</div>
);
 case "paragraph":
 return (
 <p style={{ margin: "8px 0", lineHeight: 1.55, color: "var(--ink)" }}>
 {renderInline(block.text)}
 </p>
);
 case "bullets":
 // If every item starts with a sub-step label like **1a.** / **2c.** /
 // **Step 3** / **Visit 2** — drop the disc marker (the sub-step label
 // already serves as a marker) but preserve the same left indent so
 // the visual hierarchy is intact. The author opts in by formatting
 // items with a leading **N[a-z].** or **Step N** convention.
 {
 const subStepRe = /^\*\*(?:\d+[a-z]?\.|Step \d+\b|Visit \d+\b|Day \d+\b|Phase \d+\b)/;
 const allSubStep = block.items.length > 0 && block.items.every(it => subStepRe.test(it));
 return (
 <ul style={{
 margin: "6px 0 10px",
 paddingLeft: "20px",
 lineHeight: 1.55,
 listStyle: allSubStep ? "none" : undefined,
 }}>
 {block.items.map((item, i) => (
 <li key={i} style={{ margin: "4px 0" }}>{renderInline(item)}</li>
))}
 </ul>
);
 }
 case "numbered":
 return (
 <ol style={{ margin: "6px 0 10px", paddingLeft: "22px", lineHeight: 1.55 }}>
 {block.items.map((item, i) => (
 <li key={i} style={{ margin: "5px 0" }}>{renderInline(item)}</li>
))}
 </ol>
);
 case "callout":
 return (
 <div style={{
 background: "rgba(122, 26, 26, 0.04)",
 border: "1px solid var(--rule)",
 borderLeft: "3px solid var(--accent)",
 padding: "12px 16px", margin: "14px 0",
 borderRadius: "2px", lineHeight: 1.5,
 }}>
 <div style={{
 fontSize: "0.8rem", textTransform: "uppercase", letterSpacing: "0.07em",
 color: "var(--accent)", fontWeight: 600, marginBottom: "6px",
 }}>{block.title}</div>
 <div>{renderInline(block.body)}</div>
 </div>
);
 case "troubleshoot":
 return (
 <div style={{
 background: "rgba(180, 110, 30, 0.06)",
 border: "1px solid var(--rule)",
 borderLeft: "3px solid var(--gold, #b46e1e)",
 padding: "12px 16px", margin: "14px 0",
 borderRadius: "2px", lineHeight: 1.5,
 }}>
 <div style={{
 fontSize: "0.84rem", letterSpacing: "0.01em",
 color: "var(--gold, #b46e1e)", fontWeight: 600, marginBottom: "6px",
 }}>{block.title}</div>
 <div>{renderInline(block.body)}</div>
 </div>
);
 default:
 return null;
 }
}

function GuideChapter({ chapter, hideHeader }) {
 // Group blocks under their preceding section header so each section
 // can be collapsed independently. Blocks before the first section
 // header are "intro" (always visible). The Materials checklist
 // defaults to collapsed because it's reference content the student
 // already knows by SC-2; other sections default expanded so the
 // procedural flow reads top-to-bottom on first open.
 const groups = useMemo(() => {
 if (!chapter.blocks) return { intro: [], sections: [] };
 const intro = [];
 const sections = [];
 let current = null;
 chapter.blocks.forEach((block) => {
 if (block.kind === "section") {
 if (current) sections.push(current);
 current = { label: block.text, blocks: [] };
 } else if (current) {
 current.blocks.push(block);
 } else {
 intro.push(block);
 }
 });
 if (current) sections.push(current);
 return { intro, sections };
 }, [chapter.blocks]);

 // Collapse state: Set of section labels that are collapsed. Default
 // is everything collapsed — the user reads the chapter top-down by
 // expanding sections as they go. The "Expand steps" toggle at the
 // top-right of the chapter flips them all open at once.
 const [collapsedSecs, setCollapsedSecs] = useState(() => {
 return new Set(groups.sections.map(g => g.label));
 });

 // Reset when the chapter changes (e.g., user picks a different
 // pathway / chapter). All collapsed again — same rationale as initial.
 useEffect(() => {
 setCollapsedSecs(new Set(groups.sections.map(g => g.label)));
 }, [chapter.id]);

 const toggleSec = (label) => {
 setCollapsedSecs(prev => {
 const next = new Set(prev);
 if (next.has(label)) next.delete(label);
 else next.add(label);
 return next;
 });
 };

 const allSecsCollapsed = groups.sections.length > 0 &&
 groups.sections.every(g => collapsedSecs.has(g.label));
 const toggleAllSecs = () => {
 if (allSecsCollapsed) {
 setCollapsedSecs(new Set);
 } else {
 setCollapsedSecs(new Set(groups.sections.map(g => g.label)));
 }
 };

 if (chapter.stub) {
 return (
 <div style={{ padding: "40px 0", color: "var(--ink-soft)", textAlign: "center" }}>
 {!hideHeader && (
 <div style={{ fontSize: "1rem", fontWeight: 500, marginBottom: "6px" }}>
 Ch {chapter.num} · {chapter.title}
 </div>
)}
 <div style={{ fontSize: "0.9rem", color: "var(--ink-faint)", fontStyle: "italic" }}>
 Coming soon. Live source: the deep-dive PDF.
 </div>
 </div>
);
 }
 return (
 <div>
 {!hideHeader && (
 <h2 className="serif" style={{
 fontSize: "1.4rem", fontWeight: 400, color: "var(--ink)",
 margin: "0 0 4px",
 }}>
 <span style={{ color: "var(--accent)", fontSize: "0.85rem", fontWeight: 600,
 textTransform: "uppercase", letterSpacing: "0.1em", marginRight: "10px" }}>
 Ch {chapter.num}
 </span>
 {chapter.title}
 </h2>
)}
 {chapter.verdict && (
 <p style={{
 margin: "8px 0 14px", fontStyle: "italic", color: "var(--ink-soft)",
 lineHeight: 1.55, fontSize: "0.95rem",
 }}>
 {chapter.verdict}
 </p>
)}
 {/* Intro blocks (before the first section header) — always visible */}
 {groups.intro.map((block, i) => <GuideBlock key={`intro-${i}`} block={block} />)}
 {/* Collapse all steps toggle — only shown when there are 2+ sections */}
 {groups.sections.length >= 2 && (
 <div style={{
 display: "flex", justifyContent: "flex-end",
 marginTop: groups.intro.length > 0 ? "10px" : "0",
 marginBottom: "4px",
 }}>
 <button
 onClick={toggleAllSecs}
 title={allSecsCollapsed ? "Expand every section in this chapter" : "Collapse every section in this chapter"}
 style={{
 fontFamily: "'Geist', sans-serif",
 fontSize: "0.66rem", textTransform: "uppercase", letterSpacing: "0.08em",
 color: "var(--ink-faint)", fontWeight: 500,
 background: "transparent",
 border: "1px solid var(--rule)",
 borderRadius: "100px",
 padding: "2px 9px", cursor: "pointer",
 transition: "all 120ms ease",
 }}
 onMouseEnter={(e) => {
 e.currentTarget.style.borderColor = "var(--accent)";
 e.currentTarget.style.color = "var(--ink-soft)";
 }}
 onMouseLeave={(e) => {
 e.currentTarget.style.borderColor = "var(--rule)";
 e.currentTarget.style.color = "var(--ink-faint)";
 }}
 >{allSecsCollapsed ? "Expand" : "Collapse"}</button>
 </div>
)}
 {/* Each section: clickable header + collapsible body */}
 {groups.sections.map((g, gi) => {
 const isCollapsed = collapsedSecs.has(g.label);
 return (
 <div key={`sec-${gi}`} style={{ marginTop: gi === 0 ? "6px" : "2px" }}>
 <button
 type="button"
 onClick={() => toggleSec(g.label)}
 aria-expanded={!isCollapsed}
 style={{
 display: "flex", alignItems: "baseline", width: "100%",
 textAlign: "left", background: "transparent", border: "none",
 padding: "10px 0 8px", margin: 0,
 cursor: "pointer", color: "inherit",
 }}
 >
 <span className="serif" style={{
 fontSize: "1.02rem", fontWeight: 500, lineHeight: 1.3,
 color: isCollapsed ? "var(--ink-soft)" : "var(--ink)", flex: 1,
 transition: "color 160ms ease",
 }}>{renderInline(g.label)}</span>
 <span aria-hidden="true" style={{
 marginLeft: "10px", color: "var(--ink-faint)",
 fontSize: "0.8rem", lineHeight: 1,
 transition: "transform 160ms ease",
 transform: isCollapsed ? "rotate(-90deg)" : "rotate(0deg)",
 opacity: 0.6,
 }}>▾</span>
 </button>
 {!isCollapsed && (
 <div style={{
 borderLeft: "2px solid var(--accent)",
 paddingLeft: "18px", margin: "2px 0 16px",
 }}>
 {g.blocks.map((b, bi) => (
 <GuideBlock key={`sec-${gi}-b-${bi}`} block={b} />
 ))}
 </div>
 )}
 </div>
 );
})}
 </div>
);
}

function Guides() {
 const [guideId, setGuideId] = useState(GUIDES[0].id);
 const guide = GUIDES.find(g => g.id === guideId);
 const [partId, setPartId] = useState(guide.parts[0].id);
 const part = guide.parts.find(p => p.id === partId) || guide.parts[0];
 const [chapterId, setChapterId] = useState(part.chapters[0].id);
 const chapter = part.chapters.find(c => c.id === chapterId) || part.chapters[0];

 const handleGuideChange = (id) => {
 const g = GUIDES.find(x => x.id === id);
 setGuideId(id);
 setPartId(g.parts[0].id);
 setChapterId(g.parts[0].chapters[0].id);
 };
 const handlePartChange = (id) => {
 const p = guide.parts.find(x => x.id === id);
 setPartId(id);
 setChapterId(p.chapters[0].id);
 };

 const selectStyle = {
...inputStyle,
 padding: "8px 10px", borderRadius: "3px",
 background: "var(--card, white)", cursor: "pointer",
 };

 return (
 <div className="fade-in" style={{ maxWidth: "880px", margin: "0 auto", padding: "8px 0 40px", textAlign: "left" }}>
 <div style={{ display: "flex", gap: "8px", marginBottom: "14px", flexWrap: "wrap" }}>
 {GUIDES.map(g => {
 const active = g.id === guideId;
 return (
 <button key={g.id} onClick={() => handleGuideChange(g.id)} style={{
 padding: "7px 14px", borderRadius: "100px",
 border: `1px solid ${active? "var(--accent)": "var(--rule)"}`,
 background: active? "var(--accent)": "transparent",
 color: active? "var(--paper, white)": "var(--ink-soft)",
 fontSize: "0.85rem", fontWeight: 500, cursor: "pointer",
 fontFamily: "'Geist', sans-serif",
 transition: "all 120ms ease",
 }}>
 {g.label}
 </button>
);
 })}
 </div>

 <div style={{ display: "grid", gridTemplateColumns: "1fr 1.4fr", gap: "10px", marginBottom: "20px" }}>
 <div>
 <div style={labelStyle}>Part</div>
 <select value={partId} onChange={(e) => handlePartChange(e.target.value)} style={selectStyle}>
 {guide.parts.map(p => <option key={p.id} value={p.id}>{p.label}</option>)}
 </select>
 </div>
 <div>
 <div style={labelStyle}>Chapter</div>
 <select value={chapterId} onChange={(e) => setChapterId(e.target.value)} style={selectStyle}>
 {part.chapters.map(c => (
 <option key={c.id} value={c.id}>
 {`Ch ${c.num} · ${c.title}${c.stub? " (stub)": ""}`}
 </option>
))}
 </select>
 </div>
 </div>

 {part.tagline && (
 <div style={{
 background: "var(--card, white)",
 border: "1px solid var(--rule-soft)",
 padding: "10px 14px", margin: "0 0 18px",
 borderRadius: "2px",
 fontStyle: "italic", color: "var(--ink-soft)",
 fontSize: "0.88rem", lineHeight: 1.5,
 }}>
 {part.tagline}
 </div>
)}

 <div style={{
 background: "var(--card, white)",
 border: "1px solid var(--rule)",
 padding: "24px 28px", borderRadius: "3px",
 boxShadow: "0 1px 4px rgba(26, 22, 18, 0.09), 0 8px 24px rgba(26, 22, 18, 0.07)",
 }}>
 <GuideChapter chapter={chapter} />
 </div>
 </div>
);
}


/* ============================================================================
 * PATHWAYS — situational navigation. Pick a patient scenario, get a
 * customized guide assembled from the comprehensive guide sections.
 *
 * Data model:
 * PATHWAY_DOMAINS: top-level grouping (CD / RPD / Indirect / Cross / Repair).
 * PATHWAYS: { id, domain, label, description, sections: [...] }
 * where each section is { guideId, chapterId, sectionId? }.
 * Omit sectionId to include the whole chapter.
 *
 * The customized guide view assembles the sections in order, renders a TOC
 * at the top, and shows each section inline. Stub chapters render as
 * "Coming soon" placeholders until populated.
 * ==========================================================================*/

